    case 'Beef': return <Beef {...props} />;
    case 'Salad': return <Salad {...props} />;
    case 'Soup': return <Soup {...props} />;
    case 'Utensils': return <Utensils {...props} />;
    case 'Cookie': return <Cookie {...props} />;
    case 'IceCream': return <IceCream {...props} />;
