  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { Recipe } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// Define the schema for a structured recipe response
const recipeSchema = {
  type: Type.OBJECT,
  properties: {
    name: { type: Type.STRING, description: "The name of the dish in Chinese." },
    description: { type: Type.STRING, description: "A short, appetizing description of the dish." },
    ingredients: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "List of ingredients with quantities (e.g., '500g 猪肉')."
    },
    instructions: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "Step-by-step cooking instructions."
    },
    cookingTime: { type: Type.STRING, description: "Total cooking time (e.g., '45分钟')." },
    difficulty: { 
      type: Type.STRING, 
      enum: ["Easy", "Medium", "Hard"],
      description: "Difficulty level."
    }
  },
  required: ["name", "description", "ingredients", "instructions", "cookingTime", "difficulty"]
};

export const generateRecipeWithAI = async (dishName: string, categoryName: string): Promise<Partial<Recipe>> => {
  if (!apiKey) {
    throw new Error("API Key is missing. Please configure it in your environment.");
  }

  const prompt = `请为“${categoryName}”类别下的菜品“${dishName}”生成一份详细的食谱。请使用中文回答。`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: recipeSchema,
        systemInstruction: "You are a professional Chinese chef helper. Generate authentic and detailed recipes."
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const data = JSON.parse(text);
    return {
      name: data.name,
      description: data.description,
      ingredients: data.ingredients,
      instructions: data.instructions,
      cookingTime: data.cookingTime,
      difficulty: data.difficulty,
    };
  } catch (error) {
    console.error("AI Generation Error:", error);
    throw error;
  }
};

export const suggestRandomRecipe = async (categoryName: string): Promise<Partial<Recipe>> => {
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }

  const prompt = `请推荐一道经典的“${categoryName}”。直接生成食谱详情。`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: recipeSchema,
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text);
  } catch (error) {
    console.error("AI Suggestion Error:", error);
    throw error;
  }
};

