import React, { useState } from 'react';
import { CategoryId, Recipe } from '../types';
import { generateRecipeWithAI } from '../services/geminiService';
import { Sparkles, Loader2, Save, X } from 'lucide-react';

interface RecipeFormProps {
  categoryId: CategoryId;
  categoryName: string;
  initialData?: Recipe;
  onSave: (recipe: Omit<Recipe, 'id' | 'createdAt'>) => void;
  onCancel: () => void;
}

export const RecipeForm: React.FC<RecipeFormProps> = ({ 
  categoryId, 
  categoryName,
  initialData, 
  onSave, 
  onCancel 
}) => {
  const [name, setName] = useState(initialData?.name || '');
  const [description, setDescription] = useState(initialData?.description || '');
  // Ingredients and Instructions are stored as newline-separated strings for easier editing in textarea
  const [ingredientsText, setIngredientsText] = useState(initialData?.ingredients.join('\n') || '');
  const [instructionsText, setInstructionsText] = useState(initialData?.instructions.join('\n') || '');
  const [cookingTime, setCookingTime] = useState(initialData?.cookingTime || '');
  const [difficulty, setDifficulty] = useState<'Easy' | 'Medium' | 'Hard'>(initialData?.difficulty || 'Medium');

  const [isGenerating, setIsGenerating] = useState(false);

  const handleAISuggest = async () => {
    if (!name.trim()) {
      alert("请输入菜名以便AI为您生成食谱");
      return;
    }

    setIsGenerating(true);
    try {
      const generated = await generateRecipeWithAI(name, categoryName);
      if (generated) {
        if (generated.description) setDescription(generated.description);
        if (generated.ingredients) setIngredientsText(generated.ingredients.join('\n'));
        if (generated.instructions) setInstructionsText(generated.instructions.join('\n'));
        if (generated.cookingTime) setCookingTime(generated.cookingTime);
        if (generated.difficulty) setDifficulty(generated.difficulty as any);
      }
    } catch (e) {
      alert("AI 生成失败，请稍后重试。");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      categoryId,
      name,
      description,
      ingredients: ingredientsText.split('\n').filter(line => line.trim() !== ''),
      instructions: instructionsText.split('\n').filter(line => line.trim() !== ''),
      cookingTime,
      difficulty
    });
  };

  return (
    <div className="max-w-3xl mx-auto p-4 sm:p-6 bg-white rounded-xl shadow-lg my-4">
      <div className="flex justify-between items-center mb-6 border-b pb-4">
        <h2 className="text-2xl font-bold text-gray-800">
          {initialData ? '编辑食谱' : '添加新食谱'}
        </h2>
        <button onClick={onCancel} className="text-gray-400 hover:text-gray-600">
          <X className="w-6 h-6" />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Name Input with AI Button */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">菜品名称</label>
          <div className="flex gap-2">
            <input
              type="text"
              required
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="flex-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-orange-500 focus:ring-orange-500 sm:text-sm border p-2"
              placeholder="例如：红烧肉"
            />
            <button
              type="button"
              onClick={handleAISuggest}
              disabled={isGenerating || !name.trim()}
              className="inline-flex items-center px-4 py-2 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {isGenerating ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Sparkles className="w-4 h-4 mr-2" />}
              AI 自动填充
            </button>
          </div>
          <p className="mt-1 text-xs text-gray-500">输入菜名后点击 "AI 自动填充" 可自动生成食谱内容。</p>
        </div>

        {/* Description */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">简介</label>
          <textarea
            rows={2}
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            className="block w-full rounded-md border-gray-300 shadow-sm focus:border-orange-500 focus:ring-orange-500 sm:text-sm border p-2"
            placeholder="简要描述这道菜..."
          />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
           {/* Ingredients */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">食材清单 (每行一项)</label>
            <textarea
              rows={8}
              required
              value={ingredientsText}
              onChange={(e) => setIngredientsText(e.target.value)}
              className="block w-full rounded-md border-gray-300 shadow-sm focus:border-orange-500 focus:ring-orange-500 sm:text-sm border p-2 font-mono"
              placeholder="500g 五花肉&#10;2片 姜&#10;2勺 酱油"
            />
          </div>

          {/* Instructions */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">制作步骤 (每行一步)</label>
            <textarea
              rows={8}
              required
              value={instructionsText}
              onChange={(e) => setInstructionsText(e.target.value)}
              className="block w-full rounded-md border-gray-300 shadow-sm focus:border-orange-500 focus:ring-orange-500 sm:text-sm border p-2 font-mono"
              placeholder="1. 洗净猪肉...&#10;2. 冷水下锅焯水...&#10;3. 炒糖色..."
            />
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {/* Cooking Time */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">烹饪时间</label>
            <input
              type="text"
              value={cookingTime}
              onChange={(e) => setCookingTime(e.target.value)}
              className="block w-full rounded-md border-gray-300 shadow-sm focus:border-orange-500 focus:ring-orange-500 sm:text-sm border p-2"
              placeholder="例如：45分钟"
            />
          </div>

          {/* Difficulty */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">难度</label>
            <select
              value={difficulty}
              onChange={(e) => setDifficulty(e.target.value as any)}
              className="block w-full rounded-md border-gray-300 shadow-sm focus:border-orange-500 focus:ring-orange-500 sm:text-sm border p-2 bg-white"
            >
              <option value="Easy">简单</option>
              <option value="Medium">中等</option>
              <option value="Hard">困难</option>
            </select>
          </div>
        </div>

        <div className="flex justify-end pt-4 border-t gap-3">
          <button
            type="button"
            onClick={onCancel}
            className="px-4 py-2 border border-gray-300 rounded-md text-sm font-medium text-gray-700 hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-orange-500"
          >
            取消
          </button>
          <button
            type="submit"
            className="inline-flex items-center px-4 py-2 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-orange-600 hover:bg-orange-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-orange-500"
          >
            <Save className="w-4 h-4 mr-2" />
            保存食谱
          </button>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { CategoryCard } from './components/CategoryCard';
import { RecipeForm } from './components/RecipeForm';
import { RecipeDetail } from './components/RecipeDetail';
import { Category, CategoryId, Recipe, ViewState } from './types';
import { CATEGORIES, getIconComponent } from './constants';
import { Plus, ArrowLeft, Wand2, Loader2, Search } from 'lucide-react';
import { suggestRandomRecipe } from './services/geminiService';

export default function App() {
  const [recipes, setRecipes] = useState<Recipe[]>([]);
  const [viewState, setViewState] = useState<ViewState>({ type: 'HOME' });
  const [searchTerm, setSearchTerm] = useState('');
  const [isSuggesting, setIsSuggesting] = useState(false);

  // Load recipes from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem('smart-recipe-book-data');
    if (saved) {
      try {
        setRecipes(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load recipes", e);
      }
    } else {
      // Seed some initial data if empty? Maybe not, keep it clean.
    }
  }, []);

  // Save recipes to local storage whenever they change
  useEffect(() => {
    localStorage.setItem('smart-recipe-book-data', JSON.stringify(recipes));
  }, [recipes]);

  const handleSaveRecipe = (newRecipeData: Omit<Recipe, 'id' | 'createdAt'>) => {
    const newRecipe: Recipe = {
      ...newRecipeData,
      id: crypto.randomUUID(),
      createdAt: Date.now()
    };
    setRecipes(prev => [...prev, newRecipe]);
    setViewState({ type: 'CATEGORY', categoryId: newRecipeData.categoryId });
  };

  const handleSuggestRecipe = async (categoryId: CategoryId, categoryName: string) => {
    setIsSuggesting(true);
    try {
      const suggestion = await suggestRandomRecipe(categoryName);
      if (suggestion && suggestion.name && suggestion.instructions) {
        const newRecipe: Recipe = {
          id: crypto.randomUUID(),
          categoryId,
          name: suggestion.name,
          description: suggestion.description || '',
          ingredients: suggestion.ingredients || [],
          instructions: suggestion.instructions || [],
          cookingTime: suggestion.cookingTime || '30 mins',
          difficulty: (suggestion.difficulty as any) || 'Medium',
          createdAt: Date.now()
        };
        setRecipes(prev => [...prev, newRecipe]);
      }
    } catch (e) {
      alert("推荐生成失败，请检查网络或API Key");
    } finally {
      setIsSuggesting(false);
    }
  };

  const renderContent = () => {
    switch (viewState.type) {
      case 'HOME':
        const filteredCategories = CATEGORIES.filter(c => 
          c.name.includes(searchTerm) || c.description.includes(searchTerm)
        );

        return (
          <div className="p-4 sm:p-6">
            <div className="mb-6 relative">
               <input 
                 type="text" 
                 placeholder="搜索分类..." 
                 value={searchTerm}
                 onChange={e => setSearchTerm(e.target.value)}
                 className="w-full pl-10 pr-4 py-3 rounded-xl border-gray-200 shadow-sm focus:ring-2 focus:ring-orange-500 focus:border-transparent transition-all outline-none"
               />
               <Search className="absolute left-3 top-3.5 text-gray-400 w-5 h-5" />
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {filteredCategories.map(category => (
                <CategoryCard
                  key={category.id}
                  category={category}
                  count={recipes.filter(r => r.categoryId === category.id).length}
                  onClick={() => setViewState({ type: 'CATEGORY', categoryId: category.id })}
                />
              ))}
            </div>

            {recipes.length === 0 && (
               <div className="mt-12 text-center text-gray-400">
                  <p>您的食谱本还是空的。</p>
                  <p>点击上方分类开始添加美食吧！</p>
               </div>
            )}
          </div>
        );

      case 'CATEGORY':
        const category = CATEGORIES.find(c => c.id === viewState.categoryId);
        if (!category) return <div>Category not found</div>;

        const categoryRecipes = recipes.filter(r => r.categoryId === category.id);

        return (
          <div className="p-4 sm:p-6 min-h-screen">
            <div className="flex items-center justify-between mb-6">
              <button 
                onClick={() => setViewState({ type: 'HOME' })}
                className="flex items-center text-gray-600 hover:text-orange-600 transition-colors"
              >
                <ArrowLeft className="w-5 h-5 mr-1" />
                <span className="font-medium">返回</span>
              </button>

              <div className="flex gap-2">
                 <button
                  onClick={() => handleSuggestRecipe(category.id, category.name)}
                  disabled={isSuggesting}
                  className="flex items-center px-3 py-2 bg-indigo-50 text-indigo-600 rounded-lg hover:bg-indigo-100 transition-colors text-sm font-medium disabled:opacity-50"
                >
                  {isSuggesting ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Wand2 className="w-4 h-4 mr-2" />}
                  AI 帮我想一个
                </button>
                <button
                  onClick={() => setViewState({ type: 'ADD_RECIPE', categoryId: category.id })}
                  className="flex items-center px-3 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 transition-colors shadow-md text-sm font-medium"
                >
                  <Plus className="w-4 h-4 mr-2" />
                  添加食谱
                </button>
              </div>
            </div>

            <div className="flex items-center gap-3 mb-8">
               <div className={`p-3 rounded-full ${category.color} bg-opacity-20`}>
                 {getIconComponent(category.icon, "w-8 h-8")}
               </div>
               <div>
                 <h2 className="text-2xl font-bold text-gray-800">{category.name}</h2>
                 <p className="text-gray-500 text-sm">{category.description}</p>
               </div>
            </div>

            {categoryRecipes.length === 0 ? (
              <div className="text-center py-20 bg-white rounded-xl border border-dashed border-gray-300">
                <div className="mx-auto w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mb-4">
                  <Plus className="w-8 h-8 text-gray-400" />
                </div>
                <h3 className="text-lg font-medium text-gray-900">暂无食谱</h3>
                <p className="mt-1 text-gray-500">点击右上角添加您的第一道{category.name}！</p>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {categoryRecipes.map(recipe => (
                  <div 
                    key={recipe.id}
                    onClick={() => setViewState({ type: 'RECIPE_DETAIL', recipeId: recipe.id })}
                    className="bg-white p-4 rounded-xl shadow-sm hover:shadow-md transition-all cursor-pointer border border-gray-100 flex flex-col"
                  >
                    <div className="flex justify-between items-start mb-2">
                       <h3 className="font-bold text-lg text-gray-800 truncate pr-2">{recipe.name}</h3>
                       <span className={`text-xs px-2 py-1 rounded-full whitespace-nowrap ${
                         recipe.difficulty === 'Easy' ? 'bg-green-100 text-green-700' :
                         recipe.difficulty === 'Medium' ? 'bg-yellow-100 text-yellow-700' :
                         'bg-red-100 text-red-700'
                       }`}>
                         {recipe.difficulty === 'Easy' ? '简单' : recipe.difficulty === 'Medium' ? '中等' : '困难'}
                       </span>
                    </div>
                    <p className="text-gray-500 text-sm line-clamp-2 mb-3 flex-1">
                      {recipe.description || recipe.instructions[0]}
                    </p>
                    <div className="text-xs text-gray-400 mt-auto pt-2 border-t">
                       烹饪时间: {recipe.cookingTime}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        );

      case 'ADD_RECIPE':
        const addCategory = CATEGORIES.find(c => c.id === viewState.categoryId);
        return (
          <RecipeForm
            categoryId={viewState.categoryId}
            categoryName={addCategory?.name || ''}
            onSave={handleSaveRecipe}
            onCancel={() => setViewState({ type: 'CATEGORY', categoryId: viewState.categoryId })}
          />
        );

      case 'RECIPE_DETAIL':
        const recipe = recipes.find(r => r.id === viewState.recipeId);
        if (!recipe) return <div>Recipe not found</div>;
        return (
          <RecipeDetail
            recipe={recipe}
            onBack={() => setViewState({ type: 'CATEGORY', categoryId: recipe.categoryId })}
          />
        );

      default:
        return <div>Unknown view</div>;
    }
  };

  return (
    <Layout onHomeClick={() => setViewState({ type: 'HOME' })}>
      {renderContent()}
    </Layout>
  );
}

