            <div className="flex items-center gap-1 bg-gray-50 px-3 py-1 rounded-full">
              <BarChart className="w-4 h-4" />
              <span>难度: {recipe.difficulty === 'Easy' ? '简单' : recipe.difficulty === 'Medium' ? '中等' : '困难'}</span>
            </div>
          </div>

          <div className="mb-8">
             <p className="text-gray-600 leading-relaxed italic border-l-4 border-orange-200 pl-4">
               {recipe.description || '暂无简介'}
             </p>
          </div>

          <div className="grid md:grid-cols-3 gap-8">
            <div className="md:col-span-1">
              <h3 className="text-lg font-bold text-gray-800 mb-4 flex items-center">
                <span className="w-1 h-6 bg-orange-500 mr-2 rounded-full"></span>
                食材清单
              </h3>
              <ul className="space-y-3">
                {recipe.ingredients.map((ing, idx) => (
                  <li key={idx} className="flex items-start text-gray-700 border-b border-dashed border-gray-100 pb-2 last:border-0">
                    <span className="w-2 h-2 mt-2 bg-orange-300 rounded-full mr-2 flex-shrink-0"></span>
                    <span>{ing}</span>
                  </li>
                ))}
              </ul>
            </div>

            <div className="md:col-span-2">
              <h3 className="text-lg font-bold text-gray-800 mb-4 flex items-center">
                <span className="w-1 h-6 bg-orange-500 mr-2 rounded-full"></span>
                制作步骤
              </h3>
              <div className="space-y-6">
                {recipe.instructions.map((step, idx) => (
                  <div key={idx} className="flex gap-4">
                    <div className="flex-shrink-0 w-8 h-8 bg-orange-100 text-orange-600 rounded-full flex items-center justify-center font-bold text-sm">
                      {idx + 1}
                    </div>
                    <div className="pt-1">
                      <p className="text-gray-700 leading-relaxed">{step}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export enum CategoryIdEnum {
  MEAT = 'meat',
  VEGETABLE = 'vegetable',
  SOUP = 'soup',
  STAPLE = 'staple',
  SNACK = 'snack',
  DESSERT = 'dessert',
  DRINK = 'drink',
  HEALTH = 'health'
}

export type CategoryId = string;

export interface Category {
  id: CategoryId;
  name: string;
  icon: string;
  color: string;
  description: string;
}

export interface Recipe {
  id: string;
  categoryId: CategoryId;
  name: string;
  description: string;
  ingredients: string[];
  instructions: string[];
  cookingTime: string;
  difficulty: 'Easy' | 'Medium' | 'Hard';
  createdAt: number;
}

export type ViewState = 
  | { type: 'HOME' }
  | { type: 'CATEGORY'; categoryId: CategoryId }
  | { type: 'RECIPE_DETAIL'; recipeId: string }
  | { type: 'ADD_RECIPE'; categoryId: CategoryId }
  | { type: 'EDIT_RECIPE'; recipeId: string }
  | { type: 'ADD_CATEGORY' };

