import React, { useState } from 'react';
import { Category } from '../types';
import { Save, X } from 'lucide-react';

interface CategoryFormProps {
  onSave: (categoryData: Omit<Category, 'id'>) => void;
  onCancel: () => void;
}

const COLORS = [
  { label: '红色', value: 'bg-red-100 text-red-600' },
  { label: '绿色', value: 'bg-green-100 text-green-600' },
  { label: '蓝色', value: 'bg-blue-100 text-blue-600' },
  { label: '黄色', value: 'bg-yellow-100 text-yellow-600' },
  { label: '橙色', value: 'bg-orange-100 text-orange-600' },
  { label: '粉色', value: 'bg-pink-100 text-pink-600' },
  { label: '青色', value: 'bg-cyan-100 text-cyan-600' },
  { label: '紫色', value: 'bg-purple-100 text-purple-600' },
  { label: '翠绿', value: 'bg-emerald-100 text-emerald-600' },
];

export const CategoryForm: React.FC<CategoryFormProps> = ({ onSave, onCancel }) => {
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [selectedColor, setSelectedColor] = useState(COLORS[4].value); // Default orange

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) return;

    onSave({
      name,
      description,
      color: selectedColor,
      icon: 'Utensils' // Default icon
    });
  };

  return (
    <div className="max-w-xl mx-auto p-4 sm:p-6 bg-white rounded-xl shadow-lg my-4">
      <div className="flex justify-between items-center mb-6 border-b pb-4">
        <h2 className="text-2xl font-bold text-gray-800">
          添加新分类
        </h2>
        <button onClick={onCancel} className="text-gray-400 hover:text-gray-600">
          <X className="w-6 h-6" />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">分类名称</label>
          <input
            type="text"
            required
            value={name}
            onChange={(e) => setName(e.target.value)}
            className="block w-full rounded-md border-gray-300 shadow-sm focus:border-orange-500 focus:ring-orange-500 sm:text-sm border p-2"
            placeholder="例如：海鲜"
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">描述</label>
          <textarea
            rows={3}
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            className="block w-full rounded-md border-gray-300 shadow-sm focus:border-orange-500 focus:ring-orange-500 sm:text-sm border p-2"
            placeholder="例如：各种美味的海鲜料理"
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">主题颜色</label>
          <div className="grid grid-cols-3 sm:grid-cols-5 gap-3">
            {COLORS.map((color) => (
              <button
                key={color.value}
                type="button"
                onClick={() => setSelectedColor(color.value)}
                className={`h-10 rounded-lg border-2 flex items-center justify-center text-xs font-bold ${
                  color.value.split(' ')[0]
                } ${
                  selectedColor === color.value 
                    ? 'border-gray-600 scale-105 shadow-md' 
                    : 'border-transparent opacity-70 hover:opacity-100'
                }`}
              >
                {selectedColor === color.value && '✓'}
              </button>
            ))}
          </div>
        </div>

        <div className="flex justify-end pt-4 border-t gap-3">
          <button
            type="button"
            onClick={onCancel}
            className="px-4 py-2 border border-gray-300 rounded-md text-sm font-medium text-gray-700 hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-orange-500"
          >
            取消
          </button>
          <button
            type="submit"
            className="inline-flex items-center px-4 py-2 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-orange-600 hover:bg-orange-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-orange-500"
          >
            <Save className="w-4 h-4 mr-2" />
            保存分类
          </button>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { CategoryCard } from './components/CategoryCard';
import { RecipeForm } from './components/RecipeForm';
import { RecipeDetail } from './components/RecipeDetail';
import { CategoryForm } from './components/CategoryForm';
import { Category, CategoryId, Recipe, ViewState } from './types';
import { DEFAULT_CATEGORIES, getIconComponent } from './constants';
import { Plus, ArrowLeft, Loader2, Search, Pencil, Trash2 } from 'lucide-react';
import { suggestRandomRecipe, generateRecipeWithAI } from './services/geminiService';

export default function App() {
  const [categories, setCategories] = useState<Category[]>([]);
  const [recipes, setRecipes] = useState<Recipe[]>([]);
  const [viewState, setViewState] = useState<ViewState>({ type: 'HOME' });
  const [searchTerm, setSearchTerm] = useState('');
  const [isSuggesting, setIsSuggesting] = useState(false);

  // Initialize Data
  useEffect(() => {
    // Load Recipes
    const savedRecipes = localStorage.getItem('smart-recipe-book-data');
    if (savedRecipes) {
      try {
        setRecipes(JSON.parse(savedRecipes));
      } catch (e) {
        console.error("Failed to load recipes", e);
      }
    }

    // Load Categories
    const savedCategories = localStorage.getItem('smart-recipe-book-categories');
    if (savedCategories) {
      try {
        setCategories(JSON.parse(savedCategories));
      } catch (e) {
        setCategories(DEFAULT_CATEGORIES);
      }
    } else {
      setCategories(DEFAULT_CATEGORIES);
    }
  }, []);

  // Persistence
  useEffect(() => {
    if (recipes.length > 0) {
      localStorage.setItem('smart-recipe-book-data', JSON.stringify(recipes));
    }
  }, [recipes]);

  useEffect(() => {
    if (categories.length > 0) {
      localStorage.setItem('smart-recipe-book-categories', JSON.stringify(categories));
    }
  }, [categories]);

  // --- Recipe Actions ---

  const handleSaveRecipe = (newRecipeData: Omit<Recipe, 'id' | 'createdAt'>) => {
    if (viewState.type === 'EDIT_RECIPE') {
      const updatedRecipes = recipes.map(r => 
        r.id === viewState.recipeId ? { ...r, ...newRecipeData } : r
      );
      setRecipes(updatedRecipes);
      setViewState({ type: 'RECIPE_DETAIL', recipeId: viewState.recipeId });
    } else {
      const newRecipe: Recipe = {
        ...newRecipeData,
        id: crypto.randomUUID(),
        createdAt: Date.now()
      };
      setRecipes(prev => [...prev, newRecipe]);
      setViewState({ type: 'CATEGORY', categoryId: newRecipeData.categoryId });
    }
  };

  const handleDeleteRecipe = (recipeId: string, categoryId: CategoryId) => {
    if (window.confirm('确定要删除这道菜谱吗？')) {
      setRecipes(prev => prev.filter(r => r.id !== recipeId));
      setViewState({ type: 'CATEGORY', categoryId });
    }
  };

  const handleSuggestRecipe = async (categoryId: CategoryId, categoryName: string) => {
    const userDishName = window.prompt("您想吃什么？\n输入菜名，AI为您生成食谱。\n如果不输入直接点击确认，AI将为您随机推荐一道菜。");

    // User cancelled
    if (userDishName === null) return;

    setIsSuggesting(true);
    try {
      let suggestion: Partial<Recipe>;

      if (userDishName.trim()) {
        // User provided a name
        suggestion = await generateRecipeWithAI(userDishName, categoryName);
      } else {
        // Random suggestion
        suggestion = await suggestRandomRecipe(categoryName);
      }

      if (suggestion && suggestion.name && suggestion.instructions) {
        const newRecipe: Recipe = {
          id: crypto.randomUUID(),
          categoryId,
          name: suggestion.name,
          description: suggestion.description || '',
          ingredients: suggestion.ingredients || [],
          instructions: suggestion.instructions || [],
          cookingTime: suggestion.cookingTime || '30 mins',
          difficulty: (suggestion.difficulty as any) || 'Medium',
          createdAt: Date.now()
        };
        setRecipes(prev => [...prev, newRecipe]);
      }
    } catch (e) {
      alert("生成失败，请检查网络或API Key");
    } finally {
      setIsSuggesting(false);
    }
  };

  // --- Category Actions ---

  const handleSaveCategory = (categoryData: Omit<Category, 'id'>) => {
    const newCategory: Category = {
      ...categoryData,
      id: `custom-${crypto.randomUUID()}`,
    };
    setCategories(prev => [...prev, newCategory]);
    setViewState({ type: 'HOME' });
  };

  const handleEditCategory = (e: React.MouseEvent, category: Category) => {
    e.stopPropagation();
    const newName = window.prompt("修改分类名称", category.name);
    if (newName && newName.trim() !== '') {
       setCategories(prev => prev.map(c => c.id === category.id ? { ...c, name: newName } : c));
    }
  };

  const handleDeleteCategory = (e: React.MouseEvent, categoryId: CategoryId) => {
    e.stopPropagation();
    const count = recipes.filter(r => r.categoryId === categoryId).length;
    if (window.confirm(`确定要删除此分类吗？\n这将同时删除该分类下的 ${count} 道食谱！`)) {
      setRecipes(prev => prev.filter(r => r.categoryId !== categoryId));
      setCategories(prev => prev.filter(c => c.id !== categoryId));
    }
  };


  const renderContent = () => {
    switch (viewState.type) {
      case 'HOME':
        const filteredCategories = categories.filter(c => 
          c.name.includes(searchTerm) || c.description.includes(searchTerm)
        );

        return (
          <div className="p-4 sm:p-6">
            <div className="mb-6 relative">
               <input 
                 type="text" 
                 placeholder="搜索分类..." 
                 value={searchTerm}
                 onChange={e => setSearchTerm(e.target.value)}
                 className="w-full pl-10 pr-4 py-3 rounded-xl border-gray-200 shadow-sm focus:ring-2 focus:ring-orange-500 focus:border-transparent transition-all outline-none"
               />
               <Search className="absolute left-3 top-3.5 text-gray-400 w-5 h-5" />
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {filteredCategories.map(category => (
                <CategoryCard
                  key={category.id}
                  category={category}
                  count={recipes.filter(r => r.categoryId === category.id).length}
                  onClick={() => setViewState({ type: 'CATEGORY', categoryId: category.id })}
                  // onEdit and onDelete removed as requested
                />
              ))}

              {/* "More" Card to add new category */}
              <button 
                 onClick={() => setViewState({ type: 'ADD_CATEGORY' })}
                 className="flex flex-col items-center justify-center p-6 rounded-2xl bg-white border-2 border-dashed border-gray-300 hover:border-orange-500 hover:bg-orange-50 transition-all min-h-[160px] group"
              >
                <div className="p-3 rounded-full bg-gray-100 group-hover:bg-orange-100 mb-3 transition-colors">
                  <Plus className="w-8 h-8 text-gray-400 group-hover:text-orange-500" />
                </div>
                <h3 className="text-lg font-bold text-gray-600 group-hover:text-orange-600">更多</h3>
                <p className="text-sm text-gray-400">添加自定义分类</p>
              </button>
            </div>

            {categories.length === 0 && (
              <div className="text-center py-12">
                <p className="text-gray-500">没有分类，请刷新页面重置默认数据。</p>
              </div>
            )}

            {recipes.length === 0 && categories.length > 0 && (
               <div className="mt-12 text-center text-gray-400">
                  <p>您的食谱本还是空的。</p>
                  <p>点击上方分类开始添加美食吧！</p>
               </div>
            )}
          </div>
        );

      case 'ADD_CATEGORY':
        return (
          <CategoryForm 
            onSave={handleSaveCategory}
            onCancel={() => setViewState({ type: 'HOME' })}
          />
        );

      case 'CATEGORY':
        const category = categories.find(c => c.id === viewState.categoryId);
        if (!category) return <div>Category not found</div>;

        const categoryRecipes = recipes.filter(r => r.categoryId === category.id);

        return (
          <div className="p-4 sm:p-6 min-h-screen">
            <div className="flex items-center justify-between mb-6">
              <button 
                onClick={() => setViewState({ type: 'HOME' })}
                className="flex items-center text-gray-600 hover:text-orange-600 transition-colors"
              >
                <ArrowLeft className="w-5 h-5 mr-1" />
                <span className="font-medium">返回</span>
              </button>

              <div className="flex gap-2">
                 {/* Removed AI Suggest Button as requested */}
                <button
                  onClick={() => setViewState({ type: 'ADD_RECIPE', categoryId: category.id })}
                  className="flex items-center px-3 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 transition-colors shadow-md text-sm font-medium"
                >
                  <Plus className="w-4 h-4 mr-2" />
                  添加食谱
                </button>
              </div>
            </div>

            <div className="flex items-center gap-3 mb-8">
               <div className={`p-3 rounded-full ${category.color} bg-opacity-20`}>
                 {getIconComponent(category.icon, "w-8 h-8")}
               </div>
               <div>
                 <h2 className="text-2xl font-bold text-gray-800">{category.name}</h2>
                 <p className="text-gray-500 text-sm">{category.description}</p>
               </div>
            </div>

            {categoryRecipes.length === 0 ? (
              <div className="text-center py-20 bg-white rounded-xl border border-dashed border-gray-300">
                <div className="mx-auto w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mb-4">
                  <Plus className="w-8 h-8 text-gray-400" />
                </div>
                <h3 className="text-lg font-medium text-gray-900">暂无食谱</h3>
                <p className="mt-1 text-gray-500">点击右上角添加您的第一道{category.name}！</p>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {categoryRecipes.map(recipe => (
                  <div 
                    key={recipe.id}
                    onClick={() => setViewState({ type: 'RECIPE_DETAIL', recipeId: recipe.id })}
                    className="group bg-white p-4 rounded-xl shadow-sm hover:shadow-md transition-all cursor-pointer border border-gray-100 flex flex-col relative"
                  >
                    {/* Recipe Action Buttons on List View */}
                    <div className="absolute top-2 right-2 flex space-x-1 opacity-0 group-hover:opacity-100 transition-opacity z-10 bg-white/80 rounded-full p-1 shadow-sm backdrop-blur-sm">
                      <button
                        onClick={(e) => { e.stopPropagation(); setViewState({ type: 'EDIT_RECIPE', recipeId: recipe.id }); }}
                        className="p-1.5 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-full"
                        title="编辑"
                      >
                        <Pencil className="w-3.5 h-3.5" />
                      </button>
                      <button
                        onClick={(e) => { e.stopPropagation(); handleDeleteRecipe(recipe.id, category.id); }}
                        className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-full"
                        title="删除"
                      >
                        <Trash2 className="w-3.5 h-3.5" />
                      </button>
                    </div>

                    <div className="flex justify-between items-start mb-2 mt-1">
                       <h3 className="font-bold text-lg text-gray-800 truncate pr-2">{recipe.name}</h3>
                       <span className={`text-xs px-2 py-1 rounded-full whitespace-nowrap ${
                         recipe.difficulty === 'Easy' ? 'bg-green-100 text-green-700' :
                         recipe.difficulty === 'Medium' ? 'bg-yellow-100 text-yellow-700' :
                         'bg-red-100 text-red-700'
                       }`}>
                         {recipe.difficulty === 'Easy' ? '简单' : recipe.difficulty === 'Medium' ? '中等' : '困难'}
                       </span>
                    </div>
                    <p className="text-gray-500 text-sm line-clamp-2 mb-3 flex-1">
                      {recipe.description || recipe.instructions[0]}
                    </p>
                    <div className="text-xs text-gray-400 mt-auto pt-2 border-t">
                       烹饪时间: {recipe.cookingTime}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        );

      case 'ADD_RECIPE':
        const addCategory = categories.find(c => c.id === viewState.categoryId);
        return (
          <RecipeForm
            categoryId={viewState.categoryId}
            categoryName={addCategory?.name || ''}
            onSave={handleSaveRecipe}
            onCancel={() => setViewState({ type: 'CATEGORY', categoryId: viewState.categoryId })}
          />
        );

      case 'EDIT_RECIPE':
        const editRecipe = recipes.find(r => r.id === viewState.recipeId);
        if (!editRecipe) return <div>Recipe not found</div>;
        const editCategory = categories.find(c => c.id === editRecipe.categoryId);

        return (
          <RecipeForm
            categoryId={editRecipe.categoryId}
            categoryName={editCategory?.name || ''}
            initialData={editRecipe}
            onSave={handleSaveRecipe}
            onCancel={() => setViewState({ type: 'RECIPE_DETAIL', recipeId: editRecipe.id })}
          />
        );

      case 'RECIPE_DETAIL':
        const recipe = recipes.find(r => r.id === viewState.recipeId);
        if (!recipe) return <div>Recipe not found</div>;
        return (
          <RecipeDetail
            recipe={recipe}
            onBack={() => setViewState({ type: 'CATEGORY', categoryId: recipe.categoryId })}
            onEdit={() => setViewState({ type: 'EDIT_RECIPE', recipeId: recipe.id })}
            onDelete={() => handleDeleteRecipe(recipe.id, recipe.categoryId)}
          />
        );

      default:
        return <div>Unknown view</div>;
    }
  };

  return (
    <Layout onHomeClick={() => setViewState({ type: 'HOME' })}>
      {renderContent()}
    </Layout>
  );
}

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { CategoryCard } from './components/CategoryCard';
import { RecipeForm } from './components/RecipeForm';
import { RecipeDetail } from './components/RecipeDetail';
import { CategoryForm } from './components/CategoryForm';
import { Category, CategoryId, Recipe, ViewState } from './types';
import { DEFAULT_CATEGORIES, getIconComponent } from './constants';
import { Plus, ArrowLeft, Loader2, Search, Pencil, Trash2 } from 'lucide-react';
import { suggestRandomRecipe, generateRecipeWithAI } from './services/geminiService';

export default function App() {
  const [categories, setCategories] = useState<Category[]>([]);
  const [recipes, setRecipes] = useState<Recipe[]>([]);
  const [viewState, setViewState] = useState<ViewState>({ type: 'HOME' });
  const [searchTerm, setSearchTerm] = useState('');
  const [isSuggesting, setIsSuggesting] = useState(false);

  // Initialize Data
  useEffect(() => {
    // Load Recipes
    const savedRecipes = localStorage.getItem('smart-recipe-book-data');
    if (savedRecipes) {
      try {
        setRecipes(JSON.parse(savedRecipes));
      } catch (e) {
        console.error("Failed to load recipes", e);
      }
    }

    // Load Categories
    const savedCategories = localStorage.getItem('smart-recipe-book-categories');
    if (savedCategories) {
      try {
        setCategories(JSON.parse(savedCategories));
      } catch (e) {
        setCategories(DEFAULT_CATEGORIES);
      }
    } else {
      setCategories(DEFAULT_CATEGORIES);
    }
  }, []);

  // Persistence
  useEffect(() => {
    if (recipes.length > 0) {
      localStorage.setItem('smart-recipe-book-data', JSON.stringify(recipes));
    }
  }, [recipes]);

  useEffect(() => {
    if (categories.length > 0) {
      localStorage.setItem('smart-recipe-book-categories', JSON.stringify(categories));
    }
  }, [categories]);

  // --- Navigation Helpers ---
  const navigateToHome = () => {
    setSearchTerm('');
    setViewState({ type: 'HOME' });
  };

  const navigateToCategory = (categoryId: CategoryId) => {
    setSearchTerm('');
    setViewState({ type: 'CATEGORY', categoryId });
  };

  // --- Recipe Actions ---

  const handleSaveRecipe = (newRecipeData: Omit<Recipe, 'id' | 'createdAt'>) => {
    if (viewState.type === 'EDIT_RECIPE') {
      const updatedRecipes = recipes.map(r => 
        r.id === viewState.recipeId ? { ...r, ...newRecipeData } : r
      );
      setRecipes(updatedRecipes);
      setViewState({ type: 'RECIPE_DETAIL', recipeId: viewState.recipeId });
    } else {
      const newRecipe: Recipe = {
        ...newRecipeData,
        id: crypto.randomUUID(),
        createdAt: Date.now()
      };
      setRecipes(prev => [...prev, newRecipe]);
      setViewState({ type: 'CATEGORY', categoryId: newRecipeData.categoryId });
    }
  };

  const handleDeleteRecipe = (recipeId: string, categoryId: CategoryId) => {
    if (window.confirm('确定要删除这道菜谱吗？')) {
      setRecipes(prev => prev.filter(r => r.id !== recipeId));
      setViewState({ type: 'CATEGORY', categoryId });
    }
  };

  const handleSuggestRecipe = async (categoryId: CategoryId, categoryName: string) => {
    const userDishName = window.prompt("您想吃什么？\n输入菜名，AI为您生成食谱。\n如果不输入直接点击确认，AI将为您随机推荐一道菜。");

    // User cancelled
    if (userDishName === null) return;

    setIsSuggesting(true);
    try {
      let suggestion: Partial<Recipe>;

      if (userDishName.trim()) {
        // User provided a name
        suggestion = await generateRecipeWithAI(userDishName, categoryName);
      } else {
        // Random suggestion
        suggestion = await suggestRandomRecipe(categoryName);
      }

      if (suggestion && suggestion.name && suggestion.instructions) {
        const newRecipe: Recipe = {
          id: crypto.randomUUID(),
          categoryId,
          name: suggestion.name,
          description: suggestion.description || '',
          ingredients: suggestion.ingredients || [],
          instructions: suggestion.instructions || [],
          cookingTime: suggestion.cookingTime || '30 mins',
          difficulty: (suggestion.difficulty as any) || 'Medium',
          createdAt: Date.now()
        };
        setRecipes(prev => [...prev, newRecipe]);
      }
    } catch (e) {
      alert("生成失败，请检查网络或API Key");
    } finally {
      setIsSuggesting(false);
    }
  };

  // --- Category Actions ---

  const handleSaveCategory = (categoryData: Omit<Category, 'id'>) => {
    const newCategory: Category = {
      ...categoryData,
      id: `custom-${crypto.randomUUID()}`,
    };
    setCategories(prev => [...prev, newCategory]);
    navigateToHome();
  };

  const handleEditCategory = (e: React.MouseEvent, category: Category) => {
    e.stopPropagation();
    const newName = window.prompt("修改分类名称", category.name);
    if (newName && newName.trim() !== '') {
       setCategories(prev => prev.map(c => c.id === category.id ? { ...c, name: newName } : c));
    }
  };

  const handleDeleteCategory = (e: React.MouseEvent, categoryId: CategoryId) => {
    e.stopPropagation();
    const count = recipes.filter(r => r.categoryId === categoryId).length;
    if (window.confirm(`确定要删除此分类吗？\n这将同时删除该分类下的 ${count} 道食谱！`)) {
      setRecipes(prev => prev.filter(r => r.categoryId !== categoryId));
      setCategories(prev => prev.filter(c => c.id !== categoryId));
    }
  };


  const renderContent = () => {
    switch (viewState.type) {
      case 'HOME':
        const filteredCategories = categories.filter(c => 
          c.name.includes(searchTerm) || c.description.includes(searchTerm)
        );

        return (
          <div className="p-4 sm:p-6">
            <div className="mb-6 relative">
               <input 
                 type="text" 
                 placeholder="搜索分类..." 
                 value={searchTerm}
                 onChange={e => setSearchTerm(e.target.value)}
                 className="w-full pl-10 pr-4 py-3 rounded-xl border-gray-200 shadow-sm focus:ring-2 focus:ring-orange-500 focus:border-transparent transition-all outline-none"
               />
               <Search className="absolute left-3 top-3.5 text-gray-400 w-5 h-5" />
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {filteredCategories.map(category => (
                <CategoryCard
                  key={category.id}
                  category={category}
                  count={recipes.filter(r => r.categoryId === category.id).length}
                  onClick={() => navigateToCategory(category.id)}
                  // onEdit and onDelete removed as requested
                />
              ))}

              {/* "More" Card to add new category */}
              <button 
                 onClick={() => setViewState({ type: 'ADD_CATEGORY' })}
                 className="flex flex-col items-center justify-center p-6 rounded-2xl bg-white border-2 border-dashed border-gray-300 hover:border-orange-500 hover:bg-orange-50 transition-all min-h-[160px] group"
              >
                <div className="p-3 rounded-full bg-gray-100 group-hover:bg-orange-100 mb-3 transition-colors">
                  <Plus className="w-8 h-8 text-gray-400 group-hover:text-orange-500" />
                </div>
                <h3 className="text-lg font-bold text-gray-600 group-hover:text-orange-600">更多</h3>
                <p className="text-sm text-gray-400">添加自定义分类</p>
              </button>
            </div>

            {categories.length === 0 && (
              <div className="text-center py-12">
                <p className="text-gray-500">没有分类，请刷新页面重置默认数据。</p>
              </div>
            )}

            {recipes.length === 0 && categories.length > 0 && (
               <div className="mt-12 text-center text-gray-400">
                  <p>您的食谱本还是空的。</p>
                  <p>点击上方分类开始添加美食吧！</p>
               </div>
            )}
          </div>
        );

      case 'ADD_CATEGORY':
        return (
          <CategoryForm 
            onSave={handleSaveCategory}
            onCancel={() => navigateToHome()}
          />
        );

      case 'CATEGORY':
        const category = categories.find(c => c.id === viewState.categoryId);
        if (!category) return <div>Category not found</div>;

        const filteredRecipes = recipes.filter(r => {
           if (r.categoryId !== category.id) return false;
           const term = searchTerm.toLowerCase();
           return (
             r.name.toLowerCase().includes(term) ||
             r.description.toLowerCase().includes(term) ||
             r.ingredients.some(ing => ing.toLowerCase().includes(term))
           );
        });

        return (
          <div className="p-4 sm:p-6 min-h-screen">
            <div className="flex items-center justify-between mb-6">
              <button 
                onClick={() => navigateToHome()}
                className="flex items-center text-gray-600 hover:text-orange-600 transition-colors"
              >
                <ArrowLeft className="w-5 h-5 mr-1" />
                <span className="font-medium">返回</span>
              </button>

              <div className="flex gap-2">
                 {/* Removed AI Suggest Button as requested */}
                <button
                  onClick={() => setViewState({ type: 'ADD_RECIPE', categoryId: category.id })}
                  className="flex items-center px-3 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 transition-colors shadow-md text-sm font-medium"
                >
                  <Plus className="w-4 h-4 mr-2" />
                  添加食谱
                </button>
              </div>
            </div>

            <div className="flex items-center gap-3 mb-6">
               <div className={`p-3 rounded-full ${category.color} bg-opacity-20`}>
                 {getIconComponent(category.icon, "w-8 h-8")}
               </div>
               <div>
                 <h2 className="text-2xl font-bold text-gray-800">{category.name}</h2>
                 <p className="text-gray-500 text-sm">{category.description}</p>
               </div>
            </div>

            {/* Recipe Search Bar */}
            <div className="mb-6 relative">
               <input 
                 type="text" 
                 placeholder={`在 ${category.name} 中搜索食谱...`}
                 value={searchTerm}
                 onChange={e => setSearchTerm(e.target.value)}
                 className="w-full pl-10 pr-4 py-3 rounded-xl border-gray-200 shadow-sm focus:ring-2 focus:ring-orange-500 focus:border-transparent transition-all outline-none"
               />
               <Search className="absolute left-3 top-3.5 text-gray-400 w-5 h-5" />
            </div>

            {filteredRecipes.length === 0 ? (
              <div className="text-center py-20 bg-white rounded-xl border border-dashed border-gray-300">
                {searchTerm ? (
                  <>
                    <div className="mx-auto w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mb-4">
                      <Search className="w-8 h-8 text-gray-400" />
                    </div>
                    <h3 className="text-lg font-medium text-gray-900">未找到相关食谱</h3>
                    <p className="mt-1 text-gray-500">换个关键词试试？</p>
                  </>
                ) : (
                  <>
                    <div className="mx-auto w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mb-4">
                      <Plus className="w-8 h-8 text-gray-400" />
                    </div>
                    <h3 className="text-lg font-medium text-gray-900">暂无食谱</h3>
                    <p className="mt-1 text-gray-500">点击右上角添加您的第一道{category.name}！</p>
                  </>
                )}
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {filteredRecipes.map(recipe => (
                  <div 
                    key={recipe.id}
                    onClick={() => setViewState({ type: 'RECIPE_DETAIL', recipeId: recipe.id })}
                    className="group bg-white p-4 rounded-xl shadow-sm hover:shadow-md transition-all cursor-pointer border border-gray-100 flex flex-col relative"
                  >
                    {/* Recipe Action Buttons on List View */}
                    <div className="absolute top-2 right-2 flex space-x-1 opacity-0 group-hover:opacity-100 transition-opacity z-10 bg-white/80 rounded-full p-1 shadow-sm backdrop-blur-sm">
                      <button
                        onClick={(e) => { e.stopPropagation(); setViewState({ type: 'EDIT_RECIPE', recipeId: recipe.id }); }}
                        className="p-1.5 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-full"
                        title="编辑"
                      >
                        <Pencil className="w-3.5 h-3.5" />
                      </button>
                      <button
                        onClick={(e) => { e.stopPropagation(); handleDeleteRecipe(recipe.id, category.id); }}
                        className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-full"
                        title="删除"
                      >
                        <Trash2 className="w-3.5 h-3.5" />
                      </button>
                    </div>

                    <div className="flex justify-between items-start mb-2 mt-1">
                       <h3 className="font-bold text-lg text-gray-800 truncate pr-2">{recipe.name}</h3>
                       <span className={`text-xs px-2 py-1 rounded-full whitespace-nowrap ${
                         recipe.difficulty === 'Easy' ? 'bg-green-100 text-green-700' :
                         recipe.difficulty === 'Medium' ? 'bg-yellow-100 text-yellow-700' :
                         'bg-red-100 text-red-700'
                       }`}>
                         {recipe.difficulty === 'Easy' ? '简单' : recipe.difficulty === 'Medium' ? '中等' : '困难'}
                       </span>
                    </div>
                    <p className="text-gray-500 text-sm line-clamp-2 mb-3 flex-1">
                      {recipe.description || recipe.instructions[0]}
                    </p>
                    <div className="text-xs text-gray-400 mt-auto pt-2 border-t">
                       烹饪时间: {recipe.cookingTime}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        );

      case 'ADD_RECIPE':
        const addCategory = categories.find(c => c.id === viewState.categoryId);
        return (
          <RecipeForm
            categoryId={viewState.categoryId}
            categoryName={addCategory?.name || ''}
            onSave={handleSaveRecipe}
            onCancel={() => setViewState({ type: 'CATEGORY', categoryId: viewState.categoryId })}
          />
        );

      case 'EDIT_RECIPE':
        const editRecipe = recipes.find(r => r.id === viewState.recipeId);
        if (!editRecipe) return <div>Recipe not found</div>;
        const editCategory = categories.find(c => c.id === editRecipe.categoryId);

        return (
          <RecipeForm
            categoryId={editRecipe.categoryId}
            categoryName={editCategory?.name || ''}
            initialData={editRecipe}
            onSave={handleSaveRecipe}
            onCancel={() => setViewState({ type: 'RECIPE_DETAIL', recipeId: editRecipe.id })}
          />
        );

      case 'RECIPE_DETAIL':
        const recipe = recipes.find(r => r.id === viewState.recipeId);
        if (!recipe) return <div>Recipe not found</div>;
        return (
          <RecipeDetail
            recipe={recipe}
            onBack={() => setViewState({ type: 'CATEGORY', categoryId: recipe.categoryId })}
            onEdit={() => setViewState({ type: 'EDIT_RECIPE', recipeId: recipe.id })}
            onDelete={() => handleDeleteRecipe(recipe.id, recipe.categoryId)}
          />
        );

      default:
        return <div>Unknown view</div>;
    }
  };

  return (
    <Layout onHomeClick={() => navigateToHome()}>
      {renderContent()}
    </Layout>
  );
}

export enum CategoryIdEnum {
  MEAT = 'meat',
  VEGETABLE = 'vegetable',
  SOUP = 'soup',
  STAPLE = 'staple',
  SNACK = 'snack',
  DESSERT = 'dessert',
  DRINK = 'drink',
  HEALTH = 'health'
}

export type CategoryId = string;

export interface Category {
  id: CategoryId;
  name: string;
  icon: string;
  color: string;
  description: string;
}

export interface Recipe {
  id: string;
  categoryId: CategoryId;
  name: string;
  description: string;
  ingredients: string[];
  instructions: string[];
  cookingTime: string;
  difficulty: 'Easy' | 'Medium' | 'Hard';
  createdAt: number;
  views?: number; // Track popularity
}

export type ViewState = 
  | { type: 'HOME' }
  | { type: 'CATEGORY'; categoryId: CategoryId }
  | { type: 'RECIPE_DETAIL'; recipeId: string }
  | { type: 'ADD_RECIPE'; categoryId: CategoryId }
  | { type: 'EDIT_RECIPE'; recipeId: string }
  | { type: 'ADD_CATEGORY' };

import { GoogleGenAI, Type } from "@google/genai";
import { Recipe } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// Define the schema for a structured recipe response
const recipeSchema = {
  type: Type.OBJECT,
  properties: {
    name: { type: Type.STRING, description: "The name of the dish in Chinese." },
    description: { type: Type.STRING, description: "A short, appetizing description of the dish." },
    ingredients: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "List of ingredients with quantities (e.g., '500g 猪肉')."
    },
    instructions: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "Step-by-step cooking instructions."
    },
    cookingTime: { type: Type.STRING, description: "Total cooking time (e.g., '45分钟')." },
    difficulty: { 
      type: Type.STRING, 
      enum: ["Easy", "Medium", "Hard"],
      description: "Difficulty level."
    }
  },
  required: ["name", "description", "ingredients", "instructions", "cookingTime", "difficulty"]
};

// Schema for search results (list of recipes)
const searchResultSchema = {
  type: Type.ARRAY,
  items: recipeSchema
};

export const generateRecipeWithAI = async (dishName: string, categoryName: string): Promise<Partial<Recipe>> => {
  if (!apiKey) {
    throw new Error("API Key is missing. Please configure it in your environment.");
  }

  const prompt = `请为“${categoryName}”类别下的菜品“${dishName}”生成一份详细的食谱。请使用中文回答。`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: recipeSchema,
        systemInstruction: "You are a professional Chinese chef helper. Generate authentic and detailed recipes."
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const data = JSON.parse(text);
    return {
      name: data.name,
      description: data.description,
      ingredients: data.ingredients,
      instructions: data.instructions,
      cookingTime: data.cookingTime,
      difficulty: data.difficulty,
    };
  } catch (error) {
    console.error("AI Generation Error:", error);
    throw error;
  }
};

export const suggestRandomRecipe = async (categoryName: string): Promise<Partial<Recipe>> => {
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }

  const prompt = `请推荐一道经典的“${categoryName}”。直接生成食谱详情。`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: recipeSchema,
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text);
  } catch (error) {
    console.error("AI Suggestion Error:", error);
    throw error;
  }
};

export const searchRecipesWithAI = async (searchTerm: string): Promise<Partial<Recipe>[]> => {
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }

  const prompt = `用户想找"${searchTerm}"相关的菜谱。
  1. 如果"${searchTerm}"是一道具体的菜，请生成这道菜的食谱，并额外推荐2道相似或搭配的菜。
  2. 如果"${searchTerm}"是食材，请推荐3道使用该食材的经典菜谱。
  请直接返回3个食谱的详细JSON数组。`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: searchResultSchema,
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text);
  } catch (error) {
    console.error("AI Search Error:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { CategoryCard } from './components/CategoryCard';
import { RecipeForm } from './components/RecipeForm';
import { RecipeDetail } from './components/RecipeDetail';
import { CategoryForm } from './components/CategoryForm';
import { Category, CategoryId, Recipe, ViewState } from './types';
import { DEFAULT_CATEGORIES, getIconComponent } from './constants';
import { Plus, ArrowLeft, Loader2, Search, Pencil, Trash2, Sparkles, ChefHat } from 'lucide-react';
import { suggestRandomRecipe, generateRecipeWithAI, searchRecipesWithAI } from './services/geminiService';
import { INITIAL_RECIPES } from './seedData';

export default function App() {
  const [categories, setCategories] = useState<Category[]>([]);
  const [recipes, setRecipes] = useState<Recipe[]>([]);
  const [viewState, setViewState] = useState<ViewState>({ type: 'HOME' });
  const [searchTerm, setSearchTerm] = useState('');
  const [isSuggesting, setIsSuggesting] = useState(false);
  const [aiSearchResults, setAiSearchResults] = useState<Partial<Recipe>[]>([]);

  // Initialize Data
  useEffect(() => {
    // Load Recipes
    const savedRecipes = localStorage.getItem('smart-recipe-book-data');
    if (savedRecipes) {
      try {
        const parsed = JSON.parse(savedRecipes);
        // Migration: Add views if missing
        const migrated = parsed.map((r: any) => ({ ...r, views: r.views || 0 }));
        setRecipes(migrated);
      } catch (e) {
        console.error("Failed to load recipes", e);
        setRecipes(INITIAL_RECIPES); // Fallback if parse error
      }
    } else {
      // Load Seed Data
      setRecipes(INITIAL_RECIPES);
    }

    // Load Categories
    const savedCategories = localStorage.getItem('smart-recipe-book-categories');
    if (savedCategories) {
      try {
        setCategories(JSON.parse(savedCategories));
      } catch (e) {
        setCategories(DEFAULT_CATEGORIES);
      }
    } else {
      setCategories(DEFAULT_CATEGORIES);
    }
  }, []);

  // Persistence
  useEffect(() => {
    if (recipes.length > 0) {
      localStorage.setItem('smart-recipe-book-data', JSON.stringify(recipes));
    }
  }, [recipes]);

  useEffect(() => {
    if (categories.length > 0) {
      localStorage.setItem('smart-recipe-book-categories', JSON.stringify(categories));
    }
  }, [categories]);

  // --- Navigation Helpers ---
  const navigateToHome = () => {
    setSearchTerm('');
    setAiSearchResults([]);
    setViewState({ type: 'HOME' });
  };

  const navigateToCategory = (categoryId: CategoryId) => {
    setSearchTerm('');
    setAiSearchResults([]);
    setViewState({ type: 'CATEGORY', categoryId });
  };

  const navigateToRecipe = (recipe: Recipe) => {
    // Increment view count
    const updatedRecipes = recipes.map(r => 
      r.id === recipe.id ? { ...r, views: (r.views || 0) + 1 } : r
    );
    setRecipes(updatedRecipes);
    setViewState({ type: 'RECIPE_DETAIL', recipeId: recipe.id });
  };

  // --- Dynamic Descriptions ---
  const getCategoryDescription = (category: Category) => {
    const catRecipes = recipes.filter(r => r.categoryId === category.id);
    if (catRecipes.length === 0) return category.description;

    // Sort by views desc
    const sorted = [...catRecipes].sort((a, b) => (b.views || 0) - (a.views || 0));
    const topNames = sorted.slice(0, 3).map(r => r.name).join('、');
    return `${topNames}${sorted.length > 3 ? '等...' : ''}`;
  };

  // --- Recipe Actions ---

  const handleSaveRecipe = (newRecipeData: Omit<Recipe, 'id' | 'createdAt'>) => {
    if (viewState.type === 'EDIT_RECIPE') {
      const updatedRecipes = recipes.map(r => 
        r.id === viewState.recipeId ? { ...r, ...newRecipeData } : r
      );
      setRecipes(updatedRecipes);
      setViewState({ type: 'RECIPE_DETAIL', recipeId: viewState.recipeId });
    } else {
      const newRecipe: Recipe = {
        ...newRecipeData,
        id: crypto.randomUUID(),
        createdAt: Date.now(),
        views: 0
      };
      setRecipes(prev => [...prev, newRecipe]);
      // If we are in global search mode (HOME + searchTerm), stay there or go to detail?
      // Usually go to category.
      navigateToCategory(newRecipeData.categoryId);
    }
  };

  const handleAddAiRecipe = (aiRecipe: Partial<Recipe>) => {
    if (!aiRecipe.name) return;

    // Auto-detect category or default to 'Meat' if unknown
    // A simple heuristic or user choice could work. For now, defaulting to MEAT or first available.
    // Better: Ask user or just save to 'Uncategorized' if we had one. 
    // Let's default to the first category (MEAT) for now, user can edit later.
    // Or try to match keywords. 
    let targetCatId = categories[0].id;

    const newRecipe: Recipe = {
      id: crypto.randomUUID(),
      categoryId: targetCatId,
      name: aiRecipe.name,
      description: aiRecipe.description || '',
      ingredients: aiRecipe.ingredients || [],
      instructions: aiRecipe.instructions || [],
      cookingTime: aiRecipe.cookingTime || '30 mins',
      difficulty: (aiRecipe.difficulty as any) || 'Medium',
      createdAt: Date.now(),
      views: 0
    };
    setRecipes(prev => [...prev, newRecipe]);
    navigateToRecipe(newRecipe);
  };

  const handleDeleteRecipe = (recipeId: string, categoryId: CategoryId) => {
    if (window.confirm('确定要删除这道菜谱吗？')) {
      setRecipes(prev => prev.filter(r => r.id !== recipeId));
      // Return to category or home depending on where we came from
      setViewState({ type: 'CATEGORY', categoryId });
    }
  };

  const handleSuggestRecipe = async (categoryId: CategoryId, categoryName: string) => {
    const userDishName = window.prompt("您想吃什么？\n输入菜名，AI为您生成食谱。\n如果不输入直接点击确认，AI将为您随机推荐一道菜。");
    if (userDishName === null) return;

    setIsSuggesting(true);
    try {
      let suggestion: Partial<Recipe>;
      if (userDishName.trim()) {
        suggestion = await generateRecipeWithAI(userDishName, categoryName);
      } else {
        suggestion = await suggestRandomRecipe(categoryName);
      }

      if (suggestion && suggestion.name) {
        const newRecipe: Recipe = {
          id: crypto.randomUUID(),
          categoryId,
          name: suggestion.name,
          description: suggestion.description || '',
          ingredients: suggestion.ingredients || [],
          instructions: suggestion.instructions || [],
          cookingTime: suggestion.cookingTime || '30 mins',
          difficulty: (suggestion.difficulty as any) || 'Medium',
          createdAt: Date.now(),
          views: 0
        };
        setRecipes(prev => [...prev, newRecipe]);
      }
    } catch (e) {
      alert("生成失败，请检查网络或API Key");
    } finally {
      setIsSuggesting(false);
    }
  };

  const handleGlobalAiSearch = async () => {
    if (!searchTerm.trim()) return;
    setIsSuggesting(true);
    try {
      const results = await searchRecipesWithAI(searchTerm);
      setAiSearchResults(results);
    } catch (e) {
      alert("AI 搜索失败，请重试");
    } finally {
      setIsSuggesting(false);
    }
  };

  // --- Category Actions ---

  const handleSaveCategory = (categoryData: Omit<Category, 'id'>) => {
    const newCategory: Category = {
      ...categoryData,
      id: `custom-${crypto.randomUUID()}`,
    };
    setCategories(prev => [...prev, newCategory]);
    navigateToHome();
  };

  const handleEditCategory = (e: React.MouseEvent, category: Category) => {
    e.stopPropagation();
    const newName = window.prompt("修改分类名称", category.name);
    if (newName && newName.trim() !== '') {
       setCategories(prev => prev.map(c => c.id === category.id ? { ...c, name: newName } : c));
    }
  };

  const handleDeleteCategory = (e: React.MouseEvent, categoryId: CategoryId) => {
    e.stopPropagation();
    const count = recipes.filter(r => r.categoryId === categoryId).length;
    if (window.confirm(`确定要删除此分类吗？\n这将同时删除该分类下的 ${count} 道食谱！`)) {
      setRecipes(prev => prev.filter(r => r.categoryId !== categoryId));
      setCategories(prev => prev.filter(c => c.id !== categoryId));
    }
  };


  const renderContent = () => {
    switch (viewState.type) {
      case 'HOME':
        // Global Search Logic
        const isSearching = searchTerm.trim().length > 0;

        const localSearchResults = isSearching ? recipes.filter(r => {
           const term = searchTerm.toLowerCase();
           return (
             r.name.toLowerCase().includes(term) ||
             r.ingredients.some(ing => ing.toLowerCase().includes(term))
           );
        }) : [];

        // If not searching, show categories
        if (!isSearching) {
          const filteredCategories = categories.filter(c => 
            c.name.includes(searchTerm) || c.description.includes(searchTerm)
          );

          return (
            <div className="p-4 sm:p-6">
              <div className="mb-6 relative">
                 <input 
                   type="text" 
                   placeholder="输入菜名或食材（如：油菜、鸡翅）..." 
                   value={searchTerm}
                   onChange={e => setSearchTerm(e.target.value)}
                   className="w-full pl-10 pr-4 py-3 rounded-xl border-gray-200 shadow-sm focus:ring-2 focus:ring-orange-500 focus:border-transparent transition-all outline-none"
                 />
                 <Search className="absolute left-3 top-3.5 text-gray-400 w-5 h-5" />
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                {filteredCategories.map(category => (
                  <CategoryCard
                    key={category.id}
                    category={{...category, description: getCategoryDescription(category)}}
                    count={recipes.filter(r => r.categoryId === category.id).length}
                    onClick={() => navigateToCategory(category.id)}
                  />
                ))}

                <button 
                   onClick={() => setViewState({ type: 'ADD_CATEGORY' })}
                   className="flex flex-col items-center justify-center p-6 rounded-2xl bg-white border-2 border-dashed border-gray-300 hover:border-orange-500 hover:bg-orange-50 transition-all min-h-[160px] group"
                >
                  <div className="p-3 rounded-full bg-gray-100 group-hover:bg-orange-100 mb-3 transition-colors">
                    <Plus className="w-8 h-8 text-gray-400 group-hover:text-orange-500" />
                  </div>
                  <h3 className="text-lg font-bold text-gray-600 group-hover:text-orange-600">更多</h3>
                  <p className="text-sm text-gray-400">添加自定义分类</p>
                </button>
              </div>
            </div>
          );
        }

        // Search Results View
        return (
          <div className="p-4 sm:p-6">
            <div className="mb-6 relative flex gap-2">
               <div className="relative flex-1">
                 <input 
                   type="text" 
                   placeholder="输入菜名或食材..." 
                   value={searchTerm}
                   onChange={e => {
                     setSearchTerm(e.target.value);
                     if (e.target.value === '') {
                       setAiSearchResults([]); // Clear AI results on clear
                     }
                   }}
                   className="w-full pl-10 pr-4 py-3 rounded-xl border-gray-200 shadow-sm focus:ring-2 focus:ring-orange-500 focus:border-transparent transition-all outline-none"
                 />
                 <Search className="absolute left-3 top-3.5 text-gray-400 w-5 h-5" />
               </div>
               <button onClick={navigateToHome} className="text-gray-500 px-2 hover:text-gray-800">取消</button>
            </div>

            <h2 className="text-lg font-bold text-gray-800 mb-4 flex items-center">
              <Search className="w-5 h-5 mr-2 text-orange-500" />
              本地搜索结果 ({localSearchResults.length})
            </h2>

            {localSearchResults.length > 0 ? (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
                {localSearchResults.map(recipe => (
                  <div 
                    key={recipe.id}
                    onClick={() => navigateToRecipe(recipe)}
                    className="bg-white p-4 rounded-xl shadow-sm hover:shadow-md transition-all cursor-pointer border border-gray-100"
                  >
                     <h3 className="font-bold text-gray-800">{recipe.name}</h3>
                     <p className="text-sm text-gray-500 line-clamp-1">{recipe.description}</p>
                     <div className="flex gap-2 mt-2 text-xs text-gray-400">
                        <span>{recipe.cookingTime}</span>
                        <span>{categories.find(c => c.id === recipe.categoryId)?.name || '未知分类'}</span>
                     </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="text-center py-8 text-gray-500 bg-white rounded-xl border border-dashed border-gray-200 mb-8">
                本地食谱中未找到相关内容
              </div>
            )}

            {/* AI Search Section */}
            <div className="border-t pt-8">
              <h2 className="text-lg font-bold text-gray-800 mb-4 flex items-center">
                <Sparkles className="w-5 h-5 mr-2 text-indigo-500" />
                AI 智能推荐
              </h2>

              {aiSearchResults.length === 0 ? (
                <div className="bg-indigo-50 rounded-xl p-6 text-center">
                  <p className="text-indigo-800 mb-3 font-medium">
                    {localSearchResults.length === 0 
                      ? `没找到"${searchTerm}"？让 AI 帮您生成菜谱或推荐相似菜品。`
                      : `想看看更多关于"${searchTerm}"的做法？`
                    }
                  </p>
                  <button
                    onClick={handleGlobalAiSearch}
                    disabled={isSuggesting}
                    className="inline-flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors shadow-md disabled:opacity-50"
                  >
                    {isSuggesting ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <ChefHat className="w-4 h-4 mr-2" />}
                    AI 搜索 / 生成 "{searchTerm}"
                  </button>
                </div>
              ) : (
                <div className="space-y-4">
                   <p className="text-sm text-gray-500">点击下方卡片即可查看详情并添加到食谱本：</p>
                   <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                     {aiSearchResults.map((aiRecipe, idx) => (
                       <div 
                         key={idx}
                         onClick={() => handleAddAiRecipe(aiRecipe)}
                         className="group bg-white p-4 rounded-xl shadow-sm hover:shadow-md hover:border-indigo-200 transition-all cursor-pointer border border-indigo-100 relative overflow-hidden"
                       >
                         <div className="absolute top-0 right-0 bg-indigo-500 text-white text-xs px-2 py-1 rounded-bl-lg">AI 推荐</div>
                         <h3 className="font-bold text-gray-800">{aiRecipe.name}</h3>
                         <p className="text-sm text-gray-500 line-clamp-2 mt-1">{aiRecipe.description}</p>
                         <div className="mt-3 flex items-center text-indigo-600 text-xs font-medium opacity-0 group-hover:opacity-100 transition-opacity">
                           <Plus className="w-3 h-3 mr-1" />
                           添加到我的食谱
                         </div>
                       </div>
                     ))}
                   </div>
                   <button 
                     onClick={() => setAiSearchResults([])}
                     className="text-sm text-gray-400 hover:text-gray-600 mt-2 underline"
                   >
                     清空推荐
                   </button>
                </div>
              )}
            </div>
          </div>
        );

      case 'ADD_CATEGORY':
        return (
          <CategoryForm 
            onSave={handleSaveCategory}
            onCancel={() => navigateToHome()}
          />
        );

      case 'CATEGORY':
        const category = categories.find(c => c.id === viewState.categoryId);
        if (!category) return <div>Category not found</div>;

        const filteredRecipes = recipes.filter(r => {
           if (r.categoryId !== category.id) return false;
           const term = searchTerm.toLowerCase();
           return (
             r.name.toLowerCase().includes(term) ||
             r.description.toLowerCase().includes(term) ||
             r.ingredients.some(ing => ing.toLowerCase().includes(term))
           );
        });

        return (
          <div className="p-4 sm:p-6 min-h-screen">
            <div className="flex items-center justify-between mb-6">
              <button 
                onClick={() => navigateToHome()}
                className="flex items-center text-gray-600 hover:text-orange-600 transition-colors"
              >
                <ArrowLeft className="w-5 h-5 mr-1" />
                <span className="font-medium">返回</span>
              </button>

              <div className="flex gap-2">
                <button
                  onClick={() => setViewState({ type: 'ADD_RECIPE', categoryId: category.id })}
                  className="flex items-center px-3 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 transition-colors shadow-md text-sm font-medium"
                >
                  <Plus className="w-4 h-4 mr-2" />
                  添加食谱
                </button>
              </div>
            </div>

            <div className="flex items-center gap-3 mb-6">
               <div className={`p-3 rounded-full ${category.color} bg-opacity-20`}>
                 {getIconComponent(category.icon, "w-8 h-8")}
               </div>
               <div>
                 <h2 className="text-2xl font-bold text-gray-800">{category.name}</h2>
                 <p className="text-gray-500 text-sm">{getCategoryDescription(category)}</p>
               </div>
            </div>

            {/* Recipe Search Bar */}
            <div className="mb-6 relative">
               <input 
                 type="text" 
                 placeholder={`在 ${category.name} 中搜索食谱...`}
                 value={searchTerm}
                 onChange={e => setSearchTerm(e.target.value)}
                 className="w-full pl-10 pr-4 py-3 rounded-xl border-gray-200 shadow-sm focus:ring-2 focus:ring-orange-500 focus:border-transparent transition-all outline-none"
               />
               <Search className="absolute left-3 top-3.5 text-gray-400 w-5 h-5" />
            </div>

            {filteredRecipes.length === 0 ? (
              <div className="text-center py-20 bg-white rounded-xl border border-dashed border-gray-300">
                {searchTerm ? (
                  <>
                    <div className="mx-auto w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mb-4">
                      <Search className="w-8 h-8 text-gray-400" />
                    </div>
                    <h3 className="text-lg font-medium text-gray-900">未找到相关食谱</h3>
                    <p className="mt-1 text-gray-500">换个关键词试试？</p>
                  </>
                ) : (
                  <>
                    <div className="mx-auto w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mb-4">
                      <Plus className="w-8 h-8 text-gray-400" />
                    </div>
                    <h3 className="text-lg font-medium text-gray-900">暂无食谱</h3>
                    <p className="mt-1 text-gray-500">点击右上角添加您的第一道{category.name}！</p>
                  </>
                )}
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {filteredRecipes.map(recipe => (
                  <div 
                    key={recipe.id}
                    onClick={() => navigateToRecipe(recipe)}
                    className="group bg-white p-4 rounded-xl shadow-sm hover:shadow-md transition-all cursor-pointer border border-gray-100 flex flex-col relative"
                  >
                    {/* Recipe Action Buttons on List View */}
                    <div className="absolute top-2 right-2 flex space-x-1 opacity-0 group-hover:opacity-100 transition-opacity z-10 bg-white/80 rounded-full p-1 shadow-sm backdrop-blur-sm">
                      <button
                        onClick={(e) => { e.stopPropagation(); setViewState({ type: 'EDIT_RECIPE', recipeId: recipe.id }); }}
                        className="p-1.5 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-full"
                        title="编辑"
                      >
                        <Pencil className="w-3.5 h-3.5" />
                      </button>
                      <button
                        onClick={(e) => { e.stopPropagation(); handleDeleteRecipe(recipe.id, category.id); }}
                        className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-full"
                        title="删除"
                      >
                        <Trash2 className="w-3.5 h-3.5" />
                      </button>
                    </div>

                    <div className="flex justify-between items-start mb-2 mt-1">
                       <h3 className="font-bold text-lg text-gray-800 truncate pr-2">{recipe.name}</h3>
                       <span className={`text-xs px-2 py-1 rounded-full whitespace-nowrap ${
                         recipe.difficulty === 'Easy' ? 'bg-green-100 text-green-700' :
                         recipe.difficulty === 'Medium' ? 'bg-yellow-100 text-yellow-700' :
                         'bg-red-100 text-red-700'
                       }`}>
                         {recipe.difficulty === 'Easy' ? '简单' : recipe.difficulty === 'Medium' ? '中等' : '困难'}
                       </span>
                    </div>
                    <p className="text-gray-500 text-sm line-clamp-2 mb-3 flex-1">
                      {recipe.description || recipe.instructions[0]}
                    </p>
                    <div className="text-xs text-gray-400 mt-auto pt-2 border-t flex justify-between">
                       <span>烹饪时间: {recipe.cookingTime}</span>
                       <span className="text-gray-300">👁 {recipe.views || 0}</span>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        );

      case 'ADD_RECIPE':
        const addCategory = categories.find(c => c.id === viewState.categoryId);
        return (
          <RecipeForm
            categoryId={viewState.categoryId}
            categoryName={addCategory?.name || ''}
            onSave={handleSaveRecipe}
            onCancel={() => setViewState({ type: 'CATEGORY', categoryId: viewState.categoryId })}
          />
        );

      case 'EDIT_RECIPE':
        const editRecipe = recipes.find(r => r.id === viewState.recipeId);
        if (!editRecipe) return <div>Recipe not found</div>;
        const editCategory = categories.find(c => c.id === editRecipe.categoryId);

        return (
          <RecipeForm
            categoryId={editRecipe.categoryId}
            categoryName={editCategory?.name || ''}
            initialData={editRecipe}
            onSave={handleSaveRecipe}
            onCancel={() => setViewState({ type: 'RECIPE_DETAIL', recipeId: editRecipe.id })}
          />
        );

      case 'RECIPE_DETAIL':
        const recipe = recipes.find(r => r.id === viewState.recipeId);
        if (!recipe) return <div>Recipe not found</div>;
        return (
          <RecipeDetail
            recipe={recipe}
            onBack={() => setViewState({ type: 'CATEGORY', categoryId: recipe.categoryId })}
            onEdit={() => setViewState({ type: 'EDIT_RECIPE', recipeId: recipe.id })}
            onDelete={() => handleDeleteRecipe(recipe.id, recipe.categoryId)}
          />
        );

      default:
        return <div>Unknown view</div>;
    }
  };

  return (
    <Layout onHomeClick={() => navigateToHome()}>
      {renderContent()}
    </Layout>
  );
}

