                  <>
                    <div className="mx-auto w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mb-4">
                      <Plus className="w-8 h-8 text-gray-400" />
                    </div>
                    <h3 className="text-lg font-medium text-gray-900">暂无食谱</h3>
                    <p className="mt-1 text-gray-500 mb-4">您可以手动添加，或使用“灵感菜单”获取推荐。</p>
                    <button 
                      onClick={() => setIsRecModalOpen(true)}
                      className="inline-flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 shadow-md text-sm font-medium"
                    >
                      <Sparkles className="w-4 h-4 mr-2" />
                      打开灵感菜单
                    </button>
                  </>
                )}
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {sortedRecipes.map(recipe => (
                  <div 
                    key={recipe.id}
                    onClick={() => navigateToRecipe(recipe)}
                    className={`group bg-white p-4 rounded-xl shadow-sm hover:shadow-md transition-all cursor-pointer border relative ${recipe.isFavorite ? 'border-yellow-200 bg-yellow-50/30' : 'border-gray-100'}`}
                  >
                    {/* Recipe Action Buttons on List View */}
                    <div className="absolute top-2 right-2 flex space-x-1 opacity-0 group-hover:opacity-100 transition-opacity z-10 bg-white/80 rounded-full p-1 shadow-sm backdrop-blur-sm">
                      <button
                        onClick={(e) => { e.stopPropagation(); setViewState({ type: 'EDIT_RECIPE', recipeId: recipe.id }); }}
                        className="p-1.5 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-full"
                        title="编辑"
                      >
                        <Pencil className="w-3.5 h-3.5" />
                      </button>
                      <button
                        onClick={(e) => { e.stopPropagation(); handleDeleteRecipe(recipe.id, category.id); }}
                        className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-full"
                        title="删除"
                      >
                        <Trash2 className="w-3.5 h-3.5" />
                      </button>
                    </div>

                    <div className="flex gap-4">
                      <div className="flex-1 min-w-0">
                        <div className="flex justify-between items-start mb-2 mt-1">
                           <div className="flex items-center gap-1.5 truncate pr-2">
                             <h3 className="font-bold text-lg text-gray-800 truncate">{recipe.name}</h3>
                             {recipe.isFavorite && (
                               <Star className="w-4 h-4 text-yellow-400 fill-current flex-shrink-0" />
                             )}
                           </div>
                           <span className={`text-xs px-2 py-1 rounded-full whitespace-nowrap flex-shrink-0 ${
                             recipe.difficulty === 'Easy' ? 'bg-green-100 text-green-700' :
                             recipe.difficulty === 'Medium' ? 'bg-yellow-100 text-yellow-700' :
                             'bg-red-100 text-red-700'
                           }`}>
                             {recipe.difficulty === 'Easy' ? '简单' : recipe.difficulty === 'Medium' ? '中等' : '困难'}
                           </span>
                        </div>
                        <p className="text-gray-500 text-sm line-clamp-2 mb-3">
                          {recipe.description || recipe.instructions[0]}
                        </p>
                        <div className="text-xs text-gray-400 flex items-center gap-3">
                           <span>{recipe.cookingTime}</span>
                           <div className="flex items-center gap-2">
                             <span className="flex items-center"><Eye className="w-3 h-3 mr-1"/> {recipe.views || 0}</span>
                           </div>
                        </div>
                      </div>

                      {recipe.image && (
                         <div className="w-20 h-20 sm:w-24 sm:h-24 flex-shrink-0 rounded-lg overflow-hidden bg-gray-100 border border-gray-200">
                           <img src={recipe.image} alt={recipe.name} className="w-full h-full object-cover" />
                         </div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            )}

            {/* Recommendation Modal */}
            {isRecModalOpen && (
              <RecommendationModal 
                categoryName={category.name}
                existingRecipes={recipes.filter(r => r.categoryId === category.id)}
                onClose={() => setIsRecModalOpen(false)}
                onAddRecipe={(name) => handleQuickAddRecipe(name, category.id, category.name)}
              />
            )}
          </div>
        );

      case 'ADD_RECIPE':
        const addCategory = categories.find(c => c.id === viewState.categoryId);
        return (
          <RecipeForm
            categoryId={viewState.categoryId}
            categoryName={addCategory?.name || ''}
            onSave={handleSaveRecipe}
            onCancel={() => setViewState({ type: 'CATEGORY', categoryId: viewState.categoryId })}
          />
        );

      case 'EDIT_RECIPE':
        const editRecipe = recipes.find(r => r.id === viewState.recipeId);
        if (!editRecipe) return <div>Recipe not found</div>;
        const editCategory = categories.find(c => c.id === editRecipe.categoryId);

        return (
          <RecipeForm
            categoryId={editRecipe.categoryId}
            categoryName={editCategory?.name || ''}
            initialData={editRecipe}
            onSave={handleSaveRecipe}
            onCancel={() => setViewState({ type: 'RECIPE_DETAIL', recipeId: editRecipe.id })}
          />
        );

      case 'RECIPE_DETAIL':
        const recipe = recipes.find(r => r.id === viewState.recipeId);
        if (!recipe) return <div>Recipe not found</div>;
        return (
          <RecipeDetail
            recipe={recipe}
            onBack={() => setViewState({ type: 'CATEGORY', categoryId: recipe.categoryId })}
            onEdit={() => setViewState({ type: 'EDIT_RECIPE', recipeId: recipe.id })}
            onDelete={() => handleDeleteRecipe(recipe.id, recipe.categoryId)}
            onToggleFavorite={() => handleToggleFavorite(recipe.id)}
          />
        );

      default:
        return <div>Unknown view</div>;
    }
  };

  return (
    <Layout onHomeClick={() => navigateToHome()}>
      {renderContent()}
    </Layout>
  );
}

import React, { useState } from 'react';
import { Recipe } from '../types';
import { Clock, BarChart, ArrowLeft, Pencil, Trash2, Eye, Star } from 'lucide-react';

interface RecipeDetailProps {
  recipe: Recipe;
  onBack: () => void;
  onEdit?: () => void;
  onDelete?: () => void;
  onToggleFavorite: () => void;
}

export const RecipeDetail: React.FC<RecipeDetailProps> = ({ recipe, onBack, onEdit, onDelete, onToggleFavorite }) => {
  const [isAnimating, setIsAnimating] = useState(false);

  const handleDelete = () => {
    if (onDelete) {
       onDelete();
    }
  };

  const handleFavoriteClick = () => {
    onToggleFavorite();
    setIsAnimating(true);
    setTimeout(() => setIsAnimating(false), 300);
  };

  return (
    <div className="bg-white min-h-full pb-8">
      {/* Header Image Area */}
      <div className="h-48 sm:h-72 w-full bg-gray-100 flex items-center justify-center relative overflow-hidden group">

        {recipe.image ? (
          <img src={recipe.image} alt={recipe.name} className="w-full h-full object-cover" />
        ) : (
          <div className="w-full h-full bg-gradient-to-r from-orange-100 to-yellow-100 flex items-center justify-center">
             <span className="text-6xl opacity-20 select-none">🍲</span>
          </div>
        )}

        {/* Action Buttons */}
        <button 
          onClick={onBack}
          className="absolute top-4 left-4 bg-white/90 backdrop-blur-sm p-2 rounded-full hover:bg-white shadow-md transition-all z-20"
        >
          <ArrowLeft className="w-6 h-6 text-gray-700" />
        </button>

        <div className="absolute top-4 right-4 flex gap-2 z-20">
          {onEdit && (
            <button 
              onClick={onEdit}
              className="bg-white/90 backdrop-blur-sm p-2 rounded-full hover:bg-blue-50 hover:text-blue-600 shadow-md transition-all"
              title="编辑食谱"
            >
              <Pencil className="w-5 h-5" />
            </button>
          )}
          {onDelete && (
            <button 
              onClick={handleDelete}
              className="bg-white/90 backdrop-blur-sm p-2 rounded-full hover:bg-red-50 hover:text-red-600 shadow-md transition-all"
              title="删除食谱"
            >
              <Trash2 className="w-5 h-5" />
            </button>
          )}
        </div>

        {/* Title Overlay */}
        <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-black/70 via-black/30 to-transparent text-white pt-16">
             <h1 className="text-3xl font-bold drop-shadow-lg tracking-wide">{recipe.name}</h1>
        </div>
      </div>

      <div className="max-w-4xl mx-auto px-4 sm:px-6 -mt-6 relative z-10">
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6">

          <div className="flex flex-wrap gap-4 text-sm text-gray-600 mb-6 pb-6 border-b items-center">
            <div className="flex items-center gap-1 bg-gray-50 px-3 py-1 rounded-full border border-gray-100">
              <Clock className="w-4 h-4 text-orange-500" />
              <span>{recipe.cookingTime || '未知时间'}</span>
            </div>
            <div className="flex items-center gap-1 bg-gray-50 px-3 py-1 rounded-full border border-gray-100">
              <BarChart className="w-4 h-4 text-orange-500" />
              <span>难度: {recipe.difficulty === 'Easy' ? '简单' : recipe.difficulty === 'Medium' ? '中等' : '困难'}</span>
            </div>

            <div className="ml-auto flex items-center gap-3">
               <button 
                 onClick={handleFavoriteClick}
                 className={`flex items-center gap-1 px-3 py-1 rounded-full border transition-all ${
                   recipe.isFavorite 
                     ? 'bg-yellow-50 border-yellow-200 text-yellow-600 hover:bg-yellow-100' 
                     : 'bg-gray-50 border-gray-100 hover:bg-gray-100'
                 } ${isAnimating ? 'scale-110' : ''}`}
               >
                 <Star className={`w-4 h-4 ${recipe.isFavorite ? 'fill-current text-yellow-500' : 'text-gray-400'}`} />
                 <span className={`${recipe.isFavorite ? 'font-medium' : 'text-gray-500'}`}>
                   {recipe.isFavorite ? '已收藏' : '收藏'}
                 </span>
               </button>
               <div className="flex items-center gap-1 bg-gray-50 px-3 py-1 rounded-full border border-gray-100">
                 <Eye className="w-4 h-4 text-gray-400" />
                 <span className="text-gray-400">{recipe.views || 0}</span>
               </div>
            </div>
          </div>

          <div className="mb-8">
             <p className="text-gray-600 leading-relaxed italic border-l-4 border-orange-200 pl-4 bg-orange-50/50 py-2 rounded-r-lg">
               {recipe.description || '暂无简介，快去点击编辑添加吧！'}
             </p>
          </div>

          <div className="grid md:grid-cols-3 gap-8">
            <div className="md:col-span-1">
              <h3 className="text-lg font-bold text-gray-800 mb-4 flex items-center">
                <span className="w-1.5 h-6 bg-orange-500 mr-2 rounded-full"></span>
                食材清单
              </h3>
              <ul className="space-y-3">
                {recipe.ingredients.map((ing, idx) => (
                  <li key={idx} className="flex items-start text-gray-700 border-b border-dashed border-gray-100 pb-2 last:border-0 hover:bg-gray-50 transition-colors rounded px-2 -mx-2">
                    <span className="w-2 h-2 mt-2 bg-orange-300 rounded-full mr-2 flex-shrink-0"></span>
                    <span>{ing}</span>
                  </li>
                ))}
              </ul>
            </div>

            <div className="md:col-span-2">
              <h3 className="text-lg font-bold text-gray-800 mb-4 flex items-center">
                <span className="w-1.5 h-6 bg-orange-500 mr-2 rounded-full"></span>
                制作步骤
              </h3>
              <div className="space-y-6">
                {recipe.instructions.map((step, idx) => (
                  <div key={idx} className="flex gap-4 group">
                    <div className="flex-shrink-0 w-8 h-8 bg-orange-100 text-orange-600 rounded-full flex items-center justify-center font-bold text-sm group-hover:bg-orange-500 group-hover:text-white transition-colors shadow-sm">
                      {idx + 1}
                    </div>
                    <div className="pt-1">
                      <p className="text-gray-700 leading-relaxed">{step}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export enum CategoryIdEnum {
  MEAT = 'meat',
  VEGETABLE = 'vegetable',
  SOUP = 'soup',
  STAPLE = 'staple',
  SNACK = 'snack',
  DESSERT = 'dessert',
  DRINK = 'drink',
  HEALTH = 'health'
}

export type CategoryId = string;

export interface Category {
  id: CategoryId;
  name: string;
  icon: string;
  color: string;
  description: string;
}

export interface UserPreferences {
  spiciness: 'No Spicy' | 'Mild' | 'Medium' | 'Hot' | 'Crazy';
  dietaryRestrictions: string; // e.g. "No Cilantro, No Peanuts"
  favoriteFlavors: string; // e.g. "Sweet and Sour, Garlic"
}

export interface User {
  phoneNumber: string;
  name: string;
  avatar?: string;
  preferences: UserPreferences;
  createdAt: number;
}

export interface Recipe {
  id: string;
  categoryId: CategoryId;
  name: string;
  description: string;
  ingredients: string[];
  instructions: string[];
  cookingTime: string;
  difficulty: 'Easy' | 'Medium' | 'Hard';
  image?: string; // Base64 Data URL for the dish photo
  createdAt: number;
  views?: number; // Track popularity
  isFavorite?: boolean; // Track if favorited/collected
}

export type ViewState = 
  | { type: 'HOME' }
  | { type: 'CATEGORY'; categoryId: CategoryId }
  | { type: 'RECIPE_DETAIL'; recipeId: string }
  | { type: 'ADD_RECIPE'; categoryId: CategoryId }
  | { type: 'EDIT_RECIPE'; recipeId: string }
  | { type: 'ADD_CATEGORY' };

import { GoogleGenAI, Type } from "@google/genai";
import { Recipe, UserPreferences } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// Define the schema for a structured recipe response
const recipeSchema = {
  type: Type.OBJECT,
  properties: {
    name: { type: Type.STRING, description: "The name of the dish in Chinese." },
    description: { type: Type.STRING, description: "A short, appetizing description of the dish." },
    ingredients: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "List of ingredients with quantities (e.g., '500g 猪肉')."
    },
    instructions: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "Step-by-step cooking instructions."
    },
    cookingTime: { type: Type.STRING, description: "Total cooking time (e.g., '45分钟')." },
    difficulty: { 
      type: Type.STRING, 
      enum: ["Easy", "Medium", "Hard"],
      description: "Difficulty level."
    }
  },
  required: ["name", "description", "ingredients", "instructions", "cookingTime", "difficulty"]
};

// Schema for search results (list of recipes)
const searchResultSchema = {
  type: Type.ARRAY,
  items: recipeSchema
};

// Schema for simple list of dish names
const dishListSchema = {
  type: Type.OBJECT,
  properties: {
    dishes: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "A list of 15 classic or popular dish names."
    }
  }
};

const formatPreferences = (prefs?: UserPreferences) => {
  if (!prefs) return "";
  let context = "User Preferences (Please adapt the recipe if possible): ";
  if (prefs.spiciness) context += `Spiciness Level: ${prefs.spiciness}. `;
  if (prefs.dietaryRestrictions) context += `Dietary Restrictions (Avoid these): ${prefs.dietaryRestrictions}. `;
  if (prefs.favoriteFlavors) context += `Preferred Flavors: ${prefs.favoriteFlavors}. `;
  return context;
};

export const generateRecipeWithAI = async (dishName: string, categoryName: string, prefs?: UserPreferences): Promise<Partial<Recipe>> => {
  if (!apiKey) {
    throw new Error("API Key is missing. Please configure it in your environment.");
  }

  const prefContext = formatPreferences(prefs);
  const prompt = `请为“${categoryName}”类别下的菜品“${dishName}”生成一份详细的食谱。请使用中文回答。${prefContext}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: recipeSchema,
        systemInstruction: "You are a professional Chinese chef helper. Generate authentic and detailed recipes. Pay close attention to user dietary restrictions and spiciness preferences."
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const data = JSON.parse(text);
    return {
      name: data.name,
      description: data.description,
      ingredients: data.ingredients,
      instructions: data.instructions,
      cookingTime: data.cookingTime,
      difficulty: data.difficulty,
    };
  } catch (error) {
    console.error("AI Generation Error:", error);
    throw error;
  }
};

