          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useMemo } from 'react';
import { Recipe, CategoryIdEnum } from '../types';
import { Sun, Moon, Coffee, Sunset, Sunrise, Utensils, Star, ChefHat } from 'lucide-react';

interface DailyMealRecommendationProps {
  recipes: Recipe[];
  onRecipeClick: (recipe: Recipe) => void;
  onSearchClick: (term: string) => void;
}

interface TimeConfig {
  key: string;
  title: string;
  subtitle: string;
  icon: React.ReactNode;
  bgGradient: string;
  categories: string[];
  fallbackDishes: string[];
}

export const DailyMealRecommendation: React.FC<DailyMealRecommendationProps> = ({ 
  recipes, 
  onRecipeClick, 
  onSearchClick 
}) => {
  const timeConfig = useMemo((): TimeConfig => {
    const hour = new Date().getHours();

    // 06:00 - 10:00 早餐
    if (hour >= 6 && hour < 10) {
      return {
        key: 'breakfast',
        title: '元气早餐',
        subtitle: '美好的一天从早餐开始',
        icon: <Sunrise className="w-6 h-6 text-orange-500" />,
        bgGradient: 'from-orange-50 to-yellow-50 border-orange-100',
        categories: [CategoryIdEnum.STAPLE, CategoryIdEnum.DRINK, CategoryIdEnum.SNACK],
        fallbackDishes: ['皮蛋瘦肉粥', '葱油拌面', '豆浆', '煎饼果子']
      };
    }
    // 10:00 - 15:00 午餐
    else if (hour >= 10 && hour < 15) {
      return {
        key: 'lunch',
        title: '丰盛午餐',
        subtitle: '吃饱喝足，精力充沛',
        icon: <Sun className="w-6 h-6 text-red-500" />,
        bgGradient: 'from-red-50 to-orange-50 border-red-100',
        categories: [CategoryIdEnum.MEAT, CategoryIdEnum.VEGETABLE, CategoryIdEnum.STAPLE, CategoryIdEnum.SOUP],
        fallbackDishes: ['宫保鸡丁', '番茄炒蛋', '红烧肉', '扬州炒饭']
      };
    }
    // 15:00 - 21:00 晚餐
    else if (hour >= 15 && hour < 21) {
      return {
        key: 'dinner',
        title: '温馨晚餐',
        subtitle: '犒劳辛苦一天的自己',
        icon: <Sunset className="w-6 h-6 text-indigo-500" />,
        bgGradient: 'from-indigo-50 to-purple-50 border-indigo-100',
        categories: [CategoryIdEnum.MEAT, CategoryIdEnum.VEGETABLE, CategoryIdEnum.SOUP, CategoryIdEnum.HEALTH],
        fallbackDishes: ['清蒸鲈鱼', '玉米排骨汤', '地三鲜', '白灼虾']
      };
    }
    // 21:00 - 02:00 (next day) 夜宵
    // Also handling 02:00 - 06:00 as "Early Morning" gap, grouping with Late Night or generic
    else {
      return {
        key: 'latenight',
        title: '深夜食堂',
        subtitle: '暖胃解馋，治愈时刻',
        icon: <Moon className="w-6 h-6 text-blue-500" />,
        bgGradient: 'from-slate-50 to-blue-50 border-slate-200',
        categories: [CategoryIdEnum.SNACK, CategoryIdEnum.DRINK],
        fallbackDishes: ['炸鸡翅', '烤冷面', '关东煮', '酸辣粉']
      };
    }
  }, []);

  // Filter recipes based on categories suitable for the time
  const recommendedRecipes = useMemo(() => {
    const suitable = recipes.filter(r => timeConfig.categories.includes(r.categoryId));
    // Shuffle and pick up to 3
    const shuffled = [...suitable].sort(() => 0.5 - Math.random());
    return shuffled.slice(0, 3);
  }, [recipes, timeConfig]);

  return (
    <div className={`mb-6 rounded-2xl border p-4 shadow-sm bg-gradient-to-br ${timeConfig.bgGradient}`}>
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-2">
          <div className="p-2 bg-white rounded-full shadow-sm">
            {timeConfig.icon}
          </div>
          <div>
            <h3 className="font-bold text-gray-800 text-lg">{timeConfig.title}</h3>
            <p className="text-xs text-gray-500">{timeConfig.subtitle}</p>
          </div>
        </div>
        <div className="text-xs font-medium text-gray-400 bg-white/60 px-2 py-1 rounded-lg">
          {new Date().getHours()}:00 - {(new Date().getHours() + 1) % 24}:00
        </div>
      </div>

      <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
        {/* Render Local Matches */}
        {recommendedRecipes.map(recipe => (
          <div 
            key={recipe.id}
            onClick={() => onRecipeClick(recipe)}
            className="bg-white p-3 rounded-xl shadow-sm border border-white hover:border-orange-200 cursor-pointer transition-all hover:shadow-md flex flex-col h-full"
          >
            {recipe.image ? (
              <div className="w-full h-24 rounded-lg bg-gray-100 overflow-hidden mb-2">
                 <img src={recipe.image} alt={recipe.name} className="w-full h-full object-cover" />
              </div>
            ) : (
              <div className="w-full h-24 rounded-lg bg-gray-50 flex items-center justify-center mb-2 text-2xl">
                 🥘
              </div>
            )}
            <div className="mt-auto">
              <h4 className="font-bold text-gray-800 text-sm truncate">{recipe.name}</h4>
              <div className="flex items-center gap-1 mt-1">
                 <Utensils className="w-3 h-3 text-gray-400" />
                 <span className="text-xs text-gray-500 truncate">{recipe.cookingTime}</span>
              </div>
            </div>
          </div>
        ))}

        {/* Render Fallback/AI Suggestions if less than 3 local matches */}
        {Array.from({ length: Math.max(0, 3 - recommendedRecipes.length) }).map((_, idx) => {
          const suggestion = timeConfig.fallbackDishes[idx % timeConfig.fallbackDishes.length];
          return (
            <div 
              key={`fallback-${idx}`}
              onClick={() => onSearchClick(suggestion)}
              className="bg-white/60 p-3 rounded-xl border border-dashed border-gray-300 hover:border-orange-400 hover:bg-white cursor-pointer transition-all flex flex-col items-center justify-center text-center h-full min-h-[140px]"
            >
              <div className="w-10 h-10 bg-orange-100 rounded-full flex items-center justify-center mb-2 text-orange-500">
                <ChefHat className="w-5 h-5" />
              </div>
              <h4 className="font-bold text-gray-700 text-sm">{suggestion}</h4>
              <p className="text-xs text-orange-500 mt-1 flex items-center">
                点击生成食谱
              </p>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Layout } from './components/Layout';
import { CategoryCard } from './components/CategoryCard';
import { RecipeForm } from './components/RecipeForm';
import { RecipeDetail } from './components/RecipeDetail';
import { CategoryForm } from './components/CategoryForm';
import { LoginModal } from './components/LoginModal';
import { UserProfile } from './components/UserProfile';
import { DailyMealRecommendation } from './components/DailyMealRecommendation';
import { Category, CategoryId, Recipe, ViewState, User, UserPreferences } from './types';
import { DEFAULT_CATEGORIES, getIconComponent } from './constants';
import { Plus, ArrowLeft, Loader2, Search, Pencil, Trash2, Sparkles, ChefHat, BookOpen, Eye, Star } from 'lucide-react';
import { suggestRandomRecipe, generateRecipeWithAI, searchRecipesWithAI } from './services/geminiService';
import { INITIAL_RECIPES } from './seedData';
import { SeasonalRecommendation } from './components/SeasonalRecommendation';
import { RecommendationModal } from './components/RecommendationModal';

export default function App() {
  const [categories, setCategories] = useState<Category[]>([]);
  const [recipes, setRecipes] = useState<Recipe[]>([]);
  const [viewState, setViewState] = useState<ViewState>({ type: 'HOME' });
  const [searchTerm, setSearchTerm] = useState('');
  const [isSuggesting, setIsSuggesting] = useState(false);
  const [aiSearchResults, setAiSearchResults] = useState<Partial<Recipe>[]>([]);
  const [isRecModalOpen, setIsRecModalOpen] = useState(false);

  // User State
  const [user, setUser] = useState<User | null>(null);
  const [showLogin, setShowLogin] = useState(false);
  const [showProfile, setShowProfile] = useState(false);

  // --- Data Loading Logic ---

  // Helper to get storage keys based on user
  const getStorageKeys = (currentUser: User | null) => {
    const suffix = currentUser ? `_${currentUser.phoneNumber}` : '_guest';
    return {
      recipes: `smart-recipe-book-data${suffix}`,
      categories: `smart-recipe-book-categories${suffix}`,
    };
  };

  const loadDataForUser = useCallback((currentUser: User | null) => {
    const keys = getStorageKeys(currentUser);

    // Load Recipes
    const savedRecipes = localStorage.getItem(keys.recipes);
    if (savedRecipes) {
      try {
        const parsed = JSON.parse(savedRecipes);
        const migrated = parsed.map((r: any) => ({ 
          ...r, 
          views: r.views || 0,
          isFavorite: r.isFavorite || (r.likes > 0) || false 
        }));
        setRecipes(migrated);
      } catch (e) {
        console.error("Failed to load recipes", e);
        setRecipes(INITIAL_RECIPES);
      }
    } else {
      // Always initialize with seed data for new users or guests
      setRecipes(INITIAL_RECIPES);
    }

    // Load Categories
    const savedCategories = localStorage.getItem(keys.categories);
    if (savedCategories) {
      try {
        setCategories(JSON.parse(savedCategories));
      } catch (e) {
        setCategories(DEFAULT_CATEGORIES);
      }
    } else {
      setCategories(DEFAULT_CATEGORIES);
    }
  }, []);

  // Initial Load (Check for active session)
  useEffect(() => {
    const activeUserJson = localStorage.getItem('active_user_session');
    let activeUser: User | null = null;
    if (activeUserJson) {
      try {
        activeUser = JSON.parse(activeUserJson);
        setUser(activeUser);
      } catch (e) {
        localStorage.removeItem('active_user_session');
      }
    }
    loadDataForUser(activeUser);
  }, [loadDataForUser]);

  // Persistence (Whenever data or user changes)
  useEffect(() => {
    const keys = getStorageKeys(user);
    if (recipes.length > 0 || user) { // Only save if data exists or user is logged in (to save empty state)
        localStorage.setItem(keys.recipes, JSON.stringify(recipes));
    }
  }, [recipes, user]);

  useEffect(() => {
    const keys = getStorageKeys(user);
    if (categories.length > 0) {
        localStorage.setItem(keys.categories, JSON.stringify(categories));
    }
  }, [categories, user]);

  // --- User Actions ---

  const handleLoginSuccess = (userData: User) => {
    setUser(userData);
    localStorage.setItem('active_user_session', JSON.stringify(userData));
    setShowLogin(false);

    // Switch data context
    loadDataForUser(userData);
    setViewState({ type: 'HOME' });
    setSearchTerm('');
  };

  const handleLogout = () => {
    localStorage.removeItem('active_user_session');
    setUser(null);
    setShowProfile(false);
    // Revert to guest data
    loadDataForUser(null);
    setViewState({ type: 'HOME' });
    setSearchTerm('');
  };

  const handleUpdateProfile = (name: string, prefs: UserPreferences) => {
    if (!user) return;
    const updatedUser = { ...user, name, preferences: prefs };
    setUser(updatedUser);
    localStorage.setItem('active_user_session', JSON.stringify(updatedUser));
    localStorage.setItem(`user_profile_${user.phoneNumber}`, JSON.stringify(updatedUser));
    setShowProfile(false);
  };

  // --- Navigation Helpers ---
  const navigateToHome = () => {
    setSearchTerm('');
    setAiSearchResults([]);
    setViewState({ type: 'HOME' });
    setIsRecModalOpen(false);
  };

  const navigateToCategory = (categoryId: CategoryId) => {
    setSearchTerm('');
    setAiSearchResults([]);
    setViewState({ type: 'CATEGORY', categoryId });
    setIsRecModalOpen(false);
  };

  const navigateToRecipe = (recipe: Recipe) => {
    // Increment view count
    const updatedRecipes = recipes.map(r => 
      r.id === recipe.id ? { ...r, views: (r.views || 0) + 1 } : r
    );
    setRecipes(updatedRecipes);
    setViewState({ type: 'RECIPE_DETAIL', recipeId: recipe.id });
  };

  // --- Dynamic Descriptions ---
  const getCategoryDescription = (category: Category) => {
    const catRecipes = recipes.filter(r => r.categoryId === category.id);
    if (catRecipes.length === 0) return category.description;

    // Sort by views desc
    const sorted = [...catRecipes].sort((a, b) => (b.views || 0) - (a.views || 0));
    const topNames = sorted.slice(0, 3).map(r => r.name).join('、');
    return `${topNames}${sorted.length > 3 ? '等...' : ''}`;
  };

  // --- Helper: Sort Recipes (Favorites First, Then Views) ---
  const sortRecipes = (list: Recipe[]) => {
    return [...list].sort((a, b) => {
      // 1. Favorites First
      const favA = a.isFavorite ? 1 : 0;
      const favB = b.isFavorite ? 1 : 0;
      if (favA !== favB) return favB - favA;

      // 2. Then by Views (High to Low)
      return (b.views || 0) - (a.views || 0);
    });
  };

  // --- Recipe Actions ---

  const handleSaveRecipe = (newRecipeData: Omit<Recipe, 'id' | 'createdAt'>) => {
    if (viewState.type === 'EDIT_RECIPE') {
      const updatedRecipes = recipes.map(r => 
        r.id === viewState.recipeId ? { ...r, ...newRecipeData } : r
      );
      setRecipes(updatedRecipes);
      setViewState({ type: 'RECIPE_DETAIL', recipeId: viewState.recipeId });
    } else {
      const newRecipe: Recipe = {
        ...newRecipeData,
        id: crypto.randomUUID(),
        createdAt: Date.now(),
        views: 0,
        isFavorite: false
      };
      setRecipes(prev => [...prev, newRecipe]);
      navigateToCategory(newRecipeData.categoryId);
    }
  };

  const handleToggleFavorite = (recipeId: string) => {
    setRecipes(prev => prev.map(r => {
      if (r.id === recipeId) {
        return { ...r, isFavorite: !r.isFavorite };
      }
      return r;
    }));
  };

  const handleAddAiRecipe = (aiRecipe: Partial<Recipe>) => {
    if (!aiRecipe.name) return;

    // Auto-detect category or default to 'Meat' if unknown
    let targetCatId = categories[0].id;

    const newRecipe: Recipe = {
      id: crypto.randomUUID(),
      categoryId: targetCatId,
      name: aiRecipe.name,
      description: aiRecipe.description || '',
      ingredients: aiRecipe.ingredients || [],
      instructions: aiRecipe.instructions || [],
      cookingTime: aiRecipe.cookingTime || '30 mins',
      difficulty: (aiRecipe.difficulty as any) || 'Medium',
      createdAt: Date.now(),
      views: 0,
      isFavorite: false
    };
    setRecipes(prev => [...prev, newRecipe]);
    navigateToRecipe(newRecipe);
  };

  const handleDeleteRecipe = (recipeId: string, categoryId: CategoryId) => {
    if (window.confirm('确定要删除这道菜谱吗？')) {
      setRecipes(prev => prev.filter(r => r.id !== recipeId));
      // Return to category or home depending on where we came from
      setViewState({ type: 'CATEGORY', categoryId });
    }
  };

  const handleGlobalAiSearch = async (initialTerm?: string) => {
    const term = initialTerm || searchTerm;
    if (!term.trim()) return;

    // If called with a specific term (like from daily rec), update search input
    if (initialTerm) {
        setSearchTerm(initialTerm);
    }

    setIsSuggesting(true);
    try {
      const results = await searchRecipesWithAI(term, user?.preferences);
      setAiSearchResults(results);
    } catch (e) {
      alert("AI 搜索失败，请重试");
    } finally {
      setIsSuggesting(false);
    }
  };

  // Handle Quick Add from Recommendation Modal
  const handleQuickAddRecipe = async (dishName: string, categoryId: CategoryId, categoryName: string) => {
    const aiRecipe = await generateRecipeWithAI(dishName, categoryName, user?.preferences);
    if (!aiRecipe.name) throw new Error("Failed to generate");

    const newRecipe: Recipe = {
      id: crypto.randomUUID(),
      categoryId,
      name: aiRecipe.name,
      description: aiRecipe.description || '',
      ingredients: aiRecipe.ingredients || [],
      instructions: aiRecipe.instructions || [],
      cookingTime: aiRecipe.cookingTime || '30 mins',
      difficulty: (aiRecipe.difficulty as any) || 'Medium',
      createdAt: Date.now(),
      views: 0,
      isFavorite: false
    };
    setRecipes(prev => [...prev, newRecipe]);
  };

  // --- Category Actions ---

  const handleSaveCategory = (categoryData: Omit<Category, 'id'>) => {
    const newCategory: Category = {
      ...categoryData,
      id: `custom-${crypto.randomUUID()}`,
    };
    setCategories(prev => [...prev, newCategory]);
    navigateToHome();
  };


  const renderContent = () => {
    switch (viewState.type) {
      case 'HOME':
        const isSearching = searchTerm.trim().length > 0;

        const filteredCategories = categories.filter(c => 
          c.name.includes(searchTerm) || c.description.includes(searchTerm)
        );

        let localSearchResults = isSearching ? recipes.filter(r => {
           const term = searchTerm.toLowerCase();
           return (
             r.name.toLowerCase().includes(term) ||
             r.ingredients.some(ing => ing.toLowerCase().includes(term))
           );
        }) : [];

        if (isSearching && localSearchResults.length > 0) {
            localSearchResults = sortRecipes(localSearchResults);
        }

        return (
          <div className="p-4 sm:p-6 pb-24">
            {/* Persistent Search Bar */}
            <div className="mb-6 relative flex gap-2">
               <div className="relative flex-1">
                 <input 
                   type="text" 
                   placeholder="输入菜名或食材（如：油菜、鸡翅）..." 
                   value={searchTerm}
                   onChange={e => {
                     setSearchTerm(e.target.value);
                     if (e.target.value === '') {
                       setAiSearchResults([]); 
                     }
                   }}
                   className="w-full pl-10 pr-4 py-3 rounded-xl border-gray-200 shadow-sm focus:ring-2 focus:ring-orange-500 focus:border-transparent transition-all outline-none"
                 />
                 <Search className="absolute left-3 top-3.5 text-gray-400 w-5 h-5" />
               </div>
               {isSearching && (
                 <button onClick={navigateToHome} className="text-gray-500 px-2 hover:text-gray-800">取消</button>
               )}
            </div>

            {!isSearching ? (
              <>
                {/* Daily Meal Recommendation (Only visible on Home when not searching) */}
                <DailyMealRecommendation 
                   recipes={recipes}
                   onRecipeClick={navigateToRecipe}
                   onSearchClick={(term) => handleGlobalAiSearch(term)}
                />

                {/* Categories View */}
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                    {filteredCategories.map(category => (
                    <CategoryCard
                        key={category.id}
                        category={{...category, description: getCategoryDescription(category)}}
                        count={recipes.filter(r => r.categoryId === category.id).length}
                        onClick={() => navigateToCategory(category.id)}
                    />
                    ))}

                    <button 
                    onClick={() => setViewState({ type: 'ADD_CATEGORY' })}
                    className="flex flex-col items-center justify-center p-6 rounded-2xl bg-white border-2 border-dashed border-gray-300 hover:border-orange-500 hover:bg-orange-50 transition-all min-h-[160px] group"
                    >
                    <div className="p-3 rounded-full bg-gray-100 group-hover:bg-orange-100 mb-3 transition-colors">
                        <Plus className="w-8 h-8 text-gray-400 group-hover:text-orange-500" />
                    </div>
                    <h3 className="text-lg font-bold text-gray-600 group-hover:text-orange-600">更多</h3>
                    <p className="text-sm text-gray-400">添加自定义分类</p>
                    </button>
                </div>
              </>
            ) : (
              // Search Results View
              <div>
                <h2 className="text-lg font-bold text-gray-800 mb-4 flex items-center">
                  <Search className="w-5 h-5 mr-2 text-orange-500" />
                  本地搜索结果 ({localSearchResults.length})
                </h2>

                {localSearchResults.length > 0 ? (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
                    {localSearchResults.map(recipe => (
                      <div 
                        key={recipe.id}
                        onClick={() => navigateToRecipe(recipe)}
                        className={`bg-white p-4 rounded-xl shadow-sm hover:shadow-md transition-all cursor-pointer border ${recipe.isFavorite ? 'border-yellow-200 bg-yellow-50/30' : 'border-gray-100'}`}
                      >
                         <div className="flex gap-4">
                           <div className="flex-1 min-w-0">
                             <div className="flex items-center gap-1">
                                <h3 className="font-bold text-gray-800">{recipe.name}</h3>
                                {recipe.isFavorite && <Star className="w-3.5 h-3.5 text-yellow-400 fill-current" />}
                             </div>
                             <p className="text-sm text-gray-500 line-clamp-1">{recipe.description}</p>
                             <div className="flex gap-2 mt-2 text-xs text-gray-400">
                                 <span>{recipe.cookingTime}</span>
                                 <div className="flex items-center gap-2">
                                    <span className="flex items-center"><Eye className="w-3 h-3 mr-1"/> {recipe.views || 0}</span>
                                 </div>
                             </div>
                           </div>
                           {recipe.image && (
                             <div className="w-16 h-16 flex-shrink-0 rounded-lg overflow-hidden bg-gray-100">
                               <img src={recipe.image} alt={recipe.name} className="w-full h-full object-cover" />
                             </div>
                           )}
                         </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="text-center py-8 text-gray-500 bg-white rounded-xl border border-dashed border-gray-200 mb-8">
                    本地食谱中未找到相关内容
                  </div>
                )}

                {/* AI Search Section */}
                <div className="border-t pt-8">
                  <h2 className="text-lg font-bold text-gray-800 mb-4 flex items-center">
                    <Sparkles className="w-5 h-5 mr-2 text-indigo-500" />
                    AI 智能推荐
                  </h2>

                  {aiSearchResults.length === 0 ? (
                    <div className="bg-indigo-50 rounded-xl p-6 text-center">
                      <p className="text-indigo-800 mb-3 font-medium">
                        {localSearchResults.length === 0 
                          ? `没找到"${searchTerm}"？让 AI 帮您生成菜谱或推荐相似菜品。`
                          : `想看看更多关于"${searchTerm}"的做法？`
                        }
                      </p>
                      <button
                        onClick={() => handleGlobalAiSearch()}
                        disabled={isSuggesting}
                        className="inline-flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors shadow-md disabled:opacity-50"
                      >
                        {isSuggesting ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <ChefHat className="w-4 h-4 mr-2" />}
                        AI 搜索 / 生成 "{searchTerm}"
                      </button>
                    </div>
                  ) : (
                    <div className="space-y-4">
                      <p className="text-sm text-gray-500">点击下方卡片即可查看详情并添加到食谱本：</p>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {aiSearchResults.map((aiRecipe, idx) => (
                          <div 
                            key={idx}
                            onClick={() => handleAddAiRecipe(aiRecipe)}
                            className="group bg-white p-4 rounded-xl shadow-sm hover:shadow-md hover:border-indigo-200 transition-all cursor-pointer border border-indigo-100 relative overflow-hidden"
                          >
                            <div className="absolute top-0 right-0 bg-indigo-500 text-white text-xs px-2 py-1 rounded-bl-lg">AI 推荐</div>
                            <h3 className="font-bold text-gray-800">{aiRecipe.name}</h3>
                            <p className="text-sm text-gray-500 line-clamp-2 mt-1">{aiRecipe.description}</p>
                            <div className="mt-3 flex items-center text-indigo-600 text-xs font-medium opacity-0 group-hover:opacity-100 transition-opacity">
                              <Plus className="w-3 h-3 mr-1" />
                              添加到我的食谱
                            </div>
                          </div>
                        ))}
                      </div>
                      <button 
                        onClick={() => setAiSearchResults([])}
                        className="text-sm text-gray-400 hover:text-gray-600 mt-2 underline"
                      >
                        清空推荐
                      </button>
                    </div>
                  )}
                </div>
              </div>
            )}

            {/* Floating Action Button */}
            <SeasonalRecommendation onSearch={(term) => setSearchTerm(term)} />
          </div>
        );

      case 'ADD_CATEGORY':
        return (
          <CategoryForm 
            onSave={handleSaveCategory}
            onCancel={() => navigateToHome()}
          />
        );

      case 'CATEGORY':
        const category = categories.find(c => c.id === viewState.categoryId);
        if (!category) return <div>Category not found</div>;

        const filteredRecipes = recipes.filter(r => {
           if (r.categoryId !== category.id) return false;
           const term = searchTerm.toLowerCase();
           return (
             r.name.toLowerCase().includes(term) ||
             r.description.toLowerCase().includes(term) ||
             r.ingredients.some(ing => ing.toLowerCase().includes(term))
           );
        });

        // SORTING: Favorites first, then by views desc
        const sortedRecipes = sortRecipes(filteredRecipes);

        return (
          <div className="p-4 sm:p-6 min-h-screen">
            {/* Floating Back Button using Fixed Positioning */}
            <div className="fixed top-20 left-4 z-50">
              <button 
                onClick={() => navigateToHome()}
                className="flex items-center justify-center w-10 h-10 bg-white text-gray-600 hover:text-orange-600 transition-colors rounded-full shadow-lg border border-gray-100"
                title="返回首页"
              >
                <ArrowLeft className="w-5 h-5" />
              </button>
            </div>

            {/* Top Action Bar (Non-floating part) */}
            <div className="flex justify-end gap-2 mb-6">
                <button 
                  onClick={() => setIsRecModalOpen(true)}
                  className="flex items-center px-3 py-1.5 bg-indigo-50 text-indigo-600 rounded-lg hover:bg-indigo-100 transition-colors shadow-sm text-xs font-medium"
                >
                   <BookOpen className="w-3.5 h-3.5 mr-1.5" />
                   灵感菜单
                </button>
                <button
                  onClick={() => setViewState({ type: 'ADD_RECIPE', categoryId: category.id })}
                  className="flex items-center px-3 py-1.5 bg-orange-600 text-white rounded-lg hover:bg-orange-700 transition-colors shadow-md text-xs font-medium"
                >
                  <Plus className="w-3.5 h-3.5 mr-1.5" />
                  添加食谱
                </button>
            </div>

            <div className="flex items-center gap-3 mb-6">
               <div className={`p-3 rounded-full ${category.color} bg-opacity-20`}>
                 {getIconComponent(category.icon, "w-8 h-8")}
               </div>
               <div>
                 <h2 className="text-2xl font-bold text-gray-800">{category.name}</h2>
                 <p className="text-gray-500 text-sm">{getCategoryDescription(category)}</p>
               </div>
            </div>

            {/* Recipe Search Bar */}
            <div className="mb-6 relative">
               <input 
                 type="text" 
                 placeholder={`在 ${category.name} 中搜索食谱...`}
                 value={searchTerm}
                 onChange={e => setSearchTerm(e.target.value)}
                 className="w-full pl-10 pr-4 py-3 rounded-xl border-gray-200 shadow-sm focus:ring-2 focus:ring-orange-500 focus:border-transparent transition-all outline-none"
               />
               <Search className="absolute left-3 top-3.5 text-gray-400 w-5 h-5" />
            </div>

            {sortedRecipes.length === 0 ? (
              <div className="text-center py-20 bg-white rounded-xl border border-dashed border-gray-300">
                {searchTerm ? (
                  <>
                    <div className="mx-auto w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mb-4">
                      <Search className="w-8 h-8 text-gray-400" />
                    </div>
                    <h3 className="text-lg font-medium text-gray-900">未找到相关食谱</h3>
                    <p className="mt-1 text-gray-500">换个关键词试试？</p>
                  </>
                ) : (
                  <>
                    <div className="mx-auto w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mb-4">
                      <Plus className="w-8 h-8 text-gray-400" />
                    </div>
                    <h3 className="text-lg font-medium text-gray-900">暂无食谱</h3>
                    <p className="mt-1 text-gray-500 mb-4">您可以手动添加，或使用“灵感菜单”获取推荐。</p>
                    <button 
                      onClick={() => setIsRecModalOpen(true)}
                      className="inline-flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 shadow-md text-sm font-medium"
                    >
                      <Sparkles className="w-4 h-4 mr-2" />
                      打开灵感菜单
                    </button>
                  </>
                )}
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {sortedRecipes.map(recipe => (
                  <div 
                    key={recipe.id}
                    onClick={() => navigateToRecipe(recipe)}
                    className={`group bg-white p-4 rounded-xl shadow-sm hover:shadow-md transition-all cursor-pointer border relative ${recipe.isFavorite ? 'border-yellow-200 bg-yellow-50/30' : 'border-gray-100'}`}
                  >
                    {/* Recipe Action Buttons on List View */}
                    <div className="absolute top-2 right-2 flex space-x-1 opacity-0 group-hover:opacity-100 transition-opacity z-10 bg-white/80 rounded-full p-1 shadow-sm backdrop-blur-sm">
                      <button
                        onClick={(e) => { e.stopPropagation(); setViewState({ type: 'EDIT_RECIPE', recipeId: recipe.id }); }}
                        className="p-1.5 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-full"
                        title="编辑"
                      >
                        <Pencil className="w-3.5 h-3.5" />
                      </button>
                      <button
                        onClick={(e) => { e.stopPropagation(); handleDeleteRecipe(recipe.id, category.id); }}
                        className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-full"
                        title="删除"
                      >
                        <Trash2 className="w-3.5 h-3.5" />
                      </button>
                    </div>

                    <div className="flex gap-4">
                      <div className="flex-1 min-w-0">
                        <div className="flex justify-between items-start mb-2 mt-1">
                           <div className="flex items-center gap-1.5 truncate pr-2">
                             <h3 className="font-bold text-lg text-gray-800 truncate">{recipe.name}</h3>
                             {recipe.isFavorite && (
                               <Star className="w-4 h-4 text-yellow-400 fill-current flex-shrink-0" />
                             )}
                           </div>
                           <span className={`text-xs px-2 py-1 rounded-full whitespace-nowrap flex-shrink-0 ${
                             recipe.difficulty === 'Easy' ? 'bg-green-100 text-green-700' :
                             recipe.difficulty === 'Medium' ? 'bg-yellow-100 text-yellow-700' :
                             'bg-red-100 text-red-700'
                           }`}>
                             {recipe.difficulty === 'Easy' ? '简单' : recipe.difficulty === 'Medium' ? '中等' : '困难'}
                           </span>
                        </div>
                        <p className="text-gray-500 text-sm line-clamp-2 mb-3">
                          {recipe.description || recipe.instructions[0]}
                        </p>
                        <div className="text-xs text-gray-400 flex items-center gap-3">
                           <span>{recipe.cookingTime}</span>
                           <div className="flex items-center gap-2">
                             <span className="flex items-center"><Eye className="w-3 h-3 mr-1"/> {recipe.views || 0}</span>
                           </div>
                        </div>
                      </div>

                      {recipe.image && (
                         <div className="w-20 h-20 sm:w-24 sm:h-24 flex-shrink-0 rounded-lg overflow-hidden bg-gray-100 border border-gray-200">
                           <img src={recipe.image} alt={recipe.name} className="w-full h-full object-cover" />
                         </div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            )}

            {/* Recommendation Modal */}
            {isRecModalOpen && (
              <RecommendationModal 
                categoryName={category.name}
                existingRecipes={recipes.filter(r => r.categoryId === category.id)}
                onClose={() => setIsRecModalOpen(false)}
                onAddRecipe={(name) => handleQuickAddRecipe(name, category.id, category.name)}
              />
            )}
          </div>
        );

      case 'ADD_RECIPE':
        const addCategory = categories.find(c => c.id === viewState.categoryId);
        return (
          <RecipeForm
            categoryId={viewState.categoryId}
            categoryName={addCategory?.name || ''}
            onSave={handleSaveRecipe}
            onCancel={() => setViewState({ type: 'CATEGORY', categoryId: viewState.categoryId })}
          />
        );

      case 'EDIT_RECIPE':
        const editRecipe = recipes.find(r => r.id === viewState.recipeId);
        if (!editRecipe) return <div>Recipe not found</div>;
        const editCategory = categories.find(c => c.id === editRecipe.categoryId);

        return (
          <RecipeForm
            categoryId={editRecipe.categoryId}
            categoryName={editCategory?.name || ''}
            initialData={editRecipe}
            onSave={handleSaveRecipe}
            onCancel={() => setViewState({ type: 'RECIPE_DETAIL', recipeId: editRecipe.id })}
          />
        );

      case 'RECIPE_DETAIL':
        const recipe = recipes.find(r => r.id === viewState.recipeId);
        if (!recipe) return <div>Recipe not found</div>;
        return (
          <RecipeDetail
            recipe={recipe}
            onBack={() => setViewState({ type: 'CATEGORY', categoryId: recipe.categoryId })}
            onEdit={() => setViewState({ type: 'EDIT_RECIPE', recipeId: recipe.id })}
            onDelete={() => handleDeleteRecipe(recipe.id, recipe.categoryId)}
            onToggleFavorite={() => handleToggleFavorite(recipe.id)}
          />
        );

      default:
        return <div>Unknown view</div>;
    }
  };

  return (
    <Layout 
      onHomeClick={() => navigateToHome()}
      user={user}
      onLoginClick={() => setShowLogin(true)}
      onProfileClick={() => setShowProfile(true)}
    >
      {renderContent()}

      {showLogin && (
        <LoginModal 
          onLogin={handleLoginSuccess}
          onClose={() => setShowLogin(false)}
        />
      )}

      {showProfile && user && (
        <UserProfile 
          user={user}
          onSave={handleUpdateProfile}
          onLogout={handleLogout}
          onClose={() => setShowProfile(false)}
        />
      )}
    </Layout>
  );
}

import React, { useMemo, useState } from 'react';
import { Recipe, CategoryIdEnum } from '../types';
import { Sun, Moon, Sunset, Sunrise, Utensils, ChefHat, Coffee, RefreshCw } from 'lucide-react';

interface DailyMealRecommendationProps {
  recipes: Recipe[];
  onRecipeClick: (recipe: Recipe) => void;
  onSearchClick: (term: string) => void;
}

type MealPeriod = 'breakfast' | 'lunch' | 'dinner' | 'latenight';
type BreakfastStyle = 'chinese' | 'western';

interface RecommendationSlot {
  label: string;
  categoryIds: string[]; // Valid categories for this slot
  fallbackDish: string;  // What to show if no local recipe exists
}

export const DailyMealRecommendation: React.FC<DailyMealRecommendationProps> = ({ 
  recipes, 
  onRecipeClick, 
  onSearchClick 
}) => {
  const [breakfastStyle, setBreakfastStyle] = useState<BreakfastStyle>('chinese');
  const [seed, setSeed] = useState(0); // Used to trigger re-randomization

  const timeData = useMemo(() => {
    const hour = new Date().getHours();
    let period: MealPeriod;
    let title = '';
    let subtitle = '';
    let icon: React.ReactNode;
    let bgGradient = '';

    if (hour >= 6 && hour < 10) {
      period = 'breakfast';
      title = '元气早餐';
      subtitle = '一日之计在于晨';
      icon = <Sunrise className="w-6 h-6 text-orange-500" />;
      bgGradient = 'from-orange-50 to-yellow-50 border-orange-100';
    } else if (hour >= 10 && hour < 15) {
      period = 'lunch';
      title = '丰盛午餐';
      subtitle = '荤素搭配，营养均衡';
      icon = <Sun className="w-6 h-6 text-red-500" />;
      bgGradient = 'from-red-50 to-orange-50 border-red-100';
    } else if (hour >= 15 && hour < 21) {
      period = 'dinner';
      title = '温馨晚餐';
      subtitle = '四菜一汤，抚慰人心';
      icon = <Sunset className="w-6 h-6 text-indigo-500" />;
      bgGradient = 'from-indigo-50 to-purple-50 border-indigo-100';
    } else {
      period = 'latenight';
      title = '深夜食堂';
      subtitle = '快乐夜宵，灵魂伴侣';
      icon = <Moon className="w-6 h-6 text-blue-500" />;
      bgGradient = 'from-slate-50 to-blue-50 border-slate-200';
    }

    return { period, title, subtitle, icon, bgGradient };
  }, []);

  // Define the structure of the meal based on the period
  const mealSlots = useMemo((): RecommendationSlot[] => {
    switch (timeData.period) {
      case 'breakfast':
        if (breakfastStyle === 'chinese') {
          return [
            { label: '主食', categoryIds: [CategoryIdEnum.STAPLE], fallbackDish: '肉包子' },
            { label: '汤粥', categoryIds: [CategoryIdEnum.SOUP, CategoryIdEnum.DRINK], fallbackDish: '小米粥' },
            { label: '搭配', categoryIds: [CategoryIdEnum.SNACK, CategoryIdEnum.STAPLE], fallbackDish: '油条' },
            { label: '佐餐', categoryIds: [CategoryIdEnum.SNACK, CategoryIdEnum.VEGETABLE], fallbackDish: '豆腐脑' },
          ];
        } else {
          return [
            { label: '主食', categoryIds: [CategoryIdEnum.STAPLE], fallbackDish: '培根三明治' },
            { label: '饮品', categoryIds: [CategoryIdEnum.DRINK], fallbackDish: '热牛奶' },
            { label: '烘焙', categoryIds: [CategoryIdEnum.SNACK, CategoryIdEnum.DESSERT], fallbackDish: '恰巴塔' },
            { label: '搭配', categoryIds: [CategoryIdEnum.SNACK, CategoryIdEnum.MEAT], fallbackDish: '煎蛋香肠' },
          ];
        }

      case 'lunch':
      case 'dinner':
        return [
          { label: '荤菜', categoryIds: [CategoryIdEnum.MEAT], fallbackDish: timeData.period === 'lunch' ? '宫保鸡丁' : '清蒸鲈鱼' },
          { label: '素菜', categoryIds: [CategoryIdEnum.VEGETABLE], fallbackDish: '清炒时蔬' },
          { label: '汤类', categoryIds: [CategoryIdEnum.SOUP], fallbackDish: timeData.period === 'lunch' ? '番茄蛋汤' : '玉米排骨汤' },
          { label: '主食', categoryIds: [CategoryIdEnum.STAPLE], fallbackDish: '米饭' },
        ];

      case 'latenight':
        return [
          { label: '快乐水', categoryIds: [CategoryIdEnum.DRINK], fallbackDish: '冰可乐' },
          { label: '炸物', categoryIds: [CategoryIdEnum.SNACK], fallbackDish: '韩式炸鸡' },
          { label: '速食', categoryIds: [CategoryIdEnum.SNACK, CategoryIdEnum.STAPLE], fallbackDish: '火鸡面' },
          { label: '解馋', categoryIds: [CategoryIdEnum.SNACK], fallbackDish: '烤冷面' },
        ];

      default:
        return [];
    }
  }, [timeData.period, breakfastStyle]);

  // Fill the slots with actual recipes or fallback placeholders
  const displayItems = useMemo(() => {
    // Helper to pick a random item from array based on seed
    const pickRandom = <T,>(arr: T[]): T | null => {
      if (arr.length === 0) return null;
      // Simple pseudo-random using seed + array length
      const index = (seed + Math.floor(Math.random() * 100)) % arr.length;
      return arr[index];
    };

    // Keep track of used recipes to avoid duplicates in one meal
    const usedRecipeIds = new Set<string>();

    return mealSlots.map(slot => {
      // Find local recipes that match this slot's allowed categories
      const candidates = recipes.filter(r => 
        slot.categoryIds.includes(r.categoryId) && !usedRecipeIds.has(r.id)
      );

      const picked = pickRandom(candidates);

      if (picked) {
        usedRecipeIds.add(picked.id);
        return { type: 'local', data: picked, label: slot.label };
      } else {
        return { type: 'fallback', name: slot.fallbackDish, label: slot.label };
      }
    });
  }, [mealSlots, recipes, seed]);

  const handleRefresh = () => {
    setSeed(prev => prev + 1);
  };

  return (
    <div className={`mb-6 rounded-2xl border p-4 shadow-sm bg-gradient-to-br ${timeData.bgGradient} relative overflow-hidden`}>
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between mb-4 gap-2">
        <div className="flex items-center gap-2">
          <div className="p-2 bg-white rounded-full shadow-sm">
            {timeData.icon}
          </div>
          <div>
            <h3 className="font-bold text-gray-800 text-lg flex items-center gap-2">
              {timeData.title}
              <span className="text-xs font-normal text-gray-500 bg-white/50 px-2 py-0.5 rounded-full">
                {new Date().getHours()}:00 - {(new Date().getHours() + 1) % 24}:00
              </span>
            </h3>
            <p className="text-xs text-gray-500">{timeData.subtitle}</p>
          </div>
        </div>

        <div className="flex items-center gap-2 self-end sm:self-auto">
          {timeData.period === 'breakfast' && (
            <div className="flex bg-white/60 p-1 rounded-lg border border-gray-100 mr-2">
              <button
                onClick={() => setBreakfastStyle('chinese')}
                className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${
                  breakfastStyle === 'chinese' ? 'bg-orange-500 text-white shadow-sm' : 'text-gray-500 hover:bg-white'
                }`}
              >
                中式
              </button>
              <button
                onClick={() => setBreakfastStyle('western')}
                className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${
                  breakfastStyle === 'western' ? 'bg-orange-500 text-white shadow-sm' : 'text-gray-500 hover:bg-white'
                }`}
              >
                西式
              </button>
            </div>
          )}

          <button 
            onClick={handleRefresh}
            className="p-1.5 bg-white/60 hover:bg-white text-gray-500 hover:text-orange-600 rounded-full transition-colors"
            title="换一换"
          >
            <RefreshCw className="w-4 h-4" />
          </button>
        </div>
      </div>

      {/* Grid */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
        {displayItems.map((item, idx) => {
           if (item.type === 'local' && item.data) {
             const recipe = item.data;
             return (
               <div 
                 key={`rec-${idx}`}
                 onClick={() => onRecipeClick(recipe)}
                 className="bg-white p-2.5 rounded-xl shadow-sm border border-white hover:border-orange-200 cursor-pointer transition-all hover:shadow-md flex flex-col h-full group"
               >
                 <div className="text-[10px] font-bold text-orange-600 mb-1.5 flex items-center">
                    <span className="w-1.5 h-1.5 rounded-full bg-orange-400 mr-1.5"></span>
                    {item.label}
                 </div>
                 {recipe.image ? (
                   <div className="w-full aspect-[4/3] rounded-lg bg-gray-100 overflow-hidden mb-2">
                      <img src={recipe.image} alt={recipe.name} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />
                   </div>
                 ) : (
                   <div className="w-full aspect-[4/3] rounded-lg bg-gray-50 flex items-center justify-center mb-2 text-2xl">
                      🥘
                   </div>
                 )}
                 <div className="mt-auto">
                   <h4 className="font-bold text-gray-800 text-sm truncate">{recipe.name}</h4>
                   <div className="flex items-center gap-1 mt-1">
                      <Utensils className="w-3 h-3 text-gray-400" />
                      <span className="text-xs text-gray-500 truncate">{recipe.cookingTime}</span>
                   </div>
                 </div>
               </div>
             );
           } else {
             return (
               <div 
                 key={`fallback-${idx}`}
                 onClick={() => onSearchClick(item.name || '')}
                 className="bg-white/40 p-3 rounded-xl border border-dashed border-gray-300 hover:border-orange-400 hover:bg-white cursor-pointer transition-all flex flex-col h-full min-h-[140px] relative group"
               >
                  <div className="text-[10px] font-bold text-gray-400 mb-1.5 flex items-center">
                    <span className="w-1.5 h-1.5 rounded-full bg-gray-300 mr-1.5 group-hover:bg-orange-400 transition-colors"></span>
                    {item.label}
                 </div>
                 <div className="flex-1 flex flex-col items-center justify-center text-center">
                    <div className="w-10 h-10 bg-white rounded-full shadow-sm flex items-center justify-center mb-2 text-orange-400 group-hover:text-orange-500 group-hover:scale-110 transition-all">
                        {timeData.period === 'latenight' ? <Utensils className="w-5 h-5" /> : 
                         timeData.period === 'breakfast' && breakfastStyle === 'western' ? <Coffee className="w-5 h-5" /> :
                         <ChefHat className="w-5 h-5" />}
                    </div>
                    <h4 className="font-bold text-gray-700 text-sm">{item.name}</h4>
                    <p className="text-[10px] text-orange-500/80 mt-1 opacity-0 group-hover:opacity-100 transition-opacity">
                        点击生成食谱
                    </p>
                 </div>
               </div>
             );
           }
        })}
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { CategoryId, Recipe } from '../types';
import { generateRecipeWithAI } from '../services/geminiService';
import { Sparkles, Loader2, Save, X, Image as ImageIcon, Upload } from 'lucide-react';

interface RecipeFormProps {
  categoryId: CategoryId;
  categoryName: string;
  initialData?: Recipe;
  onSave: (recipe: Omit<Recipe, 'id' | 'createdAt'>) => void;
  onCancel: () => void;
}

export const RecipeForm: React.FC<RecipeFormProps> = ({ 
  categoryId, 
  categoryName,
  initialData, 
  onSave, 
  onCancel 
}) => {
  const [name, setName] = useState(initialData?.name || '');
  const [description, setDescription] = useState(initialData?.description || '');
  const [ingredientsText, setIngredientsText] = useState(initialData?.ingredients.join('\n') || '');
  const [instructionsText, setInstructionsText] = useState(initialData?.instructions.join('\n') || '');
  const [cookingTime, setCookingTime] = useState(initialData?.cookingTime || '');
  const [difficulty, setDifficulty] = useState<'Easy' | 'Medium' | 'Hard'>(initialData?.difficulty || 'Medium');
  const [image, setImage] = useState<string>(initialData?.image || '');

  const [isGenerating, setIsGenerating] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleAISuggest = async () => {
    if (!name.trim()) {
      alert("请输入菜名以便AI为您生成食谱");
      return;
    }

    setIsGenerating(true);
    try {
      const generated = await generateRecipeWithAI(name, categoryName);
      if (generated) {
        if (generated.description) setDescription(generated.description);
        if (generated.ingredients) setIngredientsText(generated.ingredients.join('\n'));
        if (generated.instructions) setInstructionsText(generated.instructions.join('\n'));
        if (generated.cookingTime) setCookingTime(generated.cookingTime);
        if (generated.difficulty) setDifficulty(generated.difficulty as any);
      }
    } catch (e) {
      alert("AI 生成失败，请稍后重试。");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      // Basic client-side compression using Canvas
      const reader = new FileReader();
      reader.onload = (event) => {
        const img = new Image();
        img.onload = () => {
          const canvas = document.createElement('canvas');
          let width = img.width;
          let height = img.height;
          const MAX_SIZE = 800; // Resize to max 800px to save storage

          if (width > height) {
            if (width > MAX_SIZE) {
              height *= MAX_SIZE / width;
              width = MAX_SIZE;
            }
          } else {
            if (height > MAX_SIZE) {
              width *= MAX_SIZE / height;
              height = MAX_SIZE;
            }
          }

          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');
          if (ctx) {
            ctx.drawImage(img, 0, 0, width, height);
            // Compress to JPEG 0.7 quality
            const dataUrl = canvas.toDataURL('image/jpeg', 0.7);
            setImage(dataUrl);
          }
        };
        img.src = event.target?.result as string;
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      categoryId,
      name,
      description,
      ingredients: ingredientsText.split('\n').filter(line => line.trim() !== ''),
      instructions: instructionsText.split('\n').filter(line => line.trim() !== ''),
      cookingTime,
      difficulty,
      image
    });
  };

  return (
    <div className="max-w-3xl mx-auto p-4 sm:p-6 bg-white rounded-2xl shadow-xl my-4 animate-in fade-in slide-in-from-bottom-4 duration-300">
      <div className="flex justify-between items-center mb-6 border-b pb-4">
        <h2 className="text-2xl font-extrabold text-gray-900 tracking-tight">
          {initialData ? '编辑食谱' : '添加新食谱'}
        </h2>
        <button onClick={onCancel} className="p-2 rounded-full hover:bg-gray-100 text-gray-400 hover:text-gray-600 transition-colors">
          <X className="w-6 h-6" />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-8">
        {/* Name Input with AI Button */}
        <div>
          <label className="block text-sm font-bold text-gray-700 mb-2">菜品名称</label>
          <div className="flex gap-3">
            <input
              type="text"
              required
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="flex-1 block w-full rounded-xl border-gray-200 shadow-sm focus:border-orange-500 focus:ring-orange-500 text-lg py-3 px-4 border transition-all"
              placeholder="例如：红烧肉"
            />
            <button
              type="button"
              onClick={handleAISuggest}
              disabled={isGenerating || !name.trim()}
              className={`relative overflow-hidden inline-flex items-center px-6 py-3 border border-transparent text-sm font-bold rounded-xl shadow-lg focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-purple-500 disabled:opacity-70 disabled:cursor-not-allowed transition-all hover:scale-105 active:scale-95 ${
                isGenerating 
                  ? 'text-white' 
                  : 'bg-gradient-to-r from-indigo-600 to-purple-600 text-white hover:shadow-indigo-500/30'
              }`}
            >
              {isGenerating && (
                <div className="absolute inset-0 bg-gradient-to-r from-pink-500 via-purple-500 to-indigo-500 animate-[pulse_1.5s_ease-in-out_infinite]" />
              )}
              <span className="relative flex items-center">
                 {isGenerating ? <Loader2 className="w-5 h-5 mr-2 animate-spin" /> : <Sparkles className="w-5 h-5 mr-2" />}
                 {isGenerating ? 'AI 思考中...' : 'AI 自动填充'}
              </span>
            </button>
          </div>
          <p className="mt-2 text-xs text-gray-500 flex items-center">
            <Sparkles className="w-3 h-3 mr-1 text-purple-500" />
            输入菜名后点击右侧按钮，让 AI 为您自动生成食材和步骤
          </p>
        </div>

        {/* Image Upload */}
        <div>
          <label className="block text-sm font-bold text-gray-700 mb-2">菜品照片</label>
          <div className="flex items-start space-x-6">
            <div 
              onClick={() => fileInputRef.current?.click()}
              className={`relative w-40 h-40 rounded-2xl border-2 border-dashed flex items-center justify-center cursor-pointer transition-all overflow-hidden group shadow-sm hover:shadow-md ${image ? 'border-orange-500 ring-2 ring-orange-100' : 'border-gray-300 bg-gray-50 hover:bg-orange-50 hover:border-orange-400'}`}
            >
              {image ? (
                <>
                  <img src={image} alt="Preview" className="w-full h-full object-cover saturate-[1.1]" />
                  <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity backdrop-blur-[2px]">
                    <span className="text-white text-xs font-bold px-3 py-1 bg-white/20 rounded-full border border-white/50">更换图片</span>
                  </div>
                </>
              ) : (
                <div className="text-center p-4">
                  <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center mx-auto mb-2 shadow-sm group-hover:scale-110 transition-transform">
                     <ImageIcon className="w-6 h-6 text-gray-400 group-hover:text-orange-500" />
                  </div>
                  <span className="text-xs font-medium text-gray-500 group-hover:text-orange-600">点击上传美图</span>
                </div>
              )}
            </div>
            <div className="flex-1 pt-4 space-y-3">
               <button 
                 type="button"
                 onClick={() => fileInputRef.current?.click()}
                 className="inline-flex items-center px-4 py-2 border border-gray-200 shadow-sm text-sm font-medium rounded-lg text-gray-700 bg-white hover:bg-gray-50 hover:border-gray-300 transition-colors"
               >
                 <Upload className="w-4 h-4 mr-2" />
                 选择图片
               </button>
               {image && (
                 <button 
                    type="button"
                    onClick={() => setImage('')}
                    className="ml-3 inline-flex items-center px-4 py-2 text-sm font-medium rounded-lg text-red-600 bg-red-50 hover:bg-red-100 transition-colors"
                 >
                   删除
                 </button>
               )}
               <p className="text-xs text-gray-400 leading-relaxed">
                 建议上传高饱和度的美食照片（支持 JPG/PNG），图片将自动压缩优化。
               </p>
            </div>
            <input 
              type="file" 
              ref={fileInputRef} 
              onChange={handleImageUpload} 
              accept="image/*" 
              className="hidden" 
            />
          </div>
        </div>

        {/* Description */}
        <div>
          <label className="block text-sm font-bold text-gray-700 mb-2">简介</label>
          <textarea
            rows={3}
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            className="block w-full rounded-xl border-gray-200 shadow-sm focus:border-orange-500 focus:ring-orange-500 text-sm py-3 px-4 border transition-colors bg-gray-50 focus:bg-white"
            placeholder="简要描述这道菜的风味和特点..."
          />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
           {/* Ingredients */}
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2 flex items-center">
              <span className="w-2 h-2 rounded-full bg-green-500 mr-2"></span>
              食材清单
            </label>
            <textarea
              rows={10}
              required
              value={ingredientsText}
              onChange={(e) => setIngredientsText(e.target.value)}
              className="block w-full rounded-xl border-gray-200 shadow-sm focus:border-orange-500 focus:ring-orange-500 text-sm border p-4 font-mono leading-relaxed bg-gray-50 focus:bg-white transition-colors"
              placeholder={'500g 五花肉\n2片 姜\n2勺 酱油\n...'}
            />
            <p className="text-xs text-gray-400 mt-2 text-right">每行一项</p>
          </div>

          {/* Instructions */}
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2 flex items-center">
              <span className="w-2 h-2 rounded-full bg-orange-500 mr-2"></span>
              制作步骤
            </label>
            <textarea
              rows={10}
              required
              value={instructionsText}
              onChange={(e) => setInstructionsText(e.target.value)}
              className="block w-full rounded-xl border-gray-200 shadow-sm focus:border-orange-500 focus:ring-orange-500 text-sm border p-4 font-mono leading-relaxed bg-gray-50 focus:bg-white transition-colors"
              placeholder={'1. 洗净猪肉...\n2. 冷水下锅焯水...\n3. 炒糖色...\n...'}
            />
            <p className="text-xs text-gray-400 mt-2 text-right">每行一步</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 bg-gray-50 p-6 rounded-2xl border border-gray-100">
          {/* Cooking Time */}
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">烹饪时间</label>
            <input
              type="text"
              value={cookingTime}
              onChange={(e) => setCookingTime(e.target.value)}
              className="block w-full rounded-lg border-gray-200 shadow-sm focus:border-orange-500 focus:ring-orange-500 text-sm py-2 px-3 border"
              placeholder="例如：45分钟"
            />
          </div>

          {/* Difficulty */}
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">难度</label>
            <div className="relative">
              <select
                value={difficulty}
                onChange={(e) => setDifficulty(e.target.value as any)}
                className="block w-full rounded-lg border-gray-200 shadow-sm focus:border-orange-500 focus:ring-orange-500 text-sm py-2 px-3 border bg-white appearance-none"
              >
                <option value="Easy">简单</option>
                <option value="Medium">中等</option>
                <option value="Hard">困难</option>
              </select>
              <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-gray-700">
                <svg className="fill-current h-4 w-4" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20"><path d="M9.293 12.95l.707.707L15.657 8l-1.414-1.414L10 10.828 5.757 6.586 4.343 8z"/></svg>
              </div>
            </div>
          </div>
        </div>

        <div className="flex justify-end pt-6 border-t gap-4">
          <button
            type="button"
            onClick={onCancel}
            className="px-6 py-2.5 border border-gray-200 rounded-xl text-sm font-bold text-gray-600 hover:bg-gray-50 hover:text-gray-900 transition-colors"
          >
            取消
          </button>
          <button
            type="submit"
            className="inline-flex items-center px-8 py-2.5 border border-transparent text-sm font-bold rounded-xl shadow-lg text-white bg-orange-600 hover:bg-orange-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-orange-500 hover:shadow-orange-500/30 transform hover:-translate-y-0.5 transition-all"
          >
            <Save className="w-4 h-4 mr-2" />
            保存食谱
          </button>
        </div>
      </form>
    </div>
  );
};

import React, { useState } from 'react';
