export const searchRecipesWithAI = async (searchTerm: string, prefs?: UserPreferences): Promise<Partial<Recipe>[]> => {
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }

  const prefContext = formatPreferences(prefs);
  const prompt = `用户想找"${searchTerm}"相关的菜谱。${prefContext}
  1. 如果"${searchTerm}"是一道具体的菜，请生成这道菜的食谱，并额外推荐2道相似或搭配的菜。
  2. 如果"${searchTerm}"是食材，请推荐3道使用该食材的经典菜谱。
  请直接返回3个食谱的详细JSON数组。`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: searchResultSchema,
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text);
  } catch (error) {
    console.error("AI Search Error:", error);
    throw error;
  }
};

export const recommendFromIngredients = async (ingredients: string[], prefs?: UserPreferences): Promise<Partial<Recipe>[]> => {
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }

  const prefContext = formatPreferences(prefs);
  const ingredientStr = ingredients.join('、');
  const prompt = `用户的冰箱里有这些食材：${ingredientStr}。
  请根据这些食材推荐3道合适的菜谱。
  要求：
  1. 尽量利用给定食材。
  2. 如果缺少少量配料（如葱姜蒜调料）可以默认用户家里有。
  3. 菜谱要美味且做法家常。
  ${prefContext}
  请直接返回3个详细的食谱JSON数组。`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: searchResultSchema,
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text);
  } catch (error) {
    console.error("AI Ingredient Recommendation Error:", error);
    throw error;
  }
};

export const getRecommendedDishes = async (categoryName: string): Promise<string[]> => {
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }

  const prompt = `请列出15道最经典的“${categoryName}”菜名。只返回菜名列表，不要包含其他内容。例如：['红烧肉', '糖醋排骨', ...]`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: dishListSchema,
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const data = JSON.parse(text);
    return data.dishes || [];
  } catch (error) {
    console.error("AI Recommendation List Error:", error);
    // Fallback list if AI fails
    return ["推荐菜品1", "推荐菜品2", "推荐菜品3"];
  }
};

import React, { useState } from 'react';
import { recommendFromIngredients } from '../services/geminiService';
import { Recipe, UserPreferences } from '../types';
import { X, Sparkles, Loader2, Plus, Refrigerator, ChefHat } from 'lucide-react';

interface FridgeModalProps {
  onClose: () => void;
  onAddRecipe: (recipe: Partial<Recipe>) => void;
  userPrefs?: UserPreferences;
}

export const FridgeModal: React.FC<FridgeModalProps> = ({ onClose, onAddRecipe, userPrefs }) => {
  const [ingredients, setIngredients] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [results, setResults] = useState<Partial<Recipe>[]>([]);

  const handleGenerate = async () => {
    if (!ingredients.trim()) {
        alert('请先输入冰箱里的食材');
        return;
    }

    setIsGenerating(true);
    setResults([]);
    try {
      const inputs = ingredients.split(/[,，\s]+/).filter(i => i.trim());
      const recipes = await recommendFromIngredients(inputs, userPrefs);
      setResults(recipes);
    } catch (e) {
      alert('AI 思考失败，请稍后重试');
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[90vh]">
        {/* Header */}
        <div className="p-5 border-b flex justify-between items-center bg-gradient-to-r from-blue-50 to-indigo-50">
          <div className="flex items-center gap-3">
            <div className="bg-white p-2 rounded-xl shadow-sm">
                <Refrigerator className="w-6 h-6 text-blue-600" />
            </div>
            <div>
                <h2 className="text-xl font-extrabold text-gray-800">冰箱大搜救</h2>
                <p className="text-xs text-gray-500">输入食材，AI 为您定制食谱</p>
            </div>
          </div>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600 p-1 hover:bg-white rounded-full transition-colors">
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="p-6 overflow-y-auto flex-1">
            {/* Input Section */}
            <div className="mb-8">
                <label className="block text-sm font-bold text-gray-700 mb-2">冰箱里有哪些食材？</label>
                <div className="relative">
                    <textarea
                        rows={3}
                        value={ingredients}
                        onChange={(e) => setIngredients(e.target.value)}
                        className="block w-full rounded-xl border-gray-200 shadow-sm focus:border-blue-500 focus:ring-blue-500 text-lg p-4 border bg-gray-50 focus:bg-white transition-colors"
                        placeholder="例如：两个鸡蛋、半个洋葱、一根火腿肠..."
                    />
                    <button
                        onClick={handleGenerate}
                        disabled={isGenerating || !ingredients.trim()}
                        className="absolute bottom-3 right-3 inline-flex items-center px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 shadow-md disabled:opacity-50 transition-all font-bold text-sm hover:scale-105 active:scale-95"
                    >
                        {isGenerating ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Sparkles className="w-4 h-4 mr-2" />}
                        开始推荐
                    </button>
                </div>
            </div>

            {/* Results Section */}
            {isGenerating ? (
                <div className="text-center py-12">
                     <div className="w-16 h-16 bg-blue-50 rounded-full flex items-center justify-center mx-auto mb-4 animate-bounce">
                        <ChefHat className="w-8 h-8 text-blue-500" />
                     </div>
                     <h3 className="text-lg font-bold text-gray-700">AI 正在根据您的食材构思食谱...</h3>
                     <p className="text-gray-500 mt-2">正在计算最佳搭配组合</p>
                </div>
            ) : results.length > 0 ? (
                <div className="space-y-6">
                    <h3 className="font-bold text-gray-800 flex items-center">
                        <Sparkles className="w-4 h-4 mr-2 text-blue-500" />
                        为您推荐以下 {results.length} 道美味：
                    </h3>
                    <div className="grid grid-cols-1 gap-4">
                        {results.map((recipe, idx) => (
                            <div key={idx} className="bg-white border border-gray-100 rounded-xl p-4 shadow-sm hover:shadow-lg transition-all flex flex-col sm:flex-row gap-4 group">
                                <div className="flex-1">
                                    <h4 className="text-lg font-extrabold text-gray-900 mb-1">{recipe.name}</h4>
                                    <p className="text-sm text-gray-600 mb-3 line-clamp-2">{recipe.description}</p>
                                    <div className="flex flex-wrap gap-2 mb-3">
                                        {recipe.ingredients?.slice(0, 4).map((ing, i) => (
                                            <span key={i} className="bg-gray-100 text-gray-600 text-xs px-2 py-1 rounded-md">
                                                {ing}
                                            </span>
                                        ))}
                                    </div>
                                    <div className="flex items-center gap-4 text-xs font-bold text-gray-400">
                                        <span className="bg-blue-50 text-blue-600 px-2 py-0.5 rounded">{recipe.cookingTime}</span>
                                        <span>{recipe.difficulty === 'Easy' ? '简单' : recipe.difficulty === 'Medium' ? '中等' : '困难'}</span>
                                    </div>
                                </div>
                                <div className="flex items-center">
                                    <button 
                                        onClick={() => onAddRecipe(recipe)}
                                        className="w-full sm:w-auto px-4 py-2 bg-blue-50 text-blue-600 hover:bg-blue-600 hover:text-white rounded-lg font-bold text-sm transition-all flex items-center justify-center"
                                    >
                                        <Plus className="w-4 h-4 mr-2" />
                                        加入食谱
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            ) : null}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Layout } from './components/Layout';
import { CategoryCard } from './components/CategoryCard';
import { RecipeForm } from './components/RecipeForm';
import { RecipeDetail } from './components/RecipeDetail';
import { CategoryForm } from './components/CategoryForm';
import { LoginModal } from './components/LoginModal';
import { UserProfile } from './components/UserProfile';
import { DailyMealRecommendation } from './components/DailyMealRecommendation';
import { FridgeModal } from './components/FridgeModal';
import { Category, CategoryId, Recipe, ViewState, User, UserPreferences } from './types';
import { DEFAULT_CATEGORIES, getIconComponent } from './constants';
import { Plus, ArrowLeft, Loader2, Search, Pencil, Trash2, Sparkles, ChefHat, BookOpen, Eye, Star, Clock, Refrigerator } from 'lucide-react';
import { suggestRandomRecipe, generateRecipeWithAI, searchRecipesWithAI } from './services/geminiService';
import { INITIAL_RECIPES } from './seedData';
import { SeasonalRecommendation } from './components/SeasonalRecommendation';
import { RecommendationModal } from './components/RecommendationModal';

export default function App() {
  const [categories, setCategories] = useState<Category[]>([]);
  const [recipes, setRecipes] = useState<Recipe[]>([]);
  const [viewState, setViewState] = useState<ViewState>({ type: 'HOME' });
  const [searchTerm, setSearchTerm] = useState('');
  const [isSuggesting, setIsSuggesting] = useState(false);
  const [aiSearchResults, setAiSearchResults] = useState<Partial<Recipe>[]>([]);
  const [isRecModalOpen, setIsRecModalOpen] = useState(false);
  const [isFridgeModalOpen, setIsFridgeModalOpen] = useState(false);

  // User State
  const [user, setUser] = useState<User | null>(null);
  const [showLogin, setShowLogin] = useState(false);
  const [showProfile, setShowProfile] = useState(false);

  // --- Data Loading Logic ---

  // Helper to get storage keys based on user
  const getStorageKeys = (currentUser: User | null) => {
    const suffix = currentUser ? `_${currentUser.phoneNumber}` : '_guest';
    return {
      recipes: `smart-recipe-book-data${suffix}`,
      categories: `smart-recipe-book-categories${suffix}`,
    };
  };

  const loadDataForUser = useCallback((currentUser: User | null) => {
    const keys = getStorageKeys(currentUser);

    // Load Recipes
    const savedRecipes = localStorage.getItem(keys.recipes);
    if (savedRecipes) {
      try {
        const parsed = JSON.parse(savedRecipes);
        const migrated = parsed.map((r: any) => ({ 
          ...r, 
          views: r.views || 0,
          isFavorite: r.isFavorite || (r.likes > 0) || false 
        }));
        setRecipes(migrated);
      } catch (e) {
        console.error("Failed to load recipes", e);
        setRecipes(INITIAL_RECIPES);
      }
    } else {
      // Always initialize with seed data for new users or guests
      setRecipes(INITIAL_RECIPES);
    }

    // Load Categories
    const savedCategories = localStorage.getItem(keys.categories);
    if (savedCategories) {
      try {
        setCategories(JSON.parse(savedCategories));
      } catch (e) {
        setCategories(DEFAULT_CATEGORIES);
      }
    } else {
      setCategories(DEFAULT_CATEGORIES);
    }
  }, []);

  // Initial Load (Check for active session)
  useEffect(() => {
    const activeUserJson = localStorage.getItem('active_user_session');
    let activeUser: User | null = null;
    if (activeUserJson) {
      try {
        activeUser = JSON.parse(activeUserJson);
        setUser(activeUser);
      } catch (e) {
        localStorage.removeItem('active_user_session');
      }
    }
    loadDataForUser(activeUser);
  }, [loadDataForUser]);

  // Persistence (Whenever data or user changes)
  useEffect(() => {
    const keys = getStorageKeys(user);
    if (recipes.length > 0 || user) { // Only save if data exists or user is logged in (to save empty state)
        localStorage.setItem(keys.recipes, JSON.stringify(recipes));
    }
  }, [recipes, user]);

  useEffect(() => {
    const keys = getStorageKeys(user);
    if (categories.length > 0) {
        localStorage.setItem(keys.categories, JSON.stringify(categories));
    }
  }, [categories, user]);

  // --- User Actions ---

  const handleLoginSuccess = (userData: User) => {
    setUser(userData);
    localStorage.setItem('active_user_session', JSON.stringify(userData));
    setShowLogin(false);

    // Switch data context
    loadDataForUser(userData);
    setViewState({ type: 'HOME' });
    setSearchTerm('');
  };

  const handleLogout = () => {
    localStorage.removeItem('active_user_session');
    setUser(null);
    setShowProfile(false);
    // Revert to guest data
    loadDataForUser(null);
    setViewState({ type: 'HOME' });
    setSearchTerm('');
  };

  const handleUpdateProfile = (name: string, prefs: UserPreferences) => {
    if (!user) return;
    const updatedUser = { ...user, name, preferences: prefs };
    setUser(updatedUser);
    localStorage.setItem('active_user_session', JSON.stringify(updatedUser));
    localStorage.setItem(`user_profile_${user.phoneNumber}`, JSON.stringify(updatedUser));
    setShowProfile(false);
  };

  // --- Navigation Helpers ---
  const navigateToHome = () => {
    setSearchTerm('');
    setAiSearchResults([]);
    setViewState({ type: 'HOME' });
    setIsRecModalOpen(false);
  };

  const navigateToCategory = (categoryId: CategoryId) => {
    setSearchTerm('');
    setAiSearchResults([]);
    setViewState({ type: 'CATEGORY', categoryId });
    setIsRecModalOpen(false);
  };

  const navigateToRecipe = (recipe: Recipe) => {
    // Increment view count
    const updatedRecipes = recipes.map(r => 
      r.id === recipe.id ? { ...r, views: (r.views || 0) + 1 } : r
    );
    setRecipes(updatedRecipes);
    setViewState({ type: 'RECIPE_DETAIL', recipeId: recipe.id });
  };

  // --- Dynamic Descriptions ---
  const getCategoryDescription = (category: Category) => {
    const catRecipes = recipes.filter(r => r.categoryId === category.id);
    if (catRecipes.length === 0) return category.description;

    // Sort by views desc
    const sorted = [...catRecipes].sort((a, b) => (b.views || 0) - (a.views || 0));
    const topNames = sorted.slice(0, 3).map(r => r.name).join('、');
    return `${topNames}${sorted.length > 3 ? '等...' : ''}`;
  };

  // --- Helper: Sort Recipes (Favorites First, Then Views) ---
  const sortRecipes = (list: Recipe[]) => {
    return [...list].sort((a, b) => {
      // 1. Favorites First
      const favA = a.isFavorite ? 1 : 0;
      const favB = b.isFavorite ? 1 : 0;
      if (favA !== favB) return favB - favA;

      // 2. Then by Views (High to Low)
      return (b.views || 0) - (a.views || 0);
    });
  };

  // --- Recipe Actions ---

  const handleSaveRecipe = (newRecipeData: Omit<Recipe, 'id' | 'createdAt'>) => {
    if (viewState.type === 'EDIT_RECIPE') {
      const updatedRecipes = recipes.map(r => 
        r.id === viewState.recipeId ? { ...r, ...newRecipeData } : r
      );
      setRecipes(updatedRecipes);
      setViewState({ type: 'RECIPE_DETAIL', recipeId: viewState.recipeId });
    } else {
      const newRecipe: Recipe = {
        ...newRecipeData,
        id: crypto.randomUUID(),
        createdAt: Date.now(),
        views: 0,
        isFavorite: false
      };
      setRecipes(prev => [...prev, newRecipe]);
      navigateToCategory(newRecipeData.categoryId);
    }
  };

  const handleToggleFavorite = (recipeId: string) => {
    setRecipes(prev => prev.map(r => {
      if (r.id === recipeId) {
        return { ...r, isFavorite: !r.isFavorite };
      }
      return r;
    }));
  };

  const handleAddAiRecipe = (aiRecipe: Partial<Recipe>) => {
    if (!aiRecipe.name) return;

    // Auto-detect category or default to 'Meat' if unknown
    let targetCatId = categories[0].id;

    const newRecipe: Recipe = {
      id: crypto.randomUUID(),
      categoryId: targetCatId,
      name: aiRecipe.name,
      description: aiRecipe.description || '',
      ingredients: aiRecipe.ingredients || [],
      instructions: aiRecipe.instructions || [],
      cookingTime: aiRecipe.cookingTime || '30 mins',
      difficulty: (aiRecipe.difficulty as any) || 'Medium',
      createdAt: Date.now(),
      views: 0,
      isFavorite: false
    };
    setRecipes(prev => [...prev, newRecipe]);
    setIsFridgeModalOpen(false); // Close fridge modal if open
    navigateToRecipe(newRecipe);
  };

  const handleDeleteRecipe = (recipeId: string, categoryId: CategoryId) => {
    if (window.confirm('确定要删除这道菜谱吗？')) {
      setRecipes(prev => prev.filter(r => r.id !== recipeId));
      // Return to category or home depending on where we came from
      setViewState({ type: 'CATEGORY', categoryId });
    }
  };

  const handleGlobalAiSearch = async (initialTerm?: string) => {
    const term = initialTerm || searchTerm;
    if (!term.trim()) return;

    // If called with a specific term (like from daily rec), update search input
    if (initialTerm) {
        setSearchTerm(initialTerm);
    }

    setIsSuggesting(true);
    try {
      const results = await searchRecipesWithAI(term, user?.preferences);
      setAiSearchResults(results);
    } catch (e) {
      alert("AI 搜索失败，请重试");
    } finally {
      setIsSuggesting(false);
    }
  };

  // Handle Quick Add from Recommendation Modal
  const handleQuickAddRecipe = async (dishName: string, categoryId: CategoryId, categoryName: string) => {
    const aiRecipe = await generateRecipeWithAI(dishName, categoryName, user?.preferences);
    if (!aiRecipe.name) throw new Error("Failed to generate");

    const newRecipe: Recipe = {
      id: crypto.randomUUID(),
      categoryId,
      name: aiRecipe.name,
      description: aiRecipe.description || '',
      ingredients: aiRecipe.ingredients || [],
      instructions: aiRecipe.instructions || [],
      cookingTime: aiRecipe.cookingTime || '30 mins',
      difficulty: (aiRecipe.difficulty as any) || 'Medium',
      createdAt: Date.now(),
      views: 0,
      isFavorite: false
    };
    setRecipes(prev => [...prev, newRecipe]);
  };

  // --- Category Actions ---

  const handleSaveCategory = (categoryData: Omit<Category, 'id'>) => {
    const newCategory: Category = {
      ...categoryData,
      id: `custom-${crypto.randomUUID()}`,
    };
    setCategories(prev => [...prev, newCategory]);
    navigateToHome();
  };


  const renderContent = () => {
    switch (viewState.type) {
      case 'HOME':
        const isSearching = searchTerm.trim().length > 0;

        const filteredCategories = categories.filter(c => 
          c.name.includes(searchTerm) || c.description.includes(searchTerm)
        );

        let localSearchResults = isSearching ? recipes.filter(r => {
           const term = searchTerm.toLowerCase();
           return (
             r.name.toLowerCase().includes(term) ||
             r.ingredients.some(ing => ing.toLowerCase().includes(term))
           );
        }) : [];

        if (isSearching && localSearchResults.length > 0) {
            localSearchResults = sortRecipes(localSearchResults);
        }

        return (
          <div className="p-4 sm:p-6 pb-24">
            {/* Persistent Search Bar */}
            <div className="mb-6 flex gap-2">
               <div className="relative flex-1">
                 <input 
                   type="text" 
                   placeholder="输入菜名或食材（如：油菜、鸡翅）..." 
                   value={searchTerm}
                   onChange={e => {
                     setSearchTerm(e.target.value);
                     if (e.target.value === '') {
                       setAiSearchResults([]); 
                     }
                   }}
                   className="w-full pl-10 pr-4 py-3 rounded-2xl border-gray-200 shadow-sm focus:ring-2 focus:ring-orange-500 focus:border-transparent transition-all outline-none"
                 />
                 <Search className="absolute left-3 top-3.5 text-gray-400 w-5 h-5" />
               </div>
               {isSearching && (
                 <button onClick={navigateToHome} className="text-gray-500 px-2 hover:text-gray-800 font-medium">取消</button>
               )}
            </div>

            {!isSearching && (
                <div className="mb-6">
                    <button 
                        onClick={() => setIsFridgeModalOpen(true)}
                        className="w-full bg-gradient-to-r from-blue-500 to-indigo-600 text-white p-4 rounded-2xl shadow-lg hover:shadow-xl hover:scale-[1.01] transition-all flex items-center justify-between group"
                    >
                        <div className="flex items-center gap-3">
                            <div className="bg-white/20 p-2 rounded-xl">
                                <Refrigerator className="w-6 h-6 text-white" />
                            </div>
                            <div className="text-left">
                                <h3 className="font-bold text-lg">冰箱大搜救</h3>
                                <p className="text-xs text-blue-100 opacity-90">不知道吃什么？输入食材让 AI 帮您搭配！</p>
                            </div>
                        </div>
                        <ArrowLeft className="w-5 h-5 rotate-180 group-hover:translate-x-1 transition-transform" />
                    </button>
                </div>
            )}

            {!isSearching ? (
              <>
                {/* Daily Meal Recommendation (Only visible on Home when not searching) */}
                <DailyMealRecommendation 
                   recipes={recipes}
                   onRecipeClick={navigateToRecipe}
                   onSearchClick={(term) => handleGlobalAiSearch(term)}
                />

                {/* Categories View */}
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5">
                    {filteredCategories.map(category => (
                    <CategoryCard
                        key={category.id}
                        category={{...category, description: getCategoryDescription(category)}}
                        count={recipes.filter(r => r.categoryId === category.id).length}
                        onClick={() => navigateToCategory(category.id)}
                    />
                    ))}

                    <button 
                    onClick={() => setViewState({ type: 'ADD_CATEGORY' })}
                    className="flex flex-col items-center justify-center p-6 rounded-2xl bg-white border-2 border-dashed border-gray-300 hover:border-orange-500 hover:bg-orange-50 transition-all min-h-[160px] group hover:scale-[1.02] duration-300"
                    >
                    <div className="p-3 rounded-full bg-gray-100 group-hover:bg-orange-100 mb-3 transition-colors">
                        <Plus className="w-8 h-8 text-gray-400 group-hover:text-orange-500" />
                    </div>
                    <h3 className="text-lg font-bold text-gray-600 group-hover:text-orange-600">更多</h3>
                    <p className="text-sm text-gray-400">添加自定义分类</p>
                    </button>
                </div>
              </>
            ) : (
              // Search Results View
              <div>
                <h2 className="text-lg font-bold text-gray-800 mb-4 flex items-center">
                  <Search className="w-5 h-5 mr-2 text-orange-500" />
                  本地搜索结果 ({localSearchResults.length})
                </h2>

                {localSearchResults.length > 0 ? (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-5 mb-8">
                    {localSearchResults.map(recipe => (
                      <div 
                        key={recipe.id}
                        onClick={() => navigateToRecipe(recipe)}
                        className={`group bg-white p-4 rounded-2xl shadow-sm hover:shadow-xl hover:scale-[1.02] transition-all duration-300 cursor-pointer border relative overflow-hidden ${recipe.isFavorite ? 'border-yellow-200 bg-yellow-50/20' : 'border-gray-100'}`}
                      >
                         {/* Action Buttons for Search Results */}
                         <div className="absolute top-3 right-3 flex space-x-2 opacity-0 group-hover:opacity-100 transition-all duration-300 translate-y-[-10px] group-hover:translate-y-0 z-10 bg-white/90 rounded-full p-1.5 shadow-md backdrop-blur-sm">
                            <button
                                onClick={(e) => { 
                                    e.preventDefault();
                                    e.stopPropagation(); 
                                    setViewState({ type: 'EDIT_RECIPE', recipeId: recipe.id }); 
                                }}
                                className="p-2 text-gray-500 hover:text-blue-600 hover:bg-blue-50 rounded-full transition-colors"
                                title="编辑"
                            >
                                <Pencil className="w-4 h-4" />
                            </button>
                            <button
                                onClick={(e) => { 
                                    e.preventDefault();
                                    e.stopPropagation(); 
                                    handleDeleteRecipe(recipe.id, recipe.categoryId); 
                                }}
                                className="p-2 text-gray-500 hover:text-red-600 hover:bg-red-50 rounded-full transition-colors"
                                title="删除"
                            >
                                <Trash2 className="w-4 h-4" />
                            </button>
                         </div>

                         <div className="flex gap-5">
                           <div className="flex-1 min-w-0 flex flex-col justify-center">
                             <div className="flex items-center gap-2 mb-1">
                                <h3 className="font-extrabold text-xl text-gray-900 line-clamp-1">{recipe.name}</h3>
                                {recipe.isFavorite && <Star className="w-5 h-5 text-yellow-400 fill-current" />}
                             </div>
                             <p className="text-sm text-gray-600 line-clamp-1 mb-2">{recipe.description}</p>
                             <div className="flex items-center gap-3 text-xs">
                                 <span className="bg-orange-100 text-orange-700 px-2 py-0.5 rounded-md font-medium">{recipe.cookingTime}</span>
                                 <div className="flex items-center gap-1 text-gray-400">
                                    <Eye className="w-3.5 h-3.5"/> <span>{recipe.views || 0}</span>
                                 </div>
                             </div>
                           </div>
                           {recipe.image && (
                             <div className="w-24 h-24 flex-shrink-0 rounded-xl overflow-hidden shadow-sm">
                               <img src={recipe.image} alt={recipe.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500 saturate-[1.1]" />
                             </div>
                           )}
                         </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="text-center py-12 text-gray-500 bg-white rounded-2xl border-2 border-dashed border-gray-100 mb-8">
                     <p className="font-medium">本地暂无 "{searchTerm}" 的食谱</p>
                  </div>
                )}

                {/* AI Search Section */}
                <div className="border-t pt-8">
                  <h2 className="text-lg font-bold text-gray-800 mb-4 flex items-center">
                    <Sparkles className="w-5 h-5 mr-2 text-indigo-500" />
                    AI 智能推荐
                  </h2>

                  {aiSearchResults.length === 0 ? (
                    <div className="bg-indigo-50/80 rounded-2xl p-8 text-center border border-indigo-100">
                      <p className="text-indigo-900 mb-4 font-bold text-lg">
                        {localSearchResults.length === 0 
                          ? `没找到"${searchTerm}"？让 AI 帮您生成菜谱。`
                          : `想看看更多关于"${searchTerm}"的做法？`
                        }
                      </p>
                      <button
                        onClick={() => handleGlobalAiSearch()}
                        disabled={isSuggesting}
                        className="inline-flex items-center px-6 py-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 hover:shadow-lg hover:scale-105 transition-all shadow-md disabled:opacity-50 font-bold"
                      >
                        {isSuggesting ? <Loader2 className="w-5 h-5 mr-2 animate-spin" /> : <ChefHat className="w-5 h-5 mr-2" />}
                        AI 搜索 / 生成 "{searchTerm}"
                      </button>
                    </div>
                  ) : (
                    <div className="space-y-4">
                      <p className="text-sm text-gray-500">点击下方卡片即可查看详情并添加到食谱本：</p>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                        {aiSearchResults.map((aiRecipe, idx) => (
                          <div 
                            key={idx}
                            onClick={() => handleAddAiRecipe(aiRecipe)}
                            className="group bg-white p-5 rounded-2xl shadow-sm hover:shadow-xl hover:scale-[1.02] border border-indigo-50 transition-all duration-300 cursor-pointer relative overflow-hidden"
                          >
                            <div className="absolute top-0 right-0 bg-indigo-500 text-white text-xs font-bold px-3 py-1.5 rounded-bl-xl shadow-sm z-10">AI 推荐</div>
                            <h3 className="font-extrabold text-gray-900 text-lg mb-1 group-hover:text-indigo-700 transition-colors">{aiRecipe.name}</h3>
                            <p className="text-sm text-gray-600 line-clamp-2 mt-1 leading-relaxed">{aiRecipe.description}</p>

                            <div className="mt-4 flex items-center text-indigo-600 text-xs font-bold opacity-0 group-hover:opacity-100 transition-all translate-y-2 group-hover:translate-y-0">
                              <Plus className="w-4 h-4 mr-1" />
                              点击添加到我的食谱
                            </div>
                          </div>
                        ))}
                      </div>
                      <button 
                        onClick={() => setAiSearchResults([])}
                        className="text-sm text-gray-400 hover:text-gray-600 mt-4 underline block mx-auto"
                      >
                        清空 AI 推荐结果
                      </button>
                    </div>
                  )}
                </div>
              </div>
            )}

            {/* Floating Action Button */}
            <SeasonalRecommendation onSearch={(term) => setSearchTerm(term)} />
          </div>
        );

      case 'ADD_CATEGORY':
        return (
          <CategoryForm 
            onSave={handleSaveCategory}
            onCancel={() => navigateToHome()}
          />
        );

      case 'CATEGORY':
        const category = categories.find(c => c.id === viewState.categoryId);
        if (!category) return <div>Category not found</div>;

        const filteredRecipes = recipes.filter(r => {
           if (r.categoryId !== category.id) return false;
           const term = searchTerm.toLowerCase();
           return (
             r.name.toLowerCase().includes(term) ||
             r.description.toLowerCase().includes(term) ||
             r.ingredients.some(ing => ing.toLowerCase().includes(term))
           );
        });

        // SORTING: Favorites first, then by views desc
        const sortedRecipes = sortRecipes(filteredRecipes);

        return (
          <div className="p-4 sm:p-6 min-h-screen">
            {/* Floating Back Button using Fixed Positioning */}
            <div className="fixed top-24 left-6 z-50">
              <button 
                onClick={() => navigateToHome()}
                className="flex items-center justify-center w-12 h-12 bg-white/90 backdrop-blur-md rounded-full shadow-2xl border border-white/50 text-gray-700 hover:text-orange-600 hover:scale-110 transition-all duration-300"
                title="返回首页"
              >
                <ArrowLeft className="w-6 h-6" />
              </button>
            </div>

            {/* Top Action Bar (Non-floating part) */}
            <div className="flex justify-end gap-3 mb-6">
                <button 
                  onClick={() => setIsRecModalOpen(true)}
                  className="flex items-center px-4 py-2 bg-indigo-50 text-indigo-700 rounded-xl hover:bg-indigo-100 hover:scale-105 transition-all shadow-sm text-sm font-bold"
                >
                   <BookOpen className="w-4 h-4 mr-2" />
                   灵感菜单
                </button>
                <button
                  onClick={() => setViewState({ type: 'ADD_RECIPE', categoryId: category.id })}
                  className="flex items-center px-4 py-2 bg-orange-600 text-white rounded-xl hover:bg-orange-700 hover:scale-105 transition-all shadow-lg text-sm font-bold hover:shadow-orange-500/30"
                >
                  <Plus className="w-4 h-4 mr-2" />
                  添加食谱
                </button>
            </div>

            <div className="flex items-center gap-4 mb-8">
               <div className={`p-4 rounded-3xl ${category.color} bg-opacity-20 shadow-sm`}>
                 {getIconComponent(category.icon, "w-10 h-10")}
               </div>
               <div>
                 <h2 className="text-3xl font-extrabold text-gray-900 tracking-tight">{category.name}</h2>
                 <p className="text-gray-500 font-medium mt-1">{getCategoryDescription(category)}</p>
               </div>
            </div>

            {/* Recipe Search Bar */}
            <div className="mb-8 relative">
               <input 
                 type="text" 
                 placeholder={`在 ${category.name} 中搜索食谱...`}
                 value={searchTerm}
                 onChange={e => setSearchTerm(e.target.value)}
                 className="w-full pl-12 pr-4 py-3.5 rounded-2xl border-gray-200 shadow-sm focus:ring-2 focus:ring-orange-500 focus:border-transparent transition-all outline-none text-lg"
               />
               <Search className="absolute left-4 top-4 text-gray-400 w-6 h-6" />
            </div>

            {sortedRecipes.length === 0 ? (
              <div className="text-center py-20 bg-white rounded-3xl border-2 border-dashed border-gray-200">
                {searchTerm ? (
                  <>
                    <div className="mx-auto w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mb-4">
                      <Search className="w-8 h-8 text-gray-400" />
                    </div>
                    <h3 className="text-lg font-bold text-gray-900">未找到相关食谱</h3>
                    <p className="mt-2 text-gray-500">换个关键词试试？</p>
                  </>
                ) : (
                  <>
                    <div className="mx-auto w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mb-6 shadow-inner">
                      <Plus className="w-10 h-10 text-gray-300" />
                    </div>
                    <h3 className="text-xl font-bold text-gray-900">暂无食谱</h3>
                    <p className="mt-2 text-gray-500 mb-6">您可以手动添加，或使用“灵感菜单”获取推荐。</p>
                    <button 
                      onClick={() => setIsRecModalOpen(true)}
                      className="inline-flex items-center px-6 py-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 hover:shadow-lg hover:scale-105 transition-all shadow-md font-bold"
                    >
                      <Sparkles className="w-5 h-5 mr-2" />
                      打开灵感菜单
                    </button>
                  </>
                )}
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                {sortedRecipes.map(recipe => (
                  <div 
                    key={recipe.id}
                    onClick={() => navigateToRecipe(recipe)}
                    className={`group bg-white p-5 rounded-2xl shadow-sm hover:shadow-2xl hover:scale-[1.02] transition-all duration-300 cursor-pointer border relative overflow-hidden ${recipe.isFavorite ? 'border-yellow-200 bg-yellow-50/20' : 'border-gray-100'}`}
                  >
                    {/* Recipe Action Buttons on List View */}
                    <div className="absolute top-3 right-3 flex space-x-2 opacity-0 group-hover:opacity-100 transition-all duration-300 translate-y-[-10px] group-hover:translate-y-0 z-10 bg-white/90 rounded-full p-1.5 shadow-md backdrop-blur-sm">
                      <button
                        onClick={(e) => { 
                            e.preventDefault();
                            e.stopPropagation(); 
                            setViewState({ type: 'EDIT_RECIPE', recipeId: recipe.id }); 
                        }}
                        className="p-2 text-gray-500 hover:text-blue-600 hover:bg-blue-50 rounded-full transition-colors"
                        title="编辑"
                      >
                        <Pencil className="w-4 h-4" />
                      </button>
                      <button
                        onClick={(e) => { 
                            e.preventDefault();
                            e.stopPropagation(); 
                            handleDeleteRecipe(recipe.id, category.id); 
                        }}
                        className="p-2 text-gray-500 hover:text-red-600 hover:bg-red-50 rounded-full transition-colors"
                        title="删除"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>

                    <div className="flex gap-5">
                      <div className="flex-1 min-w-0 flex flex-col justify-center">
                        <div className="flex items-center gap-2 mb-2">
                            {/* Difficulty Dot */}
                           <span className={`w-2 h-2 rounded-full flex-shrink-0 ${
                             recipe.difficulty === 'Easy' ? 'bg-green-500' :
                             recipe.difficulty === 'Medium' ? 'bg-yellow-500' :
                             'bg-red-500'
                           }`}></span>
                           <h3 className="font-extrabold text-xl text-gray-900 truncate">{recipe.name}</h3>
                           {recipe.isFavorite && (
                             <Star className="w-5 h-5 text-yellow-400 fill-current flex-shrink-0" />
                           )}
                        </div>

                        <p className="text-gray-600 text-sm line-clamp-2 mb-3 leading-relaxed">
                          {recipe.description || recipe.instructions[0]}
                        </p>

                        <div className="flex items-center gap-4 text-xs font-medium text-gray-500">
                           <div className="flex items-center gap-1.5 bg-gray-100 px-2 py-1 rounded-md">
                             <Clock className="w-3.5 h-3.5"/> 
                             <span>{recipe.cookingTime}</span>
                           </div>
                           <div className="flex items-center gap-1.5">
                             <Eye className="w-3.5 h-3.5"/> 
                             <span>{recipe.views || 0}</span>
                           </div>
                        </div>
                      </div>

                      {recipe.image && (
                         <div className="w-28 h-28 flex-shrink-0 rounded-2xl overflow-hidden shadow-sm border border-gray-100">
                           <img src={recipe.image} alt={recipe.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500 saturate-[1.1]" />
                         </div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            )}

            {/* Recommendation Modal */}
            {isRecModalOpen && (
              <RecommendationModal 
                categoryName={category.name}
                existingRecipes={recipes.filter(r => r.categoryId === category.id)}
                onClose={() => setIsRecModalOpen(false)}
                onAddRecipe={(name) => handleQuickAddRecipe(name, category.id, category.name)}
              />
            )}
          </div>
        );

      case 'ADD_RECIPE':
        const addCategory = categories.find(c => c.id === viewState.categoryId);
        return (
          <RecipeForm
            categoryId={viewState.categoryId}
            categoryName={addCategory?.name || ''}
            onSave={handleSaveRecipe}
            onCancel={() => setViewState({ type: 'CATEGORY', categoryId: viewState.categoryId })}
          />
        );

      case 'EDIT_RECIPE':
        const editRecipe = recipes.find(r => r.id === viewState.recipeId);
        if (!editRecipe) return <div>Recipe not found</div>;
        const editCategory = categories.find(c => c.id === editRecipe.categoryId);

        return (
          <RecipeForm
            categoryId={editRecipe.categoryId}
            categoryName={editCategory?.name || ''}
            initialData={editRecipe}
            onSave={handleSaveRecipe}
            onCancel={() => setViewState({ type: 'RECIPE_DETAIL', recipeId: editRecipe.id })}
          />
        );

      case 'RECIPE_DETAIL':
        const recipe = recipes.find(r => r.id === viewState.recipeId);
        if (!recipe) return <div>Recipe not found</div>;
        return (
          <RecipeDetail
            recipe={recipe}
            onBack={() => setViewState({ type: 'CATEGORY', categoryId: recipe.categoryId })}
            onEdit={() => setViewState({ type: 'EDIT_RECIPE', recipeId: recipe.id })}
            onDelete={() => handleDeleteRecipe(recipe.id, recipe.categoryId)}
            onToggleFavorite={() => handleToggleFavorite(recipe.id)}
          />
        );

      default:
        return <div>Unknown view</div>;
    }
  };

  return (
    <Layout 
      onHomeClick={() => navigateToHome()}
      user={user}
      onLoginClick={() => setShowLogin(true)}
      onProfileClick={() => setShowProfile(true)}
    >
      {renderContent()}

      {showLogin && (
        <LoginModal 
          onLogin={handleLoginSuccess}
          onClose={() => setShowLogin(false)}
        />
      )}

      {showProfile && user && (
        <UserProfile 
          user={user}
          onSave={handleUpdateProfile}
          onLogout={handleLogout}
          onClose={() => setShowProfile(false)}
        />
      )}

      {isFridgeModalOpen && (
        <FridgeModal 
            onClose={() => setIsFridgeModalOpen(false)}
            onAddRecipe={handleAddAiRecipe}
            userPrefs={user?.preferences}
        />
      )}
    </Layout>
  );
}

import React, { useMemo, useState } from 'react';
import { Recipe, CategoryIdEnum } from '../types';
import { Sun, Moon, Sunset, Sunrise, Utensils, ChefHat, Coffee, RefreshCw } from 'lucide-react';

interface DailyMealRecommendationProps {
  recipes: Recipe[];
  onRecipeClick: (recipe: Recipe) => void;
  onSearchClick: (term: string) => void;
}

type MealPeriod = 'breakfast' | 'lunch' | 'dinner' | 'latenight';
type BreakfastStyle = 'chinese' | 'western';

interface RecommendationSlot {
  label: string;
  categoryIds: string[]; // Valid categories for this slot
  fallbackDish: string;  // What to show if no local recipe exists
}

export const DailyMealRecommendation: React.FC<DailyMealRecommendationProps> = ({ 
  recipes, 
  onRecipeClick, 
  onSearchClick 
}) => {
  const [breakfastStyle, setBreakfastStyle] = useState<BreakfastStyle>('chinese');
  const [seed, setSeed] = useState(0); // Used to trigger re-randomization

  const timeData = useMemo(() => {
    const hour = new Date().getHours();
    let period: MealPeriod;
    let title = '';
    let subtitle = '';
    let icon: React.ReactNode;
    let bgGradient = '';

    if (hour >= 6 && hour < 10) {
      period = 'breakfast';
      title = '元气早餐';
      subtitle = '一日之计在于晨';
      icon = <Sunrise className="w-6 h-6 text-orange-500" />;
      bgGradient = 'from-orange-50 to-yellow-50 border-orange-100';
    } else if (hour >= 10 && hour < 15) {
      period = 'lunch';
      title = '丰盛午餐';
      subtitle = '荤素搭配，营养均衡';
      icon = <Sun className="w-6 h-6 text-red-500" />;
      bgGradient = 'from-red-50 to-orange-50 border-red-100';
    } else if (hour >= 15 && hour < 21) {
      period = 'dinner';
      title = '温馨晚餐';
      subtitle = '四菜一汤，抚慰人心';
      icon = <Sunset className="w-6 h-6 text-indigo-500" />;
      bgGradient = 'from-indigo-50 to-purple-50 border-indigo-100';
    } else {
      period = 'latenight';
      title = '深夜食堂';
      subtitle = '快乐夜宵，灵魂伴侣';
      icon = <Moon className="w-6 h-6 text-blue-500" />;
      bgGradient = 'from-slate-50 to-blue-50 border-slate-200';
    }

    return { period, title, subtitle, icon, bgGradient };
  }, []);

  // Define the structure of the meal based on the period
  const mealSlots = useMemo((): RecommendationSlot[] => {
    switch (timeData.period) {
      case 'breakfast':
        if (breakfastStyle === 'chinese') {
          return [
            { label: '主食', categoryIds: [CategoryIdEnum.STAPLE], fallbackDish: '肉包子' },
            { label: '汤粥', categoryIds: [CategoryIdEnum.SOUP, CategoryIdEnum.DRINK], fallbackDish: '小米粥' },
            { label: '搭配', categoryIds: [CategoryIdEnum.SNACK, CategoryIdEnum.STAPLE], fallbackDish: '油条' },
            { label: '佐餐', categoryIds: [CategoryIdEnum.SNACK, CategoryIdEnum.VEGETABLE], fallbackDish: '豆腐脑' },
          ];
        } else {
          return [
            { label: '主食', categoryIds: [CategoryIdEnum.STAPLE], fallbackDish: '培根三明治' },
            { label: '饮品', categoryIds: [CategoryIdEnum.DRINK], fallbackDish: '热牛奶' },
            { label: '烘焙', categoryIds: [CategoryIdEnum.SNACK, CategoryIdEnum.DESSERT], fallbackDish: '恰巴塔' },
            { label: '搭配', categoryIds: [CategoryIdEnum.SNACK, CategoryIdEnum.MEAT], fallbackDish: '煎蛋香肠' },
          ];
        }

      case 'lunch':
      case 'dinner':
        return [
          { label: '荤菜', categoryIds: [CategoryIdEnum.MEAT], fallbackDish: timeData.period === 'lunch' ? '宫保鸡丁' : '清蒸鲈鱼' },
          { label: '素菜', categoryIds: [CategoryIdEnum.VEGETABLE], fallbackDish: '清炒时蔬' },
          { label: '汤类', categoryIds: [CategoryIdEnum.SOUP], fallbackDish: timeData.period === 'lunch' ? '番茄蛋汤' : '玉米排骨汤' },
          { label: '主食', categoryIds: [CategoryIdEnum.STAPLE], fallbackDish: '米饭' },
        ];

      case 'latenight':
        return [
          { label: '快乐水', categoryIds: [CategoryIdEnum.DRINK], fallbackDish: '冰可乐' },
          { label: '炸物', categoryIds: [CategoryIdEnum.SNACK], fallbackDish: '韩式炸鸡' },
          { label: '速食', categoryIds: [CategoryIdEnum.SNACK, CategoryIdEnum.STAPLE], fallbackDish: '火鸡面' },
          { label: '解馋', categoryIds: [CategoryIdEnum.SNACK], fallbackDish: '烤冷面' },
        ];

      default:
        return [];
    }
  }, [timeData.period, breakfastStyle]);

  // Fill the slots with actual recipes or fallback placeholders
  const displayItems = useMemo(() => {
    // Helper to pick a random item from array based on seed
    function pickRandom<T>(arr: T[]): T | null {
      if (arr.length === 0) return null;
      // Simple pseudo-random using seed + array length
      const index = (seed + Math.floor(Math.random() * 100)) % arr.length;
      return arr[index];
    }

    // Keep track of used recipes to avoid duplicates in one meal
    const usedRecipeIds = new Set<string>();

    return mealSlots.map(slot => {
      // Find local recipes that match this slot's allowed categories
      const candidates = recipes.filter(r => 
        slot.categoryIds.includes(r.categoryId) && !usedRecipeIds.has(r.id)
      );

      const picked = pickRandom(candidates);

      if (picked) {
        usedRecipeIds.add(picked.id);
        return { type: 'local', data: picked, label: slot.label };
      } else {
        return { type: 'fallback', name: slot.fallbackDish, label: slot.label };
      }
    });
  }, [mealSlots, recipes, seed]);

  const handleRefresh = () => {
    setSeed(prev => prev + 1);
  };

  return (
    <div className={`mb-8 rounded-3xl border p-6 shadow-sm bg-gradient-to-br ${timeData.bgGradient} relative overflow-hidden transition-all duration-300 hover:shadow-lg`}>
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between mb-6 gap-3">
        <div className="flex items-center gap-3">
          <div className="p-2.5 bg-white rounded-2xl shadow-sm">
            {timeData.icon}
          </div>
          <div>
            <h3 className="font-extrabold text-gray-900 text-xl flex items-center gap-2">
              {timeData.title}
              <span className="text-xs font-bold text-gray-500 bg-white/60 px-2 py-0.5 rounded-full border border-white/20">
                {new Date().getHours()}:00 - {(new Date().getHours() + 1) % 24}:00
              </span>
            </h3>
            <p className="text-sm font-medium text-gray-600 opacity-80">{timeData.subtitle}</p>
          </div>
        </div>

        <div className="flex items-center gap-2 self-end sm:self-auto">
          {timeData.period === 'breakfast' && (
            <div className="flex bg-white/60 p-1 rounded-xl border border-gray-100 mr-2 shadow-sm">
              <button
                onClick={() => setBreakfastStyle('chinese')}
                className={`px-3 py-1.5 text-xs font-bold rounded-lg transition-all ${
                  breakfastStyle === 'chinese' ? 'bg-orange-500 text-white shadow-md' : 'text-gray-500 hover:bg-white'
                }`}
              >
                中式
              </button>
              <button
                onClick={() => setBreakfastStyle('western')}
                className={`px-3 py-1.5 text-xs font-bold rounded-lg transition-all ${
                  breakfastStyle === 'western' ? 'bg-orange-500 text-white shadow-md' : 'text-gray-500 hover:bg-white'
                }`}
              >
                西式
              </button>
            </div>
          )}

          <button 
            onClick={handleRefresh}
            className="p-2 bg-white/80 hover:bg-white text-gray-500 hover:text-orange-600 rounded-full transition-all shadow-sm hover:rotate-180 duration-500"
            title="换一换"
          >
            <RefreshCw className="w-4 h-4" />
          </button>
        </div>
      </div>

      {/* Grid */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
        {displayItems.map((item, idx) => {
           if (item.type === 'local' && item.data) {
             const recipe = item.data;
             return (
               <div 
                 key={`rec-${idx}`}
                 onClick={() => onRecipeClick(recipe)}
                 className="bg-white p-3 rounded-2xl shadow-sm border border-white/50 hover:border-orange-200 cursor-pointer transition-all hover:shadow-xl hover:scale-[1.03] flex flex-col h-full group duration-300"
               >
                 <div className="text-[10px] font-extrabold text-orange-600 mb-2 flex items-center bg-orange-50 w-fit px-2 py-0.5 rounded-full">
                    {item.label}
                 </div>
                 {recipe.image ? (
                   <div className="w-full aspect-[4/3] rounded-xl bg-gray-100 overflow-hidden mb-3 shadow-inner">
                      <img src={recipe.image} alt={recipe.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700 saturate-[1.1]" />
                   </div>
                 ) : (
                   <div className="w-full aspect-[4/3] rounded-xl bg-orange-50/50 flex items-center justify-center mb-3 text-3xl">
                      🥘
                   </div>
                 )}
                 <div className="mt-auto">
                   <h4 className="font-bold text-gray-800 text-sm truncate mb-1">{recipe.name}</h4>
                   <div className="flex items-center gap-1.5">
                      <Utensils className="w-3 h-3 text-gray-400" />
                      <span className="text-xs font-medium text-gray-500 truncate">{recipe.cookingTime}</span>
                   </div>
                 </div>
               </div>
             );
           } else {
             return (
               <div 
                 key={`fallback-${idx}`}
                 onClick={() => onSearchClick(item.name || '')}
                 className="bg-white/40 p-3 rounded-2xl border-2 border-dashed border-gray-300/60 hover:border-orange-400 hover:bg-white cursor-pointer transition-all hover:shadow-lg hover:scale-[1.03] flex flex-col h-full min-h-[140px] relative group duration-300"
               >
                  <div className="text-[10px] font-bold text-gray-400 mb-2 flex items-center w-fit px-2 py-0.5 rounded-full">
                    {item.label}
                 </div>
                 <div className="flex-1 flex flex-col items-center justify-center text-center">
                    <div className="w-12 h-12 bg-white rounded-full shadow-sm flex items-center justify-center mb-2 text-orange-400 group-hover:text-orange-500 group-hover:scale-110 group-hover:rotate-12 transition-all duration-300">
                        {timeData.period === 'latenight' ? <Utensils className="w-6 h-6" /> : 
                         timeData.period === 'breakfast' && breakfastStyle === 'western' ? <Coffee className="w-6 h-6" /> :
                         <ChefHat className="w-6 h-6" />}
                    </div>
                    <h4 className="font-bold text-gray-700 text-sm">{item.name}</h4>
                    <p className="text-[10px] font-bold text-orange-500 mt-2 opacity-0 translate-y-2 group-hover:opacity-100 group-hover:translate-y-0 transition-all duration-300">
                        点击生成食谱
                    </p>
                 </div>
               </div>
             );
           }
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Layout } from './components/Layout';
import { CategoryCard } from './components/CategoryCard';
import { RecipeForm } from './components/RecipeForm';
import { RecipeDetail } from './components/RecipeDetail';
import { CategoryForm } from './components/CategoryForm';
import { LoginModal } from './components/LoginModal';
import { UserProfile } from './components/UserProfile';
import { DailyMealRecommendation } from './components/DailyMealRecommendation';
import { FridgeModal } from './components/FridgeModal';
import { Category, CategoryId, Recipe, ViewState, User, UserPreferences } from './types';
import { DEFAULT_CATEGORIES, getIconComponent } from './constants';
import { Plus, ArrowLeft, Loader2, Search, Pencil, Trash2, Sparkles, ChefHat, BookOpen, Eye, Star, Clock, Refrigerator } from 'lucide-react';
import { suggestRandomRecipe, generateRecipeWithAI, searchRecipesWithAI } from './services/geminiService';
import { INITIAL_RECIPES } from './seedData';
import { SeasonalRecommendation } from './components/SeasonalRecommendation';
import { RecommendationModal } from './components/RecommendationModal';

export default function App() {
  const [categories, setCategories] = useState<Category[]>([]);
  const [recipes, setRecipes] = useState<Recipe[]>([]);
  const [viewState, setViewState] = useState<ViewState>({ type: 'HOME' });
  const [searchTerm, setSearchTerm] = useState('');
  const [isSuggesting, setIsSuggesting] = useState(false);
  const [aiSearchResults, setAiSearchResults] = useState<Partial<Recipe>[]>([]);
  const [isRecModalOpen, setIsRecModalOpen] = useState(false);
  const [isFridgeModalOpen, setIsFridgeModalOpen] = useState(false);

  // User State
  const [user, setUser] = useState<User | null>(null);
  const [showLogin, setShowLogin] = useState(false);
  const [showProfile, setShowProfile] = useState(false);

  // --- Data Loading Logic ---

  // Helper to get storage keys based on user
  const getStorageKeys = (currentUser: User | null) => {
    const suffix = currentUser ? `_${currentUser.phoneNumber}` : '_guest';
    return {
      recipes: `smart-recipe-book-data${suffix}`,
      categories: `smart-recipe-book-categories${suffix}`,
    };
  };

  const loadDataForUser = useCallback((currentUser: User | null) => {
    const keys = getStorageKeys(currentUser);

    // Load Recipes
    const savedRecipes = localStorage.getItem(keys.recipes);
    if (savedRecipes) {
      try {
        const parsed = JSON.parse(savedRecipes);
        const migrated = parsed.map((r: any) => ({ 
          ...r, 
          views: r.views || 0,
          isFavorite: r.isFavorite || (r.likes > 0) || false 
        }));
        setRecipes(migrated);
      } catch (e) {
        console.error("Failed to load recipes", e);
        setRecipes(INITIAL_RECIPES);
      }
    } else {
      // Always initialize with seed data for new users or guests
      setRecipes(INITIAL_RECIPES);
    }

    // Load Categories
    const savedCategories = localStorage.getItem(keys.categories);
    if (savedCategories) {
      try {
        setCategories(JSON.parse(savedCategories));
      } catch (e) {
        setCategories(DEFAULT_CATEGORIES);
      }
    } else {
      setCategories(DEFAULT_CATEGORIES);
    }
  }, []);

  // Initial Load (Check for active session)
  useEffect(() => {
    const activeUserJson = localStorage.getItem('active_user_session');
    let activeUser: User | null = null;
    if (activeUserJson) {
      try {
        activeUser = JSON.parse(activeUserJson);
        setUser(activeUser);
      } catch (e) {
        localStorage.removeItem('active_user_session');
      }
    }
    loadDataForUser(activeUser);
  }, [loadDataForUser]);

  // Persistence (Whenever data or user changes)
  useEffect(() => {
    const keys = getStorageKeys(user);
    if (recipes.length > 0 || user) { // Only save if data exists or user is logged in (to save empty state)
        localStorage.setItem(keys.recipes, JSON.stringify(recipes));
    }
  }, [recipes, user]);

  useEffect(() => {
    const keys = getStorageKeys(user);
    if (categories.length > 0) {
        localStorage.setItem(keys.categories, JSON.stringify(categories));
    }
  }, [categories, user]);

  // --- User Actions ---

  const handleLoginSuccess = (userData: User) => {
    setUser(userData);
    localStorage.setItem('active_user_session', JSON.stringify(userData));
    setShowLogin(false);

    // Switch data context
    loadDataForUser(userData);
    setViewState({ type: 'HOME' });
    setSearchTerm('');
  };

  const handleLogout = () => {
    localStorage.removeItem('active_user_session');
    setUser(null);
    setShowProfile(false);
    // Revert to guest data
    loadDataForUser(null);
    setViewState({ type: 'HOME' });
    setSearchTerm('');
  };

  const handleUpdateProfile = (name: string, prefs: UserPreferences) => {
    if (!user) return;
    const updatedUser = { ...user, name, preferences: prefs };
    setUser(updatedUser);
    localStorage.setItem('active_user_session', JSON.stringify(updatedUser));
    localStorage.setItem(`user_profile_${user.phoneNumber}`, JSON.stringify(updatedUser));
    setShowProfile(false);
  };

  // --- Navigation Helpers ---
  const navigateToHome = () => {
    setSearchTerm('');
    setAiSearchResults([]);
    setViewState({ type: 'HOME' });
    setIsRecModalOpen(false);
  };

  const navigateToCategory = (categoryId: CategoryId) => {
    setSearchTerm('');
    setAiSearchResults([]);
    setViewState({ type: 'CATEGORY', categoryId });
    setIsRecModalOpen(false);
  };

  const navigateToRecipe = (recipe: Recipe) => {
    // Increment view count
    const updatedRecipes = recipes.map(r => 
      r.id === recipe.id ? { ...r, views: (r.views || 0) + 1 } : r
    );
    setRecipes(updatedRecipes);
    setViewState({ type: 'RECIPE_DETAIL', recipeId: recipe.id });
  };

  // --- Dynamic Descriptions ---
  const getCategoryDescription = (category: Category) => {
    const catRecipes = recipes.filter(r => r.categoryId === category.id);
    if (catRecipes.length === 0) return category.description;

    // Sort by views desc
    const sorted = [...catRecipes].sort((a, b) => (b.views || 0) - (a.views || 0));
    const topNames = sorted.slice(0, 3).map(r => r.name).join('、');
    return `${topNames}${sorted.length > 3 ? '等...' : ''}`;
  };

  // --- Helper: Sort Recipes (Favorites First, Then Views) ---
  const sortRecipes = (list: Recipe[]) => {
    return [...list].sort((a, b) => {
      // 1. Favorites First
      const favA = a.isFavorite ? 1 : 0;
      const favB = b.isFavorite ? 1 : 0;
      if (favA !== favB) return favB - favA;

      // 2. Then by Views (High to Low)
      return (b.views || 0) - (a.views || 0);
    });
  };

  // --- Recipe Actions ---

  const handleSaveRecipe = (newRecipeData: Omit<Recipe, 'id' | 'createdAt'>) => {
    if (viewState.type === 'EDIT_RECIPE') {
      const updatedRecipes = recipes.map(r => 
        r.id === viewState.recipeId ? { ...r, ...newRecipeData } : r
      );
      setRecipes(updatedRecipes);
      setViewState({ type: 'RECIPE_DETAIL', recipeId: viewState.recipeId });
    } else {
      const newRecipe: Recipe = {
        ...newRecipeData,
        id: crypto.randomUUID(),
        createdAt: Date.now(),
        views: 0,
        isFavorite: false
      };
      setRecipes(prev => [...prev, newRecipe]);
      navigateToCategory(newRecipeData.categoryId);
    }
  };

  const handleToggleFavorite = (recipeId: string) => {
    setRecipes(prev => prev.map(r => {
      if (r.id === recipeId) {
        return { ...r, isFavorite: !r.isFavorite };
      }
      return r;
    }));
  };

  const handleAddAiRecipe = (aiRecipe: Partial<Recipe>) => {
    if (!aiRecipe.name) return;

    // Auto-detect category or default to 'Meat' if unknown
    // Ensure we have at least one category to assign
    let targetCatId = categories[0]?.id || DEFAULT_CATEGORIES[0].id;

    const newRecipe: Recipe = {
      id: crypto.randomUUID(),
      categoryId: targetCatId,
      name: aiRecipe.name,
      description: aiRecipe.description || '',
      ingredients: aiRecipe.ingredients || [],
      instructions: aiRecipe.instructions || [],
      cookingTime: aiRecipe.cookingTime || '30 mins',
      difficulty: (aiRecipe.difficulty as any) || 'Medium',
      createdAt: Date.now(),
      views: 1, // Start with 1 view
      isFavorite: false
    };

    setRecipes(prev => [...prev, newRecipe]);
    setIsFridgeModalOpen(false); 
    // Directly set view state to avoid race condition in navigateToRecipe
    setViewState({ type: 'RECIPE_DETAIL', recipeId: newRecipe.id });
  };

  const handleDeleteRecipe = (recipeId: string, categoryId: CategoryId) => {
    if (window.confirm('确定要删除这道菜谱吗？')) {
      setRecipes(prev => prev.filter(r => r.id !== recipeId));
      // Return to category or home depending on where we came from
      setViewState({ type: 'CATEGORY', categoryId });
    }
  };

  const handleGlobalAiSearch = async (initialTerm?: string) => {
    const term = initialTerm || searchTerm;
    if (!term.trim()) return;

    // If called with a specific term (like from daily rec), update search input
    if (initialTerm) {
        setSearchTerm(initialTerm);
    }

    setIsSuggesting(true);
    try {
      const results = await searchRecipesWithAI(term, user?.preferences);
      setAiSearchResults(results);
    } catch (e) {
      alert("AI 搜索失败，请重试");
    } finally {
      setIsSuggesting(false);
    }
  };

  // Handle Quick Add from Recommendation Modal
  const handleQuickAddRecipe = async (dishName: string, categoryId: CategoryId, categoryName: string) => {
    const aiRecipe = await generateRecipeWithAI(dishName, categoryName, user?.preferences);
    if (!aiRecipe.name) throw new Error("Failed to generate");

    const newRecipe: Recipe = {
      id: crypto.randomUUID(),
      categoryId,
      name: aiRecipe.name,
      description: aiRecipe.description || '',
      ingredients: aiRecipe.ingredients || [],
      instructions: aiRecipe.instructions || [],
      cookingTime: aiRecipe.cookingTime || '30 mins',
      difficulty: (aiRecipe.difficulty as any) || 'Medium',
      createdAt: Date.now(),
      views: 0,
      isFavorite: false
    };
    setRecipes(prev => [...prev, newRecipe]);
  };

  // --- Category Actions ---

  const handleSaveCategory = (categoryData: Omit<Category, 'id'>) => {
    const newCategory: Category = {
      ...categoryData,
      id: `custom-${crypto.randomUUID()}`,
    };
    setCategories(prev => [...prev, newCategory]);
    navigateToHome();
  };


  const renderContent = () => {
    switch (viewState.type) {
      case 'HOME':
        const isSearching = searchTerm.trim().length > 0;

        const filteredCategories = categories.filter(c => 
          c.name.includes(searchTerm) || c.description.includes(searchTerm)
        );

        let localSearchResults = isSearching ? recipes.filter(r => {
           const term = searchTerm.toLowerCase();
           return (
             r.name.toLowerCase().includes(term) ||
             r.ingredients.some(ing => ing.toLowerCase().includes(term))
           );
        }) : [];

        if (isSearching && localSearchResults.length > 0) {
            localSearchResults = sortRecipes(localSearchResults);
        }

        return (
          <div className="p-4 sm:p-6 pb-24">
            {/* Persistent Search Bar */}
            <div className="mb-6 flex gap-2">
               <div className="relative flex-1">
                 <input 
                   type="text" 
                   placeholder="输入菜名或食材（如：油菜、鸡翅）..." 
                   value={searchTerm}
                   onChange={e => {
                     setSearchTerm(e.target.value);
                     if (e.target.value === '') {
                       setAiSearchResults([]); 
                     }
                   }}
                   className="w-full pl-10 pr-4 py-3 rounded-2xl border-gray-200 shadow-sm focus:ring-2 focus:ring-orange-500 focus:border-transparent transition-all outline-none"
                 />
                 <Search className="absolute left-3 top-3.5 text-gray-400 w-5 h-5" />
               </div>
               {isSearching && (
                 <button onClick={navigateToHome} className="text-gray-500 px-2 hover:text-gray-800 font-medium">取消</button>
               )}
            </div>

            {!isSearching && (
                <div className="mb-6">
                    <button 
                        onClick={() => setIsFridgeModalOpen(true)}
                        className="w-full bg-gradient-to-r from-blue-500 to-indigo-600 text-white p-4 rounded-2xl shadow-lg hover:shadow-xl hover:scale-[1.01] transition-all flex items-center justify-between group"
                    >
                        <div className="flex items-center gap-3">
                            <div className="bg-white/20 p-2 rounded-xl">
                                <Refrigerator className="w-6 h-6 text-white" />
                            </div>
                            <div className="text-left">
                                <h3 className="font-bold text-lg">冰箱大搜救</h3>
                                <p className="text-xs text-blue-100 opacity-90">不知道吃什么？输入食材让 AI 帮您搭配！</p>
                            </div>
                        </div>
                        <ArrowLeft className="w-5 h-5 rotate-180 group-hover:translate-x-1 transition-transform" />
                    </button>
                </div>
            )}

            {!isSearching ? (
              <>
                {/* Daily Meal Recommendation (Only visible on Home when not searching) */}
                <DailyMealRecommendation 
                   recipes={recipes}
                   onRecipeClick={navigateToRecipe}
                   onSearchClick={(term) => handleGlobalAiSearch(term)}
                />

                {/* Categories View */}
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5">
                    {filteredCategories.map(category => (
                    <CategoryCard
                        key={category.id}
                        category={{...category, description: getCategoryDescription(category)}}
                        count={recipes.filter(r => r.categoryId === category.id).length}
                        onClick={() => navigateToCategory(category.id)}
                    />
                    ))}

                    <button 
                    onClick={() => setViewState({ type: 'ADD_CATEGORY' })}
                    className="flex flex-col items-center justify-center p-6 rounded-2xl bg-white border-2 border-dashed border-gray-300 hover:border-orange-500 hover:bg-orange-50 transition-all min-h-[160px] group hover:scale-[1.02] duration-300"
                    >
                    <div className="p-3 rounded-full bg-gray-100 group-hover:bg-orange-100 mb-3 transition-colors">
                        <Plus className="w-8 h-8 text-gray-400 group-hover:text-orange-500" />
                    </div>
                    <h3 className="text-lg font-bold text-gray-600 group-hover:text-orange-600">更多</h3>
                    <p className="text-sm text-gray-400">添加自定义分类</p>
                    </button>
                </div>
              </>
            ) : (
              // Search Results View
              <div>
                <h2 className="text-lg font-bold text-gray-800 mb-4 flex items-center">
                  <Search className="w-5 h-5 mr-2 text-orange-500" />
                  本地搜索结果 ({localSearchResults.length})
                </h2>

                {localSearchResults.length > 0 ? (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-5 mb-8">
                    {localSearchResults.map(recipe => (
                      <div 
                        key={recipe.id}
                        onClick={() => navigateToRecipe(recipe)}
                        className={`group bg-white p-4 rounded-2xl shadow-sm hover:shadow-xl hover:scale-[1.02] transition-all duration-300 cursor-pointer border relative overflow-hidden ${recipe.isFavorite ? 'border-yellow-200 bg-yellow-50/20' : 'border-gray-100'}`}
                      >
                         {/* Action Buttons for Search Results */}
                         <div className="absolute top-3 right-3 flex space-x-2 opacity-0 group-hover:opacity-100 transition-all duration-300 translate-y-[-10px] group-hover:translate-y-0 z-10 bg-white/90 rounded-full p-1.5 shadow-md backdrop-blur-sm">
                            <button
                                onClick={(e) => { 
                                    e.preventDefault();
                                    e.stopPropagation(); 
                                    setViewState({ type: 'EDIT_RECIPE', recipeId: recipe.id }); 
                                }}
                                className="p-2 text-gray-500 hover:text-blue-600 hover:bg-blue-50 rounded-full transition-colors"
                                title="编辑"
                            >
                                <Pencil className="w-4 h-4" />
                            </button>
                            <button
                                onClick={(e) => { 
                                    e.preventDefault();
                                    e.stopPropagation(); 
                                    handleDeleteRecipe(recipe.id, recipe.categoryId); 
                                }}
                                className="p-2 text-gray-500 hover:text-red-600 hover:bg-red-50 rounded-full transition-colors"
                                title="删除"
                            >
                                <Trash2 className="w-4 h-4" />
                            </button>
                         </div>

                         <div className="flex gap-5">
                           <div className="flex-1 min-w-0 flex flex-col justify-center">
                             <div className="flex items-center gap-2 mb-1">
                                <h3 className="font-extrabold text-xl text-gray-900 line-clamp-1">{recipe.name}</h3>
                                {recipe.isFavorite && <Star className="w-5 h-5 text-yellow-400 fill-current" />}
                             </div>
                             <p className="text-sm text-gray-600 line-clamp-1 mb-2">{recipe.description}</p>
                             <div className="flex items-center gap-3 text-xs">
                                 <span className="bg-orange-100 text-orange-700 px-2 py-0.5 rounded-md font-medium">{recipe.cookingTime}</span>
                                 <div className="flex items-center gap-1 text-gray-400">
                                    <Eye className="w-3.5 h-3.5"/> <span>{recipe.views || 0}</span>
                                 </div>
                             </div>
                           </div>
                           {recipe.image && (
                             <div className="w-24 h-24 flex-shrink-0 rounded-xl overflow-hidden shadow-sm">
                               <img src={recipe.image} alt={recipe.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500 saturate-[1.1]" />
                             </div>
                           )}
                         </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="text-center py-12 text-gray-500 bg-white rounded-2xl border-2 border-dashed border-gray-100 mb-8">
                     <p className="font-medium">本地暂无 "{searchTerm}" 的食谱</p>
                  </div>
                )}

                {/* AI Search Section */}
                <div className="border-t pt-8">
                  <h2 className="text-lg font-bold text-gray-800 mb-4 flex items-center">
                    <Sparkles className="w-5 h-5 mr-2 text-indigo-500" />
                    AI 智能推荐
                  </h2>

                  {aiSearchResults.length === 0 ? (
                    <div className="bg-indigo-50/80 rounded-2xl p-8 text-center border border-indigo-100">
                      <p className="text-indigo-900 mb-4 font-bold text-lg">
                        {localSearchResults.length === 0 
                          ? `没找到"${searchTerm}"？让 AI 帮您生成菜谱。`
                          : `想看看更多关于"${searchTerm}"的做法？`
                        }
                      </p>
                      <button
                        onClick={() => handleGlobalAiSearch()}
                        disabled={isSuggesting}
                        className="inline-flex items-center px-6 py-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 hover:shadow-lg hover:scale-105 transition-all shadow-md disabled:opacity-50 font-bold"
                      >
                        {isSuggesting ? <Loader2 className="w-5 h-5 mr-2 animate-spin" /> : <ChefHat className="w-5 h-5 mr-2" />}
                        AI 搜索 / 生成 "{searchTerm}"
                      </button>
                    </div>
                  ) : (
                    <div className="space-y-4">
                      <p className="text-sm text-gray-500">点击下方卡片即可查看详情并添加到食谱本：</p>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                        {aiSearchResults.map((aiRecipe, idx) => (
                          <div 
                            key={idx}
                            onClick={() => handleAddAiRecipe(aiRecipe)}
                            className="group bg-white p-5 rounded-2xl shadow-sm hover:shadow-xl hover:scale-[1.02] border border-indigo-50 transition-all duration-300 cursor-pointer relative overflow-hidden"
                          >
                            <div className="absolute top-0 right-0 bg-indigo-500 text-white text-xs font-bold px-3 py-1.5 rounded-bl-xl shadow-sm z-10">AI 推荐</div>
                            <h3 className="font-extrabold text-gray-900 text-lg mb-1 group-hover:text-indigo-700 transition-colors">{aiRecipe.name}</h3>
                            <p className="text-sm text-gray-600 line-clamp-2 mt-1 leading-relaxed">{aiRecipe.description}</p>

                            <div className="mt-4 flex items-center text-indigo-600 text-xs font-bold opacity-0 group-hover:opacity-100 transition-all translate-y-2 group-hover:translate-y-0">
                              <Plus className="w-4 h-4 mr-1" />
                              点击添加到我的食谱
                            </div>
                          </div>
                        ))}
                      </div>
                      <button 
                        onClick={() => setAiSearchResults([])}
                        className="text-sm text-gray-400 hover:text-gray-600 mt-4 underline block mx-auto"
                      >
                        清空 AI 推荐结果
                      </button>
                    </div>
                  )}
                </div>
              </div>
            )}

            {/* Floating Action Button */}
            <SeasonalRecommendation onSearch={(term) => setSearchTerm(term)} />
          </div>
        );

      case 'ADD_CATEGORY':
        return (
          <CategoryForm 
            onSave={handleSaveCategory}
            onCancel={() => navigateToHome()}
          />
        );

      case 'CATEGORY':
        const category = categories.find(c => c.id === viewState.categoryId);
        if (!category) return <div>Category not found</div>;

        const filteredRecipes = recipes.filter(r => {
           if (r.categoryId !== category.id) return false;
           const term = searchTerm.toLowerCase();
           return (
             r.name.toLowerCase().includes(term) ||
             r.description.toLowerCase().includes(term) ||
             r.ingredients.some(ing => ing.toLowerCase().includes(term))
           );
        });

        // SORTING: Favorites first, then by views desc
        const sortedRecipes = sortRecipes(filteredRecipes);

        return (
          <div className="p-4 sm:p-6 min-h-screen">
            {/* Floating Back Button using Fixed Positioning */}
            <div className="fixed top-24 left-6 z-50">
              <button 
                onClick={() => navigateToHome()}
                className="flex items-center justify-center w-12 h-12 bg-white/90 backdrop-blur-md rounded-full shadow-2xl border border-white/50 text-gray-700 hover:text-orange-600 hover:scale-110 transition-all duration-300"
                title="返回首页"
              >
                <ArrowLeft className="w-6 h-6" />
              </button>
            </div>

            {/* Top Action Bar (Non-floating part) */}
            <div className="flex justify-end gap-3 mb-6">
                <button 
                  onClick={() => setIsRecModalOpen(true)}
                  className="flex items-center px-4 py-2 bg-indigo-50 text-indigo-700 rounded-xl hover:bg-indigo-100 hover:scale-105 transition-all shadow-sm text-sm font-bold"
                >
                   <BookOpen className="w-4 h-4 mr-2" />
                   灵感菜单
                </button>
                <button
                  onClick={() => setViewState({ type: 'ADD_RECIPE', categoryId: category.id })}
                  className="flex items-center px-4 py-2 bg-orange-600 text-white rounded-xl hover:bg-orange-700 hover:scale-105 transition-all shadow-lg text-sm font-bold hover:shadow-orange-500/30"
                >
                  <Plus className="w-4 h-4 mr-2" />
                  添加食谱
                </button>
            </div>

            <div className="flex items-center gap-4 mb-8">
               <div className={`p-4 rounded-3xl ${category.color} bg-opacity-20 shadow-sm`}>
                 {getIconComponent(category.icon, "w-10 h-10")}
               </div>
               <div>
                 <h2 className="text-3xl font-extrabold text-gray-900 tracking-tight">{category.name}</h2>
                 <p className="text-gray-500 font-medium mt-1">{getCategoryDescription(category)}</p>
               </div>
            </div>

            {/* Recipe Search Bar */}
            <div className="mb-8 relative">
               <input 
                 type="text" 
                 placeholder={`在 ${category.name} 中搜索食谱...`}
                 value={searchTerm}
                 onChange={e => setSearchTerm(e.target.value)}
                 className="w-full pl-12 pr-4 py-3.5 rounded-2xl border-gray-200 shadow-sm focus:ring-2 focus:ring-orange-500 focus:border-transparent transition-all outline-none text-lg"
               />
               <Search className="absolute left-4 top-4 text-gray-400 w-6 h-6" />
            </div>

            {sortedRecipes.length === 0 ? (
              <div className="text-center py-20 bg-white rounded-3xl border-2 border-dashed border-gray-200">
                {searchTerm ? (
                  <>
                    <div className="mx-auto w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mb-4">
                      <Search className="w-8 h-8 text-gray-400" />
                    </div>
                    <h3 className="text-lg font-bold text-gray-900">未找到相关食谱</h3>
                    <p className="mt-2 text-gray-500">换个关键词试试？</p>
                  </>
                ) : (
                  <>
                    <div className="mx-auto w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mb-6 shadow-inner">
                      <Plus className="w-10 h-10 text-gray-300" />
                    </div>
                    <h3 className="text-xl font-bold text-gray-900">暂无食谱</h3>
                    <p className="mt-2 text-gray-500 mb-6">您可以手动添加，或使用“灵感菜单”获取推荐。</p>
                    <button 
                      onClick={() => setIsRecModalOpen(true)}
                      className="inline-flex items-center px-6 py-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 hover:shadow-lg hover:scale-105 transition-all shadow-md font-bold"
                    >
                      <Sparkles className="w-5 h-5 mr-2" />
                      打开灵感菜单
                    </button>
                  </>
                )}
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                {sortedRecipes.map(recipe => (
                  <div 
                    key={recipe.id}
                    onClick={() => navigateToRecipe(recipe)}
                    className={`group bg-white p-5 rounded-2xl shadow-sm hover:shadow-2xl hover:scale-[1.02] transition-all duration-300 cursor-pointer border relative overflow-hidden ${recipe.isFavorite ? 'border-yellow-200 bg-yellow-50/20' : 'border-gray-100'}`}
                  >
                    {/* Recipe Action Buttons on List View */}
                    <div className="absolute top-3 right-3 flex space-x-2 opacity-0 group-hover:opacity-100 transition-all duration-300 translate-y-[-10px] group-hover:translate-y-0 z-10 bg-white/90 rounded-full p-1.5 shadow-md backdrop-blur-sm">
                      <button
                        onClick={(e) => { 
                            e.preventDefault();
                            e.stopPropagation(); 
                            setViewState({ type: 'EDIT_RECIPE', recipeId: recipe.id }); 
                        }}
                        className="p-2 text-gray-500 hover:text-blue-600 hover:bg-blue-50 rounded-full transition-colors"
                        title="编辑"
                      >
                        <Pencil className="w-4 h-4" />
                      </button>
                      <button
                        onClick={(e) => { 
                            e.preventDefault();
                            e.stopPropagation(); 
                            handleDeleteRecipe(recipe.id, category.id); 
                        }}
                        className="p-2 text-gray-500 hover:text-red-600 hover:bg-red-50 rounded-full transition-colors"
                        title="删除"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>

                    <div className="flex gap-5">
                      <div className="flex-1 min-w-0 flex flex-col justify-center">
                        <div className="flex items-center gap-2 mb-2">
                            {/* Difficulty Dot */}
                           <span className={`w-2 h-2 rounded-full flex-shrink-0 ${
                             recipe.difficulty === 'Easy' ? 'bg-green-500' :
                             recipe.difficulty === 'Medium' ? 'bg-yellow-500' :
                             'bg-red-500'
                           }`}></span>
                           <h3 className="font-extrabold text-xl text-gray-900 truncate">{recipe.name}</h3>
                           {recipe.isFavorite && (
                             <Star className="w-5 h-5 text-yellow-400 fill-current flex-shrink-0" />
                           )}
                        </div>

                        <p className="text-gray-600 text-sm line-clamp-2 mb-3 leading-relaxed">
                          {recipe.description || recipe.instructions[0]}
                        </p>

                        <div className="flex items-center gap-4 text-xs font-medium text-gray-500">
                           <div className="flex items-center gap-1.5 bg-gray-100 px-2 py-1 rounded-md">
                             <Clock className="w-3.5 h-3.5"/> 
                             <span>{recipe.cookingTime}</span>
                           </div>
                           <div className="flex items-center gap-1.5">
                             <Eye className="w-3.5 h-3.5"/> 
                             <span>{recipe.views || 0}</span>
                           </div>
                        </div>
                      </div>

                      {recipe.image && (
                         <div className="w-28 h-28 flex-shrink-0 rounded-2xl overflow-hidden shadow-sm border border-gray-100">
                           <img src={recipe.image} alt={recipe.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500 saturate-[1.1]" />
                         </div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            )}

            {/* Recommendation Modal */}
            {isRecModalOpen && (
              <RecommendationModal 
                categoryName={category.name}
                existingRecipes={recipes.filter(r => r.categoryId === category.id)}
                onClose={() => setIsRecModalOpen(false)}
                onAddRecipe={(name) => handleQuickAddRecipe(name, category.id, category.name)}
              />
            )}
          </div>
        );

      case 'ADD_RECIPE':
        const addCategory = categories.find(c => c.id === viewState.categoryId);
        return (
          <RecipeForm
            categoryId={viewState.categoryId}
            categoryName={addCategory?.name || ''}
            onSave={handleSaveRecipe}
            onCancel={() => setViewState({ type: 'CATEGORY', categoryId: viewState.categoryId })}
          />
        );

      case 'EDIT_RECIPE':
        const editRecipe = recipes.find(r => r.id === viewState.recipeId);
        if (!editRecipe) return <div>Recipe not found</div>;
        const editCategory = categories.find(c => c.id === editRecipe.categoryId);

        return (
          <RecipeForm
            categoryId={editRecipe.categoryId}
            categoryName={editCategory?.name || ''}
            initialData={editRecipe}
            onSave={handleSaveRecipe}
            onCancel={() => setViewState({ type: 'RECIPE_DETAIL', recipeId: editRecipe.id })}
          />
        );

      case 'RECIPE_DETAIL':
        const recipe = recipes.find(r => r.id === viewState.recipeId);
        if (!recipe) return <div>Recipe not found</div>;
        return (
          <RecipeDetail
            recipe={recipe}
            onBack={() => setViewState({ type: 'CATEGORY', categoryId: recipe.categoryId })}
            onEdit={() => setViewState({ type: 'EDIT_RECIPE', recipeId: recipe.id })}
            onDelete={() => handleDeleteRecipe(recipe.id, recipe.categoryId)}
            onToggleFavorite={() => handleToggleFavorite(recipe.id)}
          />
        );

      default:
        return <div>Unknown view</div>;
    }
  };

  return (
    <Layout 
      onHomeClick={() => navigateToHome()}
      user={user}
      onLoginClick={() => setShowLogin(true)}
      onProfileClick={() => setShowProfile(true)}
    >
      {renderContent()}

      {showLogin && (
        <LoginModal 
          onLogin={handleLoginSuccess}
          onClose={() => setShowLogin(false)}
        />
      )}

      {showProfile && user && (
        <UserProfile 
          user={user}
          onSave={handleUpdateProfile}
          onLogout={handleLogout}
          onClose={() => setShowProfile(false)}
        />
      )}

      {isFridgeModalOpen && (
        <FridgeModal 
            onClose={() => setIsFridgeModalOpen(false)}
            onAddRecipe={handleAddAiRecipe}
            userPrefs={user?.preferences}
        />
      )}
    </Layout>
  );
}

import React, { useMemo, useState } from 'react';
import { Recipe, CategoryIdEnum } from '../types';
import { Sun, Moon, Sunset, Sunrise, Utensils, ChefHat, Coffee, RefreshCw } from 'lucide-react';

interface DailyMealRecommendationProps {
  recipes: Recipe[];
  onRecipeClick: (recipe: Recipe) => void;
  onSearchClick: (term: string) => void;
}

type MealPeriod = 'breakfast' | 'lunch' | 'dinner' | 'latenight';
type BreakfastStyle = 'chinese' | 'western';

interface RecommendationSlot {
  label: string;
  categoryIds: string[]; // Valid categories for this slot
  fallbackDish: string;  // What to show if no local recipe exists
}

export const DailyMealRecommendation: React.FC<DailyMealRecommendationProps> = ({ 
  recipes, 
  onRecipeClick, 
  onSearchClick 
}) => {
  const [breakfastStyle, setBreakfastStyle] = useState<BreakfastStyle>('chinese');
  const [seed, setSeed] = useState(0); // Used to trigger re-randomization

  const timeData = useMemo(() => {
    const hour = new Date().getHours();
    let period: MealPeriod;
    let title = '';
    let subtitle = '';
    let icon: React.ReactNode;
    let bgGradient = '';

    if (hour >= 6 && hour < 10) {
      period = 'breakfast';
      title = '元气早餐';
      subtitle = '一日之计在于晨';
      icon = <Sunrise className="w-6 h-6 text-orange-500" />;
      bgGradient = 'from-orange-50 to-yellow-50 border-orange-100';
    } else if (hour >= 10 && hour < 15) {
      period = 'lunch';
      title = '丰盛午餐';
      subtitle = '荤素搭配，营养均衡';
      icon = <Sun className="w-6 h-6 text-red-500" />;
      bgGradient = 'from-red-50 to-orange-50 border-red-100';
    } else if (hour >= 15 && hour < 21) {
      period = 'dinner';
      title = '温馨晚餐';
      subtitle = '四菜一汤，抚慰人心';
      icon = <Sunset className="w-6 h-6 text-indigo-500" />;
      bgGradient = 'from-indigo-50 to-purple-50 border-indigo-100';
    } else {
      period = 'latenight';
      title = '深夜食堂';
      subtitle = '快乐夜宵，灵魂伴侣';
      icon = <Moon className="w-6 h-6 text-blue-500" />;
      bgGradient = 'from-slate-50 to-blue-50 border-slate-200';
    }

    return { period, title, subtitle, icon, bgGradient };
  }, []);

  // Define the structure of the meal based on the period
  const mealSlots = useMemo((): RecommendationSlot[] => {
    switch (timeData.period) {
      case 'breakfast':
        if (breakfastStyle === 'chinese') {
          return [
            { label: '主食', categoryIds: [CategoryIdEnum.STAPLE], fallbackDish: '肉包子' },
            { label: '汤粥', categoryIds: [CategoryIdEnum.SOUP, CategoryIdEnum.DRINK], fallbackDish: '小米粥' },
            { label: '搭配', categoryIds: [CategoryIdEnum.SNACK, CategoryIdEnum.STAPLE], fallbackDish: '油条' },
            { label: '佐餐', categoryIds: [CategoryIdEnum.SNACK, CategoryIdEnum.VEGETABLE], fallbackDish: '豆腐脑' },
          ];
        } else {
          return [
            { label: '主食', categoryIds: [CategoryIdEnum.STAPLE], fallbackDish: '培根三明治' },
            { label: '饮品', categoryIds: [CategoryIdEnum.DRINK], fallbackDish: '热牛奶' },
            { label: '烘焙', categoryIds: [CategoryIdEnum.SNACK, CategoryIdEnum.DESSERT], fallbackDish: '恰巴塔' },
            { label: '搭配', categoryIds: [CategoryIdEnum.SNACK, CategoryIdEnum.MEAT], fallbackDish: '煎蛋香肠' },
          ];
        }

      case 'lunch':
      case 'dinner':
        return [
          { label: '荤菜', categoryIds: [CategoryIdEnum.MEAT], fallbackDish: timeData.period === 'lunch' ? '宫保鸡丁' : '清蒸鲈鱼' },
          { label: '素菜', categoryIds: [CategoryIdEnum.VEGETABLE], fallbackDish: '清炒时蔬' },
          { label: '汤类', categoryIds: [CategoryIdEnum.SOUP], fallbackDish: timeData.period === 'lunch' ? '番茄蛋汤' : '玉米排骨汤' },
          { label: '主食', categoryIds: [CategoryIdEnum.STAPLE], fallbackDish: '米饭' },
        ];

      case 'latenight':
        return [
          { label: '快乐水', categoryIds: [CategoryIdEnum.DRINK], fallbackDish: '冰可乐' },
          { label: '炸物', categoryIds: [CategoryIdEnum.SNACK], fallbackDish: '韩式炸鸡' },
          { label: '速食', categoryIds: [CategoryIdEnum.SNACK, CategoryIdEnum.STAPLE], fallbackDish: '火鸡面' },
          { label: '解馋', categoryIds: [CategoryIdEnum.SNACK], fallbackDish: '烤冷面' },
        ];

      default:
        return [];
    }
  }, [timeData.period, breakfastStyle]);

  // Fill the slots with actual recipes or fallback placeholders
  const displayItems = useMemo(() => {
    // Helper to pick a random item from array based on seed
    function pickRandom<T>(arr: T[]): T | null {
      if (arr.length === 0) return null;
      // Simple pseudo-random using seed + array length
      const index = (seed + Math.floor(Math.random() * 100)) % arr.length;
      return arr[index];
    }

    // Keep track of used recipes to avoid duplicates in one meal
    const usedRecipeIds = new Set<string>();

    return mealSlots.map(slot => {
      // Find local recipes that match this slot's allowed categories
      const candidates: Recipe[] = recipes.filter(r => 
        slot.categoryIds.includes(r.categoryId) && !usedRecipeIds.has(r.id)
      );

      const picked: Recipe | null = pickRandom(candidates);

      if (picked) {
        usedRecipeIds.add(picked.id);
        return { type: 'local', data: picked, label: slot.label };
      } else {
        return { type: 'fallback', name: slot.fallbackDish, label: slot.label };
      }
    });
  }, [mealSlots, recipes, seed]);

  const handleRefresh = () => {
    setSeed(prev => prev + 1);
  };

  return (
    <div className={`mb-8 rounded-3xl border p-6 shadow-sm bg-gradient-to-br ${timeData.bgGradient} relative overflow-hidden transition-all duration-300 hover:shadow-lg`}>
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between mb-6 gap-3">
        <div className="flex items-center gap-3">
          <div className="p-2.5 bg-white rounded-2xl shadow-sm">
            {timeData.icon}
          </div>
          <div>
            <h3 className="font-extrabold text-gray-900 text-xl flex items-center gap-2">
              {timeData.title}
              <span className="text-xs font-bold text-gray-500 bg-white/60 px-2 py-0.5 rounded-full border border-white/20">
                {new Date().getHours()}:00 - {(new Date().getHours() + 1) % 24}:00
              </span>
            </h3>
            <p className="text-sm font-medium text-gray-600 opacity-80">{timeData.subtitle}</p>
          </div>
        </div>

        <div className="flex items-center gap-2 self-end sm:self-auto">
          {timeData.period === 'breakfast' && (
            <div className="flex bg-white/60 p-1 rounded-xl border border-gray-100 mr-2 shadow-sm">
              <button
                onClick={() => setBreakfastStyle('chinese')}
                className={`px-3 py-1.5 text-xs font-bold rounded-lg transition-all ${
                  breakfastStyle === 'chinese' ? 'bg-orange-500 text-white shadow-md' : 'text-gray-500 hover:bg-white'
                }`}
              >
                中式
              </button>
              <button
                onClick={() => setBreakfastStyle('western')}
                className={`px-3 py-1.5 text-xs font-bold rounded-lg transition-all ${
                  breakfastStyle === 'western' ? 'bg-orange-500 text-white shadow-md' : 'text-gray-500 hover:bg-white'
                }`}
              >
                西式
              </button>
            </div>
          )}

          <button 
            onClick={handleRefresh}
            className="p-2 bg-white/80 hover:bg-white text-gray-500 hover:text-orange-600 rounded-full transition-all shadow-sm hover:rotate-180 duration-500"
            title="换一换"
          >
            <RefreshCw className="w-4 h-4" />
          </button>
        </div>
      </div>

      {/* Grid */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
        {displayItems.map((item, idx) => {
           if (item.type === 'local' && item.data) {
             const recipe = item.data as Recipe;
             return (
               <div 
                 key={`rec-${idx}`}
                 onClick={() => onRecipeClick(recipe)}
                 className="bg-white p-3 rounded-2xl shadow-sm border border-white/50 hover:border-orange-200 cursor-pointer transition-all hover:shadow-xl hover:scale-[1.03] flex flex-col h-full group duration-300"
               >
                 <div className="text-[10px] font-extrabold text-orange-600 mb-2 flex items-center bg-orange-50 w-fit px-2 py-0.5 rounded-full">
                    {item.label}
                 </div>
                 {recipe.image ? (
                   <div className="w-full aspect-[4/3] rounded-xl bg-gray-100 overflow-hidden mb-3 shadow-inner">
                      <img src={recipe.image} alt={recipe.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700 saturate-[1.1]" />
                   </div>
                 ) : (
                   <div className="w-full aspect-[4/3] rounded-xl bg-orange-50/50 flex items-center justify-center mb-3 text-3xl">
                      🥘
                   </div>
                 )}
                 <div className="mt-auto">
                   <h4 className="font-bold text-gray-800 text-sm truncate mb-1">{recipe.name}</h4>
                   <div className="flex items-center gap-1.5">
                      <Utensils className="w-3 h-3 text-gray-400" />
                      <span className="text-xs font-medium text-gray-500 truncate">{recipe.cookingTime}</span>
                   </div>
                 </div>
               </div>
             );
           } else {
             return (
               <div 
                 key={`fallback-${idx}`}
                 onClick={() => onSearchClick(item.name || '')}
                 className="bg-white/40 p-3 rounded-2xl border-2 border-dashed border-gray-300/60 hover:border-orange-400 hover:bg-white cursor-pointer transition-all hover:shadow-lg hover:scale-[1.03] flex flex-col h-full min-h-[140px] relative group duration-300"
               >
                  <div className="text-[10px] font-bold text-gray-400 mb-2 flex items-center w-fit px-2 py-0.5 rounded-full">
                    {item.label}
                 </div>
                 <div className="flex-1 flex flex-col items-center justify-center text-center">
                    <div className="w-12 h-12 bg-white rounded-full shadow-sm flex items-center justify-center mb-2 text-orange-400 group-hover:text-orange-500 group-hover:scale-110 group-hover:rotate-12 transition-all duration-300">
                        {timeData.period === 'latenight' ? <Utensils className="w-6 h-6" /> : 
                         timeData.period === 'breakfast' && breakfastStyle === 'western' ? <Coffee className="w-6 h-6" /> :
                         <ChefHat className="w-6 h-6" />}
                    </div>
                    <h4 className="font-bold text-gray-700 text-sm">{item.name}</h4>
                    <p className="text-[10px] font-bold text-orange-500 mt-2 opacity-0 translate-y-2 group-hover:opacity-100 group-hover:translate-y-0 transition-all duration-300">
                        点击生成食谱
                    </p>
                 </div>
               </div>
             );
           }
        })}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Recipe } from '../types';
import { Clock, BarChart, ArrowLeft, Pencil, Trash2, Eye, Star } from 'lucide-react';

interface RecipeDetailProps {
  recipe: Recipe;
  onBack: () => void;
  onEdit?: () => void;
  onDelete?: () => void;
  onToggleFavorite: () => void;
