      </div>

      {/* Timer Overlay */}
      {timers.length > 0 && (
        <div className="fixed bottom-0 left-0 right-0 bg-white shadow-[0_-4px_20px_rgba(0,0,0,0.1)] border-t border-gray-100 z-[70] p-4 animate-in slide-in-from-bottom-full duration-300">
