              </>
            ) : (
              // Search Results View
              <div>
                <h2 className="text-lg font-bold text-gray-800 mb-4 flex items-center">
                  <Search className="w-5 h-5 mr-2 text-orange-500" />
                  本地搜索结果 ({localSearchResults.length})
